	@Override
	public String setCabinetReject(String docID, String deptID, String deptName, String deptName2, String dirPath, String realPath, String hesongFlag, String companyID, String lang, int tenantID, String offSet, Locale locale) throws Exception {
		logger.debug("setCabinetReject Started");

		StringBuilder strSQL = new StringBuilder();
		String rtnVal ="TRUE";
		String sn = "";
		String docSN = "";
		String newDocID = "";
		String gFlag = getCode2Name("A35", "002", companyID, lang, tenantID);		

		String docNo = "";
		String orgDocNumCode = "";
		String docNumCode = "";
		String extFileName = "";
		String docNumZeroCnt = getDocNumZeroCnt(companyID, tenantID);
        String symbolDeptName = getDeptSymbol(deptID, tenantID);
        
        if (symbolDeptName == null || symbolDeptName.trim().isEmpty()) {
            symbolDeptName = commonUtil.cleanValue(deptName);
        }
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_TENANTID", tenantID);
		
		ApprGDocListVO apprGDocListVO = ezApprovalGDAO.setCabinetReject1(map);
		
		if (apprGDocListVO != null) {
			orgDocNumCode = apprGDocListVO.getOrgDocNumCode();
			sn = getCabinetNum(deptID, "", companyID, tenantID, offSet);
			sn = sn.replace("<REGNUM>", "").replace("</REGNUM>", "");
			sn = sn.replace("<RESULT>", "").replace("</RESULT>", "");
			
			if (!sn.trim().equals("")) {
				newDocID = getNewID(companyID, tenantID);
				
				extFileName = getExtendedFileName(apprGDocListVO.getHref());
				docNumCode = deptID + getNDigitNum(sn, 6);
				
				/* 2024-12-11 홍승비 - 반송/회송문서 대장등록 시 문서채번 자릿수를 맞춰주도록 수정 (컨피그에 따라 0이 붙도록 완료문서 채번 로직과 통일, 양식상의 문서번호 양식은 고려하지 않음) */
				docNo = symbolDeptName + "-" + createDocNO(sn, docNumZeroCnt);
				
				if (orgDocNumCode == null || orgDocNumCode.trim().equals("") || !gFlag.equals("G")) {
					//2018-10-04 배현상, companyid 병합에 따른 G버전 오류 개선(ORGCOMPANYID 추가)
					String strXML = "<SIGNINFOS><SIGNINFO><DOCID>" + newDocID + 
							"</DOCID><SIGNTYPE>TEXT</SIGNTYPE><SIGNNAME>docnumber" + 
							"</SIGNNAME><CONTENT><![CDATA[" + docNo + "]]></CONTENT>" + 
							"<ORGCOMPANYID></ORGCOMPANYID></SIGNINFO></SIGNINFOS>";
					
					Document xmlDom = commonUtil.convertStringToDocument(strXML);
					
					rtnVal = updateSignInfo(xmlDom, companyID, "QUERY", tenantID);
					
					if (rtnVal.equals("FALSE")) {
						return "<RESULT>FALSE</RESULT>";
					}
				} 
			}
		}
		
		if (strSQL.toString().equals("FALSE") || newDocID.trim().equals("")) {
			if (!sn.trim().equals("")) {
				rollbackCabinetNum(deptID, "", sn, companyID, "", lang, tenantID);
			}
			
			return "<RESULT>FALSE</RESULT>";
		}
		
		String oldYear = getDocHrefYear(docID, companyID, tenantID);
		String endURL = commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator + companyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), offSet, false).substring(0,4) + commonUtil.separator +
				getDocDir(newDocID) + commonUtil.separator + newDocID + "." + extFileName;
		
		String docState = StaDSHesong;
		
		if (hesongFlag.trim().equals("")) {
			docState = staDSBansong;
		}
		
		String containerID = returnContainerID(deptID, docState, companyID, tenantID);
		
		copyFile(dirPath + companyID + commonUtil.separator + "doc" + commonUtil.separator + oldYear + commonUtil.separator + "1000" + commonUtil.separator + getDocDir(docID) + commonUtil.separator + docID + "." + extFileName,
				dirPath + companyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), offSet, false).substring(0,4) + commonUtil.separator + getDocDir(newDocID) + commonUtil.separator + newDocID + "." + extFileName,
				dirPath + companyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), offSet, false).substring(0,4) + commonUtil.separator + getDocDir(newDocID));
		
		map.put("v_NEWDOCID", newDocID);
		map.put("v_DOCID", docID);
		map.put("v_ENDURL", endURL);
		map.put("v_DOCSTATE", docState);
		map.put("v_DOCNO", docNo);
		map.put("v_DOCNUMCODE", docNumCode);
		map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
		map.put("v_CONTAINERID", containerID);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		ezApprovalGDAO.insertRejectEndAprDocInfo(map);
		ezApprovalGDAO.insertRejectEndAprLineInfo(map);
		ezApprovalGDAO.insertRejectEndAttachInfo(map);
		ezApprovalGDAO.insertRejectEndDocAttachInfo(map);
		ezApprovalGDAO.insertRejectEndAprOpinionInfo(map);
		ezApprovalGDAO.insertRejectEndReceiptPointInfo(map);
		ezApprovalGDAO.insertRejectEndAprReceiptProcessInfo(map);
		ezApprovalGDAO.insertRejectExpendAprDocInfo(map);
		ezApprovalGDAO.insertRejectExpendAprLine(map);
		
        map.put("v_HESONGFLAG", hesongFlag.trim());
        
        ApprGDocListVO apprGDocListVO2 = ezApprovalGDAO.setCabinetReject2(map);
        
        if (apprGDocListVO2 != null) {
        	if (!docNumCode.trim().equals("")) {
        		docSN = docNumCode.trim();
        	} else {
        		docSN = apprGDocListVO2.getDocNumCode();
        	}
        	
        	if (docSN != null && !docSN.equals("")) {
        		docSN = docSN.substring(docSN.length() - 6);
        	}
        	
        	String hasAttach = "0";
        	
        	if ("Y".equals(apprGDocListVO2.getHasAttachYn())) {
        		hasAttach = "1";
        	}
        	
        	String seperateAttachXML = makeListField(apprGDocListVO2.getSeperateAttachXML()).trim();
        	String numOfPage = makeListField(apprGDocListVO2.getPageNum() == null ? "" : apprGDocListVO2.getPageNum().trim());
        	
        	if ("".equals(numOfPage)) {
        		numOfPage = "1";
        	}

        	rtnVal = regDocToCabinet("0", newDocID, docSN, apprGDocListVO2.getCabinetID(), apprGDocListVO2.getDocTitle(), deptID, deptName, deptName2,
        			"1", apprGDocListVO2.getAprMemberJobTitle(), apprGDocListVO2.getAprMemberJobTitle2(), "", "", apprGDocListVO2.getWriterName(), apprGDocListVO2.getWriterName2(), EgovDateUtil.getTodayTime().substring(0, 10),
        			"", "", "", "1", apprGDocListVO2.getOrgDocNumCode(), apprGDocListVO2.getSpecialRecordCode(), apprGDocListVO2.getPublicityCode(), apprGDocListVO2.getPublicityYN(), apprGDocListVO2.getLimitRange(), "1", numOfPage, hasAttach, seperateAttachXML, companyID, lang, tenantID, offSet, locale, "", "", "", "");

        } else {
        	if (!sn.trim().equals("")) {
        		rollbackCabinetNum(deptID, "", sn, companyID, "", lang, tenantID);
        	}
        	
        	if (hesongFlag.trim().equals("")) {
        		return "<RESULT>RESETLINE</RESULT>";
        	} else {
        		return "<RESULT>FALSE</RESULT>";
        	}
        }
        
        //hwp일 경우 대장등록전 문서에 새로운 문서번호 박아주기 | 2019-02-22 천성준 - mht일 경우 추가
        if (docNo != null && !docNo.trim().equals("")) {
        	String docFilePath = dirPath + companyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), offSet, false).substring(0,4) + commonUtil.separator + getDocDir(newDocID) + commonUtil.separator + newDocID + "." + extFileName;
        	if (extFileName.equals("hwp")) {
				File localDocFile = new File(docFilePath);
				
				if (EzFAL.isObjectStorageMode()) { // 원격저장소 사용여부를 확인
					byte[] orgBytes = null;
					
					// 원본 파일을 스트림에서 바이트로 read
					// EzFAL EzFileInputStream 사용 (자동 close 호출)
		    		try (EzFileInputStream fis = new EzFileInputStream(docFilePath)) {
		    			orgBytes = IOUtils.toByteArray(fis);
		    		} catch (Exception e) {
		    			logger.error(e.getMessage(), e);
		    		}
		    		
		    		// 읽어온 원본 파일(EzFile)을 로컬 파일(File)로 임시 저장
					// EzFAL EzFileOutputStream 사용 (자동 close 호출)
					try (FileOutputStream fos = new FileOutputStream(localDocFile)) {
						fos.write(orgBytes);
						fos.flush(); // newFile을 EzFileOutputStream으로 열어서 write했으므로, 기존의 Files.copy()와 같은 추가 호출은 필요하지 않음
					} catch (Exception e) {
						logger.error(e.getMessage(), e);
					}
				}
                
                boolean hwpFilter = "Y".equals(ezCommonService.getTenantConfig("hwpFilter", tenantID));
                String hwpPath = ezCommonService.getTenantConfig("hwpPath", tenantID);
                List<Object> hwpFile = new ArrayList<>();
                hwpFile.add(HWPReader.fromFile(docFilePath));
                if(hwpFilter)
                    hwpFile.add(new RestWHWP(ezCommonService.getTenantConfig("hwpFilterServer", tenantID)).open(hwpPath + docFilePath.substring(docFilePath.indexOf("/fileroot/"))));

                if (!"Y".equals(hesongFlag == null ? "" : hesongFlag.trim())) {
                    setHwpText(false, "docnumber", docNo, hwpFile);
                }
		        
		        //접수 후 반송,회송대장등록일 경우 접수결재칸 지워주기
				for (int i = 1; i < 10; i++) {
					if (findHwpField("1sign" + i, hwpFile)) {
						setHwpText(false, "1sign" + i, " ", hwpFile);
						setHwpText(false, "1jikwe" + i, " ", hwpFile);
					} else {
						break;
					}
				}
                
                if(!hwpFilter)
                    HWPWriter.toFile((HWPFile) hwpFile.get(0), docFilePath);
                else{
                    whwpSave(((RestWHWP) hwpFile.get(1)), hwpPath + docFilePath.substring(docFilePath.indexOf("/fileroot/")), docFilePath.substring(0, docFilePath.lastIndexOf("/")));
                }
		        
		        // docnumber 필드 등을 수정한 로컬 파일을 원격 저장소로 업로드 (로컬 파일은 업로드 후 자동 삭제됨)
				// EzFileOutputStream을 선언하는 순간 로컬 파일 경로에 새로운 File 객체가 생성되므로, 미리 저장해둔 byte 배열을 전달
		        if (EzFAL.isObjectStorageMode()) {
		        	byte[] hwpFileBytes = FileUtils.readFileToByteArray(localDocFile);
		        	
					try (EzFileOutputStream foshwp = new EzFileOutputStream(docFilePath)) {
						foshwp.write(hwpFileBytes);
						foshwp.flush();
					} catch (Exception e) {
						logger.error(e.getMessage(), e);
					}
		        }
        	} else {
        		String loadMht = ezCommonService.loadMHTFile(docFilePath);
        		String content = ezCommonService.startMHT2HTML(realPath + commonUtil.getUploadPath("config.LocalPath", tenantID), loadMht, realPath + commonUtil.getUploadPath("config.LocalPath", tenantID), realPath, locale, "", "");

        		org.jsoup.nodes.Document doc = Jsoup.parse(content);
                if (!"Y".equals(hesongFlag == null ? "" : hesongFlag.trim()) && doc.getElementById("docnumber") != null) {
                    doc.getElementById("docnumber").html(docNo);
                }

        		for (int i = 1; i < 10; i++) {
        			if (doc.getElementById("1sign" + i) != null) {
        				doc.getElementById("1sign" + i).html("");
        			}
        			if (doc.getElementById("1jikwe" + i) != null) {
        				doc.getElementById("1jikwe" + i).html("");
        			}
        			if (doc.getElementById("1seumyungdate" + i) != null) {
        				doc.getElementById("1seumyungdate" + i).html("");
        			}
        		}
        		
        		String tempHtml = doc.outerHtml();
        		String convertedMHT = ezCommonService.startHtml2Mht(tempHtml, realPath, locale);
        		
				// EzFAL EzFileOutputStream 사용 (자동 close 호출)
				try (EzFileOutputStream fos = new EzFileOutputStream(commonUtil.detectPathTraversal(docFilePath))) {
					fos.write(convertedMHT.getBytes()); // MHT 문자열을 바이트 배열로 가져와 파일 저장
					fos.flush();
				} catch (Exception e) {
					logger.error(e.getMessage(), e);
				}
        	}
        }
		
		if (!rtnVal.equals("FALSE")) {
			// 2018.06.26 - 대장등록 성공시 파일 KLIB 암호화
			if ("hwp".equals(extFileName) && "yes".equalsIgnoreCase(ezCommonService.getTenantConfig("useApprovalKlib", tenantID))) {
				ezApprovalGKlibService.encryptCompleteApproveFiles(newDocID, companyID, tenantID);
			}
			
			logger.debug("setCabinetReject ended");
			return "<RESULT>TRUE</RESULT>";
		} else {
        	return "<RESULT>FALSE</RESULT>," + sn;
		}
	}
    
    private void whwpSave(RestWHWP whwp, String savePath, String delPath) throws Exception{
        whwp.saveHwp(savePath);
        whwp.flush();
        File result = new File(delPath + "/" + whwp.getId() + ".result");
        if(result.exists())
            result.delete();
        File suc = new File(delPath + "/" + whwp.getId() + ".success");
        if(suc.exists())
            suc.delete();
    }

