	@Override
	public String updateReceiptTempletDetailInfo(Document doc, String companyID, int tenantID, String approvalFlag) throws Exception {
		logger.debug("updateReceiptTempletDetailInfo started");

		String rtnVal = "TRUE";
		String strUserID = doc.getElementsByTagName("APRDEPT").item(0).getChildNodes().item(0).getTextContent();
		String strFormID = doc.getElementsByTagName("APRDEPT").item(0).getChildNodes().item(1).getTextContent();
		String strAprDeptSN = doc.getElementsByTagName("APRDEPT").item(0).getChildNodes().item(2).getTextContent();
		String strAprDeptTempletName = doc.getElementsByTagName("APRDEPT").item(0).getChildNodes().item(3).getTextContent();
		
		/**
		 * 새로운 즐겨찾기를 등록하는 경우 strAprDeptSN = null
		 * 기존의 즐겨찾기를 수정하는 경우 strAprDeptSN != null
		 * */
		if (strAprDeptSN.trim().equals("")) {
			strAprDeptSN = getReceiptTempletSN(strFormID, strUserID, companyID, tenantID);
		} else {
			rtnVal = deleteReceiptTempletDetailInfo(strFormID, strUserID, strAprDeptSN, companyID, tenantID);
		}
		
		if (rtnVal.equals("TRUE")) {
			
			Map<String, Object> map = new HashMap<String, Object>();
			map.put("v_UserID", strUserID);
			map.put("v_FormID", strFormID);
			map.put("v_AprDeptSN", strAprDeptSN);
			map.put("v_AprDeptTempletName", strAprDeptTempletName);
			map.put("companyID", companyID);
			map.put("v_TENANTID", tenantID);
			
			ezApprovalGDAO.insertDeptTemplet(map);
			
			for (int i = 0; i < doc.getElementsByTagName("ROW").getLength(); i++) {
//				if(approvalFlag.equals("G")) {
//					map.put("v_AprDeptMemberSN", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(0).getTextContent());
//					map.put("v_AprMemberDeptID", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(3).getTextContent());
//					map.put("v_AprMemberDeptName", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(11).getTextContent());
//					map.put("v_AprMemberDeptName2", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(12).getTextContent());
//					map.put("v_ExtReceptYN", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(4).getTextContent());
//					map.put("v_ProcessYN", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(5).getTextContent());
//					map.put("v_CanEditYN", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(6).getTextContent());
//					map.put("v_ExtReceptEmail", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(7).getTextContent());
//					map.put("v_AprMemberID", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(8).getTextContent());
//					map.put("v_AprMemberName", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(11).getTextContent());
//					map.put("v_AprMemberName2", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(12).getTextContent());
//					map.put("v_AprMemberJobTitle", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(13).getTextContent());
//					map.put("v_AprMemberJobTitle2", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(14).getTextContent());
//				} else {
					// xpath 생성
					XPath  xpath = XPathFactory.newInstance().newXPath();
					// NodeList nodes = (NodeList)xpath.evaluate("//ROWS/ROW", doc, XPathConstants.NODESET);
					
					map.put("v_AprDeptMemberSN", doc.getElementsByTagName("ROW").item(i).getChildNodes().item(0).getTextContent());
					map.put("v_AprMemberDeptID", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptPointID']", doc, XPathConstants.STRING));
					map.put("v_AprMemberDeptName", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='AprMemberDeptName']", doc, XPathConstants.STRING));
					map.put("v_AprMemberDeptName2", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='AprMemberDeptName2']", doc, XPathConstants.STRING));
					map.put("v_ExtReceptYN", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ExtReceptYN']", doc, XPathConstants.STRING));
					map.put("v_ProcessYN", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ProcessYN']", doc, XPathConstants.STRING));
					map.put("v_CanEditYN", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='CanEditYN']", doc, XPathConstants.STRING));
					map.put("v_ExtReceptEmail", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ExtReceptEmail']", doc, XPathConstants.STRING));
					map.put("v_AprMemberID",xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptMemberID']", doc, XPathConstants.STRING));
					map.put("v_AprMemberName", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptMemberName']", doc, XPathConstants.STRING));
					map.put("v_AprMemberName2", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptMemberName2']", doc, XPathConstants.STRING));
					map.put("v_AprMemberJobTitle", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptMemberJobTitle']", doc, XPathConstants.STRING));
					map.put("v_AprMemberJobTitle2", xpath.evaluate("//ROWS/ROW["+(i+1)+"]/DATA[@name='ReceiptMemberJobTitle2']", doc, XPathConstants.STRING));
//				}
				
				ezApprovalGDAO.insertDeptTempletDetail(map);
			}
		}

		logger.debug("updateReceiptTempletDetailInfo ended");
		
		return rtnVal;
	}

