	@Override
	public String getUncompleteDocList(String deptID, String companyID, String cabinetID, int tenantID, String userLang, LoginVO userInfo) throws Exception {
		logger.debug("getUncompleteDocList started");

		String approvalFlag = ezCommonService.getTenantConfig("ApprovalFlag", tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		
		map.put("companyID", companyID);
		map.put("v_CABINETID", cabinetID);
		map.put("v_TENANTID", tenantID);
		
		List<ApprGDocListVO> docInfo = ezApprovalGDAO.getUncompleteDocList(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for(int i = 0; i < docInfo.size(); i++) {
			sb.append(commonUtil.getQueryResult(docInfo.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		int dlength = docXML.getElementsByTagName("ROW").getLength();
		
		StringBuilder rtnXML = new StringBuilder();
		
		rtnXML.append("<LISTVIEWDATA>");
		rtnXML.append("<HEADERS>");
		rtnXML.append("<HEADER><NAME>제목</NAME><WIDTH>140</WIDTH><COLNAME>DocTitle</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>문서상태</NAME><WIDTH>80</WIDTH><COLNAME>DocState</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>결재자</NAME><WIDTH>80</WIDTH><COLNAME>AprMemberName</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>결재방법</NAME><WIDTH>80</WIDTH><COLNAME>AprType</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>결재상태</NAME><WIDTH>80</WIDTH><COLNAME>AprState</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>기안부서</NAME><WIDTH>90</WIDTH><COLNAME>AprMemberDeptName</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>기안자</NAME><WIDTH>60</WIDTH><COLNAME>WriterName</COLNAME></HEADER>");
		rtnXML.append("<HEADER><NAME>기안일자</NAME><WIDTH>140</WIDTH><COLNAME>StartDate</COLNAME></HEADER>");
		rtnXML.append("</HEADERS>");
	
		rtnXML.append("<ROWS>");
		for (int k = 0; k < dlength; k++){
			rtnXML.append("<ROW>");
			rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(docXML.getElementsByTagName("DOCTITLE").item(k).getTextContent())) + "</VALUE>");
			rtnXML.append("<DOCID>" + makeXMLString(makeListField(docXML.getElementsByTagName("DOCID").item(k).getTextContent())) + "</DOCID></CELL>");
			rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(getCode2Name("A02", docXML.getElementsByTagName("DOCSTATE").item(k).getTextContent(), companyID, userLang, tenantID))) + "</VALUE></CELL>");
			rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(docXML.getElementsByTagName("APRMEMBERNAME").item(k).getTextContent())) + "</VALUE></CELL>");
			
			if (approvalFlag.equals("G")) {
				rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(getCode2Name("A03", docXML.getElementsByTagName("APRTYPE").item(k).getTextContent(), companyID, userLang, tenantID))) + "</VALUE></CELL>");
			} else {
				rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(getCode2Name("SA03", docXML.getElementsByTagName("APRTYPE").item(k).getTextContent(), companyID, userLang, tenantID))) + "</VALUE></CELL>");
			}
			
			if (approvalFlag.equals("G")) {
				rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(getCode2Name("A04", docXML.getElementsByTagName("APRSTATE").item(k).getTextContent(), companyID, userLang, tenantID))) + "</VALUE></CELL>");
			} else {
				rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(getCode2Name("SA04", docXML.getElementsByTagName("APRSTATE").item(k).getTextContent(), companyID, userLang, tenantID))) + "</VALUE></CELL>");
			}
			
			rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(docXML.getElementsByTagName("APRMEMBERDEPTNAME").item(k).getTextContent())) + "</VALUE></CELL>");
			rtnXML.append("<CELL><VALUE>" + makeXMLString(makeListField(docXML.getElementsByTagName("WRITERNAME").item(k).getTextContent())) + "</VALUE></CELL>");
			rtnXML.append("<CELL><VALUE>" + commonUtil.getDateStringInUTC(makeXMLString(makeListField(convertDate(docXML.getElementsByTagName("STARTDATE").item(k).getTextContent()))), userInfo.getOffset(), false) + "</VALUE></CELL>");
			rtnXML.append("</ROW>");	
		}
		rtnXML.append("</ROWS>");
		rtnXML.append("</LISTVIEWDATA>");
		logger.debug("getUncompleteDocList ended");
		
		return rtnXML.toString();
	}

	@Override
	public String transferCabinet(Document xmlDom, int tenantID) throws Exception {
		logger.debug("transferCabinet started");

		// 인수부서의 데이터 (인수부서 이름, 인수부서 ID, 인수받을 기록물철이 등록될 단위업무코드, 단위업무명...)
		String companyID = xmlDom.getElementsByTagName("COMPANYID").item(0).getTextContent();
		String deptCode = xmlDom.getElementsByTagName("DDEPTCODE").item(0).getTextContent();
		String deptName = xmlDom.getElementsByTagName("DDEPTNAME").item(0).getTextContent();
		String deptName2 = xmlDom.getElementsByTagName("DDEPTNAME").item(0).getTextContent();
		String taskCode = xmlDom.getElementsByTagName("DTASKCODE").item(0).getTextContent();
		String taskName = xmlDom.getElementsByTagName("DTASKNAME").item(0).getTextContent();
		String taskName2 = xmlDom.getElementsByTagName("DTASKNAME2").item(0).getTextContent();
		String deptMID = xmlDom.getElementsByTagName("DDEPTMID").item(0).getTextContent();
		String deptMName = xmlDom.getElementsByTagName("DDEPTMNAME").item(0).getTextContent();
		String deptMName2 = xmlDom.getElementsByTagName("DDEPTMNAME2").item(0).getTextContent();
		
		String cabIDList = ""; // 기록물철은 여러개 인계 가능
		
		// 쿼리에서 CabinetID IN 조건으로 사용하기 위해 ''문자로 이어붙임 (실제로는 하단 for 루프 내부에서 CabinetID 배열 하나씩 잘라 조건으로 사용)
		for (int k = 0; k < xmlDom.getElementsByTagName("ID").getLength(); k++) {
			if (k == 0) {
				cabIDList += "'" + xmlDom.getElementsByTagName("ID").item(k).getTextContent().trim() + "' ";
			} else {
				cabIDList += ", '" + xmlDom.getElementsByTagName("ID").item(k).getTextContent().trim() + "' ";
			}
		}
		
		/* 2024-03-14 홍승비 - SQL Injection 제거 > CabinetID를 배열로 전달 */
		// 인계할 기록물철 리스트 배열로 분리
		String cabList[] = cabIDList.replace("'", "").replace(" ", "").split(",");
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DDeptCode", deptCode);
		map.put("v_DDeptName", deptName);
		map.put("v_DDeptName2", deptName2);
		map.put("v_DTaskCode", taskCode);
		map.put("v_DTaskName", taskName);
		map.put("v_DTaskName2", taskName2);
		map.put("v_CabIDList", cabList);
		map.put("v_DeptMID", deptMID);
		map.put("v_DeptMName", deptMName);
		map.put("v_DeptMName2", deptMName2);
		map.put("v_TENANTID", tenantID);
		
		String rtnVal = "";
		
		int numRows = ezApprovalGDAO.transferCabinet(map);
		map.put("v_numRows", numRows);
		
		// 채번 구분필드2 이용여부 (부서별 채번 또는 회사별 채번 여부 / 기록물철의 고유 시리얼 번호 생성 시 TYPE2를 조건으로 사용)
		int type2Sn = ezApprovalGDAO.transferCabinetType2(map);
		if (type2Sn == 0) {
			map.put("v_TYPE2", "0");
		} else {
			map.put("v_TYPE2", deptCode);
		}
		
		// 인계할 기록물철의 개수만큼 루프를 돌면서 인수기록물철 분류정보(TBCABINETCLASS)를 생성한다.
		for (int j = 0; j < numRows; j++) {
            Map<String, Object> serialNumMap = new HashMap<>();
            serialNumMap.put("v_CABINETID", cabList[j]);
            serialNumMap.put("v_TENANTID", tenantID);
            serialNumMap.put("companyID", companyID);
            List<ApprGTaskVO> orgCabinet = ezApprovalGDAO.getCabinetInfo(serialNumMap);
            
            // 기록물철 인계 시 생산연도는 동일하게 유지 (등록일자는 현재 시간)
            String productionYear = orgCabinet.get(0).getProductionYear();
            map.put("v_YEAR", productionYear);
            map.put("v_MONTH", String.format("%03d", Integer.parseInt(commonUtil.getTodayUTCTime("").substring(6,7))).toString());
            map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
            
            String curSN = ezApprovalGDAO.transferCabinetSn(map);
            
            if (curSN == null) {
                curSN = "1";
                map.put("v_RtnSN", curSN);
                ezApprovalGDAO.insertTbSerialNumGen(map);
            } else {
                map.put("v_RtnSN", curSN);
            }
            
            ezApprovalGDAO.updateTbSerialNumGen(map);
            
            /* 2024-03-14 홍승비 - SQL Injection 제거 > 단일 CabinetID를 IN이 아닌 동일 비교(=)조건으로 사용 */
			map.put("v_cabList", cabList[j]);
			map.put("v_SN", j);
			map.put("v_CNT", String.format("%06d", Integer.parseInt(curSN)));
			
			// SerialNumGen 테이블에서 기록물철 생성을 위한 고유 번호를 가져왔으므로, CABINETCLASSNO용 추가 계산(+j) 동작 제거
			map.put("v_CABINETCLASSNO", deptCode + taskCode + productionYear + String.format("%06d", Integer.parseInt(curSN)));
			
			// 인수부서에 새로운 기록물철을 생성
			ezApprovalGDAO.insertTbCabinetClass(map);
			
			// TBL_CABINET 테이블은 TBL_CABINETCLASS의  TENANT_ID, COMPANYID, CABINETCLASSNO 칼럼을 외부 키로 가지므로,
			// TBL_CABINETCLASS 테이블에 먼저 레코드를 삽입한 다음 TBL_CABINET 테이블에 레코드를 삽입
			ezApprovalGDAO.trigerTbCabinet(map);
			ezApprovalGDAO.trigerTbCabRoleInfo(map);
			
			// 인계할 기록물철 리스트의 목표 단위업무 정보를 확인 (*인수부서가 선택한 단위업무의 정보를 가져옴)
			List<ApprGCabinetVO> apprExistUnitList = ezApprovalGDAO.selectExistUnit(map);
			
			if (apprExistUnitList.size() > 0) {
				map.put("v_rowID", apprExistUnitList.get(0).getCabinetClassNo().trim());
				map.put("KeepingPeriod", apprExistUnitList.get(0).getKeepingPeriod());
				map.put("KeepingMethod", apprExistUnitList.get(0).getKeepingPlace());
				map.put("KeepingPlace", apprExistUnitList.get(0).getKeepingMethod());
				map.put("DisplayRecFlag", apprExistUnitList.get(0).getDisplayRecFlag());
				map.put("SpecialCatalogFlag", apprExistUnitList.get(0).getSpecialCatalogFlag());
				
				// 인수부서에 새롭게 생성된 기록물철에 인수부서 단위업무 기준으로 보존기간, 보존방법, 보존장소 등 분류정보를 갱신 
				ezApprovalGDAO.updateExistUnit(map);
			}
			
			// 특수목록 입력
			String spFlag = ezApprovalGDAO.selectTbSpecialCatalogInfo(map);
			if (spFlag == null) {
				map.put("v_NewSCFlag", 0);
			} else if (!spFlag.equals("0")) {
				map.put("v_NewSCFlag", spFlag);
				
				ezApprovalGDAO.insertTbSpecialCatalogInfo(map);
				// 특수목록 플래그가 같고 특수목록 이름이 같으면 데이터를 복사한다.
				ezApprovalGDAO.insertTbSpecialCatalogInfo2(map);
			}
			
			// 구기록물철 정보 저장
			ezApprovalGDAO.insertTbOldCabinetExtraInfo(map);
			// 인수 기록물철 테이블(TBCABINET)에 생성한다.
			// 권호수가 1권이 아닐경우 -> 권호수에 따른 기록물철도 함께 생성
			ezApprovalGDAO.insertTbCabinetInfo(map);
			
			// 새롭게 생성된 인수부서의 기록물철 리스트 셀렉트
			List<ApprGCabinetVO> apprCabinetTransferList = ezApprovalGDAO.selectCabinetTransfer(map);
			
			if (apprCabinetTransferList.size() > 0) {
				map.put("v_rowID", apprCabinetTransferList.get(0).getRow_id().trim());
				map.put("ProcessDeptCode", apprCabinetTransferList.get(0).getProcessDeptCode());
				map.put("TaskCode", apprCabinetTransferList.get(0).getTaskCode());
				map.put("ProductionYear", apprCabinetTransferList.get(0).getProductionYear());
				map.put("RegSerialNo", apprCabinetTransferList.get(0).getRegSerialNo());
				map.put("VolumeNo", apprCabinetTransferList.get(0).getVolumeNo());
				map.put("CabinetID", apprCabinetTransferList.get(0).getCabinetID());
				map.put("Title", apprCabinetTransferList.get(0).getTitle());
				map.put("Title2", apprCabinetTransferList.get(0).getTitle2());
				map.put("ProcessDeptName", apprCabinetTransferList.get(0).getProcessDeptName());
				map.put("ProcessDeptName2", apprCabinetTransferList.get(0).getProcessDeptName2());
				map.put("TaskName", apprCabinetTransferList.get(0).getTaskName());
				map.put("TaskName2", apprCabinetTransferList.get(0).getTaskName2());
				map.put("CatalogTransferFlag", apprCabinetTransferList.get(0).getCatalogTransferFlag());
				map.put("CatalogTransferYear", apprCabinetTransferList.get(0).getCatalogTransferYear());
				map.put("DocTransferFlag", apprCabinetTransferList.get(0).getDocTransferFlag());
				map.put("DocTransferYear", apprCabinetTransferList.get(0).getDocTransferYear());
				map.put("ProdReportFlag", apprCabinetTransferList.get(0).getProdReportFlag());
				
				ezApprovalGDAO.updateTbCabinetInfo(map); // 인수부서의 기록물철 CabinetTransferFlag = '1' 로 업데이트 (인수)
			}
			
			// 인계부서의 기록물철 CabinetTransferFlag = '2' 로 업데이트 (인계)
			ezApprovalGDAO.updateTbCabinetInfo2(map); // 편철확정 "되지 않은" 기록물철의 TBL_CABINET 업데이트
			ezApprovalGDAO.updateTbCabinetInfo3(map); // 편철확정 "된" 기록물철의 TBL_CABINET 업데이트
			
			// 아래의 쿼리는 인수부서에서 인계부서의 기존 철을 표출하게 하는 오류를 발생시키므로 주석처리함
			// ezApprovalGDAO.updateTbCabinetClass(map); // 편철확정 "된" 기록물철의 TBL_CABINETCLASS => OwnerDeptID, OwnerTask를 인수부서의 데이터로 업데이트
			
			// 분리첨부 레코드 => 인수부서의 분리첨부가 되도록 CabinetID를 인수부서 기록물철의 CabinetID로 갱신 
			List<ApprGCabinetVO> apprTbSeperateAttachList = ezApprovalGDAO.selectTbSeperateAttach(map);
			
			if (apprTbSeperateAttachList.size() > 0) {
				map.put("v_rowID3", apprTbSeperateAttachList.get(0).getRecordID().trim());
				map.put("v_CABINETID", apprTbSeperateAttachList.get(0).getCabinetID());
				
				ezApprovalGDAO.updateTbSeperateAttach(map);
			}
			
			ezApprovalGDAO.insertTbCabinetHistory(map);
		}
		
		rtnVal = "<RESULT>TRUE</RESULT>";

		logger.debug("transferCabinet ended");
		
		return rtnVal;
	}

	@Override
	public String gongRamUpdate(String docID, String userID, String companyID, String lang, int tenantID) throws Exception {
		logger.debug("gongRamUpdate started");

		Map<String, Object> map = new HashMap<String, Object>();
		
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_USERID", userID);
		map.put("v_FLAG", "1");
		map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
		map.put("v_TENANTID", tenantID);
		boolean rtnVal = false;
		
		ezApprovalGDAO.gongRamUpdate(map);
		
		rtnVal = gongRamActivate(docID, companyID, lang, tenantID);
		
		if (!rtnVal) {
			map.put("v_FLAG", "2");
			
			ezApprovalGDAO.gongRamUpdate(map);
			rtnVal = true;
		}
		
		map.put("v_FLAG", "3");
		
		String grDocID = ezApprovalGDAO.selectGongRamDocID(map);
		
		if (grDocID != null) {
			ezApprovalGDAO.gongRamUpdate(map);
		}

		logger.debug("gongRamUpdate ended");
		
		return "<RESULT>TRUE</RESULT>";
	}

	@Override
	public String delayCabEndY(String deptCode, String flag, String cabClassList, String companyID, int tenantID) throws Exception {
		logger.debug("delayCabEndY started");
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_TENANTID", tenantID);
		map.put("companyID", companyID);
		map.put("v_flag", flag);
		map.put("v_OwnerDeptID", deptCode);

        String[] CabinetClassNoAry = cabClassList.split(",");
        map.put("v_CabinetClassNo", CabinetClassNoAry);
        
		if (flag.equals("1")) { 				// 모두 연기일 경우
			ezApprovalGDAO.updateDelayCabinetClass(map);
		} else if (flag.equals("0")) { 			// 선택된 철만 연기일 경우
			ezApprovalGDAO.updateDelayCabinetClass(map);
		} else if (flag.equals("2")) {  		// 연기취소일 경우
			ezApprovalGDAO.updateDelayCabinetClass(map);
		}

		logger.debug("delayCabEndY ended");
        
		return "<RESULT>TRUE</RESULT>";
	}

	@Override
	public String getUncabinetedDocCount(String deptID, String confirmYN, String companyID, int tenantID) throws Exception {
		logger.debug("getUncabinetedDocCount started");

		String deptInfos = ezOrganService.getPropertyValue(deptID, "extensionAttribute4", tenantID);
		String deptInfo = deptID.trim();
		
		if (deptInfos != null) {
			String[] deptList = deptInfos.split(";");
			
			for (int k = 0; k < deptList.length; k++) {
				deptInfo += ", " + deptList[k].trim();
			}
		}
		
		if (confirmYN.trim().equals("")) {
			confirmYN = commonUtil.getTodayUTCTime("yyyy");
		}
		
		confirmYN += "-12-31 23:59:59";
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DEPTINFO", deptInfo);
		map.put("v_UNTILYEAR", confirmYN);
		map.put("v_TENANTID", tenantID);
		
		int result = ezApprovalGDAO.getUncabinetedDocCount(map);

		logger.debug("getUncabinetedDocCount ended");
		
		return "<RESULT>" + result + "</RESULT>";
	}

