		map.put("SIGNNAME", signAdd + "sign" + signNum);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		ezApprovalGDAO.deleteRollBackSignInfo(map);
		
		map.put("SIGNNAME", signAdd + "seumyung" + signNum);
		ezApprovalGDAO.deleteRollBackSignInfo(map);
		
