		ezApprovalGDAO.deleteRollBackSignInfo(map);
		
		map.put("SIGNNAME", "habyuidate" + signNum);
		ezApprovalGDAO.deleteRollBackSignInfo(map);
		
		result = true;
		
		logger.debug("rollBackSignInfo ended");
		
		return result;
