	@Override
	public String updateOpinionInfo(Document docXML, String companyID, String lang, int tenantID) throws Exception {
		logger.debug("updateOpinionInfo started");
		String docID = docXML.getElementsByTagName("ROW").item(0).getChildNodes().item(4).getTextContent();
		
		logger.debug("updateOpinionInfo param : docID = " + docID);

		String rtnVal = deleteOpinionInfo(docID, companyID, lang, tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		
		if (rtnVal.equals("TRUE")) {
			for (int k = 0; k < docXML.getElementsByTagName("ROW").getLength(); k++) {
				
				map.put("v_DOCID", docID);
				map.put("v_USERID", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(5).getTextContent());
				map.put("v_OPINIONGB", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(9).getTextContent());
				map.put("v_CONTENT", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(6).getTextContent());
				map.put("v_USERNAME", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(10).getTextContent());
				map.put("v_USERNAME2", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(11).getTextContent());
				map.put("v_USERJOBTITLE", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(12).getTextContent());
				map.put("v_USERJOBTITLE2", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(13).getTextContent());
				map.put("v_USERDEPTID", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(7).getTextContent());
				map.put("v_USERDEPTNAME", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(14).getTextContent());
				map.put("v_USERDEPTNAME2", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(15).getTextContent());
				/* 2020-04-02 홍승비 - 의견순번 저장 시 중복에러 방지 처리 */
				//map.put("v_OPINIONSN", docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(8).getTextContent());
				map.put("v_OPINIONSN", (docXML.getElementsByTagName("ROW").getLength() - k));
				map.put("companyID", companyID);
				map.put("v_TENANTID", tenantID);

				ezApprovalGDAO.insertOptionInfo(map);
				
				if (docXML.getElementsByTagName("ROW").item(k).getChildNodes().item(9).getTextContent().equals("004")) {
					//부서합의  회송의견 처리하기 위해 분기 추가. 2019-03-06 홍대표
					map.put("v_habDocID", docID);
					List<ApprGDocListVO> habDocInfo = ezApprovalGDAO.getLastHabYuiDocState(map);
					map.remove("v_habDocID");
					
					//감사유형의 회송의견처리하기 위해 조건 추가. 2020-02-27 홍대표.
					if(!(habDocInfo.size() > 0 && (habDocInfo.get(0).getDocState().equals("012") || habDocInfo.get(0).getDocState().equals("014")))) {
						String orgDocID = ezApprovalGDAO.getAprOrgDocID(map);
						map.put("v_ORGDOCID", orgDocID);
						int opinionCnt = ezApprovalGDAO.getEndAprOpinionCnt(map);
						map.put("v_ORGOPINIONSN", opinionCnt + 1);
						ezApprovalGDAO.insertHesongOpinion(map);
						
						/* 2020-06-30 홍승비 - 회송의견 작성 후 회송 시 원문서에 대해 회송의견이 작성된 것이므로, 원문서의 의견 플래그를 Y로 설정 */
						Map<String, Object> mapH = new HashMap<String, Object>();
						mapH.put("v_DOCID", orgDocID);
						mapH.put("v_OpinionYN", "Y");
						mapH.put("v_TENANTID", tenantID);
						mapH.put("companyID", companyID);
						ezApprovalGDAO.updateEndAprDocOptionInfo(mapH);
					}
				}
			}
			map.put("v_DOCID", docID);
			map.put("v_OpinionYN", "Y");
			map.put("v_TENANTID", tenantID);
			
			ezApprovalGDAO.updateAprDocOptionInfo(map);
		}
		logger.debug("updateOpinionInfo ended");

		return rtnVal;
	}

	@Override
	public String getDocHrefYear(String docID, String companyID, int tenantID) throws Exception {
		String rtnValue = commonUtil.getTodayUTCTime("yyyy");
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_PDOCID", docID);
		
		String href = ezApprovalGDAO.getDocHrefYear(map);
		
		if (href != null) {
			String[] arry = href.split("/");
			
			if (arry.length >= 7 && arry[7].length() == 4) {
				rtnValue = arry[7];
			}
		}

		return rtnValue;
	}

	@Override
	public String getDocDir(String docID) throws Exception {
		String tempHref = "";
		
		if (docID.length() == 0) {
			tempHref = docID;
		} else {
			tempHref = String.valueOf((Integer.parseInt(docID.substring(docID.length() - 3, docID.length())) % 1000));
		}
		
		return tempHref;
	}

	@Override
	public String getAttachFileInfo(String docID, String mode, String sortHeader, String sortOption, String companyID, String lang, int tenantID, String offset) throws Exception {
		logger.debug("getAttachFileInfo started");

		String listString = "";
		StringBuffer resultXML = new StringBuffer();
		String orderOption1 = "";
		String approvalFlag = ezCommonService.getTenantConfig("ApprovalFlag", tenantID);
		
		if (approvalFlag.equals("G")) {
			listString = getListHeader("041", companyID, lang, tenantID);
		} else {
			listString = getListHeader("S041", companyID, lang, tenantID);
		}
		
		Document listXML = commonUtil.convertStringToDocument(listString);
		
		int hlength = listXML.getElementsByTagName("NAME").getLength();
		
		resultXML.append("<LISTVIEWDATA>");
		resultXML.append("<HEADERS>");
		
		for (int k = 0; k < hlength; k++) {
			resultXML.append("<HEADER>");
			resultXML.append("<NAME>" + listXML.getElementsByTagName("NAME").item(k).getTextContent() + "</NAME>");
			resultXML.append("<WIDTH>" + listXML.getElementsByTagName("WIDTH").item(k).getTextContent() + "</WIDTH>");
			resultXML.append("<COLNAME>" + listXML.getElementsByTagName("COLNAME").item(k).getTextContent() + "</COLNAME>");
			
			/* 2021-09-07 홍승비 - 전자결재 첨부파일 레이어 팝업 > 첨부파일명 표출 시 원본 파일명이 아닌 DISPLAYNAME을 표출하도록 수정 */
			if (listXML.getElementsByTagName("COLNAME").item(k).getTextContent().equalsIgnoreCase("ATTACHFILENAME")) {
				listXML.getElementsByTagName("COLNAME").item(k).setTextContent("DISPLAYNAME");
			}
			
			if (!sortHeader.equals("") && sortHeader.equals(listXML.getElementsByTagName("NAME").item(k).getTextContent())) {
				if (sortOption.equals("")) {
					orderOption1 = listXML.getElementsByTagName("COLNAME").item(k).getTextContent() + " ";
				} else {
					orderOption1 = listXML.getElementsByTagName("COLNAME").item(k).getTextContent() + " desc ";
				}
			}
			resultXML.append("</HEADER>");
		}
		resultXML.append("</HEADERS>");
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_MODE", mode);
		map.put("v_TENANTID", tenantID);
		map.put("v_ORDERBY", orderOption1);
		map.put("v_ORDERBYLENGTH", orderOption1.length());
		
        /* 이유정 - [웹취약점] EzApprovalG.getAttachFileInfo 관련 orderby절 수정 (파라미터 추가) */
        String orderColumn = "ATTACHUSERNAME;DISPLAYNAME;ATTACHFILESIZE;PAGENUM";
        String[] columns = orderColumn.split(";");
        
		if (orderOption1.length() > 0) {
			map.put("v_ORDERBYVALUE", orderOption1.trim().toLowerCase().substring(0, 12));
            map.put("col_order_ATTACHFILESN", "ATTACHFILESN");
            map.put("col_sort1_ATTACHFILESN", "ASC");

            for (int k = 0; k < columns.length; k++) {
                if (orderOption1.split(" ")[0].toUpperCase().equals(columns[k])) {
                    map.put("col_order_" + columns[k], columns[k]);
                    if (orderOption1.substring(orderOption1.length() - 5, orderOption1.length()).toUpperCase().equals("DESC ")) {
                        map.put("col_sort1_" + columns[k], "DESC");
                    } else {
                        map.put("col_sort1_" + columns[k], "ASC");
                    }
                }
            }
		}
		
		List<ApprGAttachInfoVO> apprGAttachInfoVOList = ezApprovalGDAO.getAttachFileInfo(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGAttachInfoVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGAttachInfoVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		int dlength = docXML.getElementsByTagName("ROW").getLength();
		
		String fieldName = "";
		String fieldValue = "";
		
		resultXML.append("<ROWS>");
		
		for (int k = 0; k < dlength; k++) {
			resultXML.append("<ROW>");
			for (int p = 0; p < hlength; p++) {
				resultXML.append("<CELL>");
				fieldName = listXML.getElementsByTagName("COLNAME").item(p).getTextContent().toUpperCase();
				
				if (fieldName.toUpperCase().equals("ATTACHUSERNAME")) {
					fieldName = fieldName + commonUtil.getMultiData(lang, tenantID);
				}
				fieldValue = docXML.getElementsByTagName(fieldName).item(k).getTextContent();
				resultXML.append("<VALUE>" + commonUtil.cleanValue(getListField(fieldName, fieldValue, companyID, lang, tenantID, offset)) + "</VALUE>");
				
				if (p == 0) {
					resultXML.append("<DATA1><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHFILEHREF").item(k).getTextContent()) + "]]></DATA1>");
					resultXML.append("<DATA2>" + makeListField(docXML.getElementsByTagName("ATTACHFILESN").item(k).getTextContent()) + "</DATA2>");
					resultXML.append("<DATA3>" + makeListField(docXML.getElementsByTagName("DOCID").item(k).getTextContent()) + "</DATA3>");
					resultXML.append("<DATA4><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERID").item(k).getTextContent()) + "]]></DATA4>");
					resultXML.append("<DATA5><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERJOBTITLE").item(k).getTextContent()) + "]]></DATA5>");
					resultXML.append("<DATA6><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERDEPTID").item(k).getTextContent()) + "]]></DATA6>");
					resultXML.append("<DATA7><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERDEPTNAME").item(k).getTextContent()) + "]]></DATA7>");
					resultXML.append("<DATA8>" + makeListField(docXML.getElementsByTagName("ATTACHFILESIZE").item(k).getTextContent() + "bytes") + "</DATA8>");
					resultXML.append("<DATA9>" + makeListField(docXML.getElementsByTagName("PAGENUM").item(k).getTextContent()) + "</DATA9>");
					resultXML.append("<DATA10><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHFILENAME").item(k).getTextContent()) + "]]></DATA10>");
					resultXML.append("<DATA11><![CDATA[" + makeListField(docXML.getElementsByTagName("BODYATTACH").item(k).getTextContent()) + "]]></DATA11>");
					resultXML.append("<DATA12><![CDATA[" + makeListField(docXML.getElementsByTagName("DISPLAYNAME").item(k).getTextContent()) + "]]></DATA12>");
					resultXML.append("<DATA13><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERNAME").item(k).getTextContent()) + "]]></DATA13>");
					resultXML.append("<DATA14><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERNAME2").item(k).getTextContent()) + "]]></DATA14>");
					resultXML.append("<DATA15><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERJOBTITLE").item(k).getTextContent()) + "]]></DATA15>");
					resultXML.append("<DATA16><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERJOBTITLE2").item(k).getTextContent()) + "]]></DATA16>");
					resultXML.append("<DATA17><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERDEPTNAME").item(k).getTextContent()) + "]]></DATA17>");
					resultXML.append("<DATA18><![CDATA[" + makeListField(docXML.getElementsByTagName("ATTACHUSERDEPTNAME2").item(k).getTextContent()) + "]]></DATA18>");
					resultXML.append("<ISBIGATTACH><![CDATA[" + makeListField(docXML.getElementsByTagName("ISBIGATTACH").item(k).getTextContent()) + "]]></ISBIGATTACH>");
					resultXML.append("<ISBIGATTACHDEL><![CDATA[" + makeListField(docXML.getElementsByTagName("ISBIGATTACHDEL").item(k).getTextContent()) + "]]></ISBIGATTACHDEL>");
				}
				resultXML.append("</CELL>");
			}
			resultXML.append("</ROW>");
		}
		resultXML.append("</ROWS>");
		resultXML.append("</LISTVIEWDATA>");

		logger.debug("getAttachFileInfo ended");
		
		return resultXML.toString();
	}

	@Override
	public String updateHistoryForAttach(String docID, String attachSN, String tempUserID, String tempUserName, String tempUserName2, String tempUserJobTitle, String tempUserJobTitle2,
			String tempUserDeptID, String tempUserDeptName, String tempUserDeptName2, String modifyFlag, String dirPath, String companyID, int tenantID) throws Exception {
		logger.debug("updateHistoryForAttach started");

		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID.trim());
		map.put("v_ATTACHFILESN", attachSN.trim());
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		int strSN = ezApprovalGDAO.updateHistoryForAttach_M(map) + 1;
		// 첨부파일 리스트 추출
		List<ApprGAttachInfoVO> apprGAttachInfoVOList = ezApprovalGDAO.updateHistoryForAttach_I(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGAttachInfoVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGAttachInfoVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		// 첨부파일이 존재하는 경우
		if (docXML.getElementsByTagName("ATTACHFILENAME").getLength() > 0) {
			String oldYear = getDocHrefYear(docID, companyID, tenantID);
			String source = convWebToPath(docXML.getElementsByTagName("ATTACHFILEHREF").item(0).getTextContent(), dirPath, tenantID);
			String target = dirPath + commonUtil.separator + companyID + commonUtil.separator + "uploadFile" + commonUtil.separator + oldYear + commonUtil.separator + "history" + commonUtil.separator +
					getDocDir(docID) + commonUtil.separator + docID.trim() + getNDigitNum(attachSN, 4) + getNDigitNum(String.valueOf(strSN), 4) + docXML.getElementsByTagName("ATTACHFILENAME").item(0).getTextContent();
			// history 디렉토리로 copy
			EzFAL.copyFile(new EzFile(commonUtil.detectPathTraversal(source)), new EzFile(commonUtil.detectPathTraversal(target)));
			// DB에 저장될 target 경로 재설정
			target = commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator + companyID + commonUtil.separator + "uploadFile" + commonUtil.separator + oldYear + commonUtil.separator + "history" + commonUtil.separator +
					getDocDir(docID) + commonUtil.separator + docID.trim() + getNDigitNum(attachSN, 4) + getNDigitNum(String.valueOf(strSN), 4) + docXML.getElementsByTagName("ATTACHFILENAME").item(0).getTextContent();
			
			Map<String, Object> map1 = new HashMap<String, Object>();
			map1.put("companyID", companyID);
			map1.put("v_DOCID", docID.trim());
			map1.put("v_ATTACHSN", attachSN.trim());
			map1.put("v_ATTACHNAME", docXML.getElementsByTagName("ATTACHFILENAME").item(0).getTextContent());
			map1.put("v_ATTACHDISPNAME", docXML.getElementsByTagName("DISPLAYNAME").item(0).getTextContent());
			map1.put("v_ATTACHHREF", target);
			map1.put("v_ATTACHSIZE", docXML.getElementsByTagName("ATTACHFILESIZE").item(0).getTextContent());
			map1.put("v_USERID", tempUserID);
			map1.put("v_USERNAME", tempUserName);
			map1.put("v_USERNAME2", tempUserName2);
			map1.put("v_USERJOBTITLE", tempUserJobTitle);
			map1.put("v_USERJOBTITLE2", tempUserJobTitle2);
			map1.put("v_USERDEPTID", tempUserDeptID);
			map1.put("v_USERDEPTNAME", tempUserDeptName);
			map1.put("v_USERDEPTNAME2", tempUserDeptName2);
			map1.put("v_MODIFYSN", String.valueOf(strSN));
			map1.put("v_MODIFYFLAG", modifyFlag.trim());
			map1.put("v_PAGENUM", docXML.getElementsByTagName("PAGENUM").item(0).getTextContent());
			map1.put("v_TENANTID", tenantID);
			map1.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
			
			ezApprovalGDAO.updateHistoryForAttach(map1);
		}

		logger.debug("updateHistoryForAttach ended");
		
		return "TRUE";
	}

	@Override
	public String updateAttachFileInfo(Document xmlDom, String companyID, String lang, int tenantID) throws Exception {
		logger.debug("updateAttachFileInfo started");

		String docID = xmlDom.getElementsByTagName("ROW").item(0).getChildNodes().item(3).getTextContent();
		String rtnVal = deleteAttachFileInfo(docID, companyID, lang, tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		
		if (rtnVal.equals("TRUE")) {
			String size = "";
			for (int k = 0; k < xmlDom.getElementsByTagName("ROW").getLength(); k++) {
				size = xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(8).getTextContent().replace("bytes", "").trim();
				
				/* 2020-03-25 홍승비 - 첨부파일 저장 시점부터 순서값 VIEWORDER 삽입 */
				map.put("v_DOCID", docID);
				map.put("v_ATTACHFILESN", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(2).getTextContent());
				map.put("v_VIEWORDER", (xmlDom.getElementsByTagName("ROW").getLength() - k));
				map.put("v_ATTACHFILENAME", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(10).getTextContent());
				map.put("v_ATTACHFILEHREF", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(1).getTextContent());
				map.put("v_ATTACHFILESIZE", size);
				map.put("v_ATTACHUSERID", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(4).getTextContent());
				map.put("v_ATTACHUSERNAME", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(13).getTextContent());
				map.put("v_ATTACHUSERNAME2", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(14).getTextContent());
				map.put("v_ATTACHUSERJOBTITLE", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(15).getTextContent());
				map.put("v_ATTACHUSERJOBTITLE2", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(16).getTextContent());
				map.put("v_ATTACHUSERDEPTID", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(6).getTextContent());
				map.put("v_ATTACHUSERDEPTNAME", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(17).getTextContent());
				map.put("v_ATTACHUSERDEPTNAME2", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(18).getTextContent());
				map.put("v_PAGENUM", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(9).getTextContent());
				map.put("v_DISPLAYNAME", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(12).getTextContent());
				map.put("v_BODYATTACH", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(11).getTextContent());
				map.put("FLAG", "Y");
				map.put("companyID", companyID);
				map.put("v_TENANTID", tenantID);
				
				/* 2020-11-12 홍승비 - 대용량첨부 플래그, 첨부파일 최초 저장일 추가 */
				map.put("v_ISBIGATTACH", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(19).getTextContent());
				map.put("v_ISBIGATTACHDEL", xmlDom.getElementsByTagName("ROW").item(k).getChildNodes().item(20).getTextContent());
				map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
				
				ezApprovalGDAO.insertAprAttachInfo(map);
				ezApprovalGDAO.updateHistoryAttachInfo(map);
				ezApprovalGDAO.updateAttachFileInfo(map);

				if (config.getProperty("config.useOpenGov").equals("YES")) {
					ezApprovalGDAO.insertOpenGovAttachInfo(map);
				}
			}
		}

		logger.debug("updateAttachFileInfo ended");
		
		return rtnVal;
	}

	@Override
	public String deleteAttachFileInfo(String docID, String companyID, String lang, int tenantID) throws Exception {
		logger.debug("deleteAttachFileInfo started");

		Map<String, Object> map = new HashMap<String, Object>();
		
		map.put("v_DOCID", docID);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		ezApprovalGDAO.deleteAttachFileInfo(map);
		// 원문정보공개 첨부파일 삭제
		ezApprovalGDAO.deleteOpenGovAttachInfo(map);
		
		int attachFile = ezApprovalGDAO.countAttachFile(map);
		
		if (attachFile > 0) {
			map.put("FLAG", "Y");
			ezApprovalGDAO.updateAttachFileInfo(map);
		} else {
			map.put("FLAG", "N");
			ezApprovalGDAO.updateAttachFileInfo(map);
		}

		logger.debug("deleteAttachFileInfo ended");
		
		return "TRUE";
	}

