	@Override
	public String deleteTmpDocInfo(String userID, String sn, String path, String companyID, String lang, int tenantID) throws Exception {
		logger.debug("deleteTmpDocInfo started");

		String rtnVal = "";
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_PUSERID", userID.trim());
		map.put("v_PSN", sn);
		map.put("v_TENANTID", tenantID);
		
		String href = ezApprovalGDAO.getTmpHref(map);
		
		map.put("href", href);
		
		ArrayList<String> docList = ezApprovalGDAO.getTmpDocList(map);
        List<String> hrefList = new ArrayList<>();
        boolean btype = false;
        int tmpSN = Integer.parseInt(sn);
        if(docList.isEmpty()){
            btype = true;
            String tmpDocID = ezApprovalGDAO.getTmpDocID(map);
            if(tmpDocID != null)
                docList.add(tmpDocID);
        }
        if(!docList.isEmpty()){
            List<ApprGGroupDocInfoVO> group = getGroupDocList(docList.get(docList.size() - 1), "TMP", tenantID, companyID);
            if(group.isEmpty()){
                hrefList.add(href);
            }

            for (int i = 0; i < group.size(); i++) {
                ApprGGroupDocInfoVO apr = group.get(i);
                String id = apr.getDocID();
                if(!docList.contains(id))
                    docList.add(id);
                if(btype)
                    hrefList.add(getDocHref(userID + "@" + (tmpSN + i), "TMP", "", "", companyID, tenantID));
                else
                    hrefList.add(apr.getDocHref() == null ? getDocHref(id, "APR", "", "", companyID, tenantID) : apr.getDocHref());
            }
        }
		for (String s : docList) {
			map.put("v_DocID", s);
			//기존 임시저장문서 지우기
			ezApprovalGDAO.aprDeleteDocInfo(map);
			ezApprovalGDAO.aprDeleteDocInfo2(map);
			ezApprovalGDAO.aprDeleteDocInfo3(map);
			ezApprovalGDAO.aprDeleteDocInfo4(map);
			ezApprovalGDAO.aprDeleteDocInfo5(map);
			ezApprovalGDAO.aprDeleteDocInfo6(map);
			ezApprovalGDAO.aprDeleteDocInfo7(map);
			ezApprovalGDAO.aprDeleteDocInfo8(map);
			ezApprovalGDAO.aprDeleteDocInfo9(map);
            deleteSummaryFile(s, companyID, tenantID);
		}

        for(int i = 0; i < hrefList.size(); i++){
            map.put("v_PSN", tmpSN + i);
            href = hrefList.get(i);
            ezApprovalGDAO.deleteTmpDocInfo(map);
            ezApprovalGDAO.deleteTmpDocInfo2(map);
            ezApprovalGDAO.deleteTmpDocInfo3(map);
            ezApprovalGDAO.deleteTmpDocInfo4(map);
            ezApprovalGDAO.deleteTmpDocInfo5(map);
            ezApprovalGDAO.deleteTmpDocInfo6(map);
            ezApprovalGDAO.deleteTmpDocInfo7(map);
            ezApprovalGDAO.deleteTmpDocInfo8(map);

            EzFile file = new EzFile(commonUtil.detectPathTraversal(path + href));
            file.delete();
        }
		
		rtnVal = "<RESULT>TRUE</RESULT>";

		logger.debug("deleteTmpDocInfo ended");
		
		return rtnVal;
	}

	@Override
	public String doProcess(String aprState, String docID, String userID, String userName, String userName2, String dirPath, String deptID, String html, Document strXML, String proxyUserID,
			String companyID, String lang, LoginVO userInfo) throws Exception {
		logger.debug("doProcess started");

        Node approvback = strXML.getElementsByTagName("APPROVBACK").item(0);
        String[] split = docID.split(",");
        if(approvback != null){
            String isBack = approvback.getTextContent();
            if("Y".equals(isBack)){
                String formid = strXML.getElementsByTagName("FORMID").item(0).getTextContent();
                String[] formsp = formid.split(",");
                
                String result = mobileSrvConn_HWP(userInfo.getId(), "A", formsp[0], "", split[0], userID, userInfo.getLang(), strXML.getElementsByTagName("ORGCOMPANYID").item(0).getTextContent(),
                        null, userInfo, "APR", "");
                if(result.equals("ERROR"))
                    throw new Exception("draftAllTypeB 최종결재시 오류발생");

//                for(int i = 0; i < split.length; i++){
//                    // orgUID 원결재자 ID
//                    String result = mobileSrvConn_HWP(userInfo.getId(), "A", formsp[i], "", split[i], userID, userInfo.getLang(), strXML.getElementsByTagName("ORGCOMPANYID").item(0).getTextContent(),
//                            null, userInfo, "APR", "");
//                    if(result.equals("ERROR"))
//                        throw new Exception("draftAllTypeB 최종결재시 오류발생");
//                }
                return "<RESULT>TRUE</RESULT>"; 
            }
        }

        String subSQL = "";
		String result = "";
		boolean rtnVal = true;
		
		//재사용시 이전 docID 가져오기 위한 것
		String beforeDocID = "";
		String isUsed = "";
		
		//현재 문서 채번 정보
		String curDocNum = "";
		String chamState = strXML.getElementsByTagName("DOCSTATE").item(0).getTextContent();
		
		//비전자문서 구분 값
		String nonElecRecXML = "";
		
		//기결재통과 플래그
		String passAprLine = "";
        
        // 통합알림 전송 여부 (일괄기안 때문에 필요)
        String sendNotiFlag = "";
        
        //자동 임시저장
        String autoSaveFlag = "";
        String autoSaveDocSN = "";
        String FautoSaveFlag = "";
		
		if (strXML.getElementsByTagName("PASSAPRLINE").getLength() > 0) {
			passAprLine = strXML.getElementsByTagName("PASSAPRLINE").item(0).getTextContent();
		}
		
		if (strXML.getElementsByTagName("NONELECREC").getLength() > 0) {
			nonElecRecXML = nonElecRecInfoToXML(strXML);
		}
		
		if (strXML.getElementsByTagName("CURDOCNUM").getLength() > 0) {
			curDocNum = strXML.getElementsByTagName("CURDOCNUM").item(0).getTextContent();
		}
		
		if (strXML.getElementsByTagName("beforeDocID").getLength() > 0) {
			beforeDocID = strXML.getElementsByTagName("beforeDocID").item(0).getTextContent();
		}
		
		if (strXML.getElementsByTagName("isUsed").getLength() > 0) {
			isUsed = strXML.getElementsByTagName("isUsed").item(0).getTextContent();
		}

        if (strXML.getElementsByTagName("SENDNOTIFLAG").getLength() > 0) {
        	sendNotiFlag = strXML.getElementsByTagName("SENDNOTIFLAG").item(0).getTextContent();
        }

        if (strXML.getElementsByTagName("autoSaveFlag").getLength() > 0) {
            autoSaveFlag = strXML.getElementsByTagName("autoSaveFlag").item(0).getTextContent();
        }

        if (strXML.getElementsByTagName("FautoSaveFlag").getLength() > 0) {
            FautoSaveFlag = strXML.getElementsByTagName("FautoSaveFlag").item(0).getTextContent();
        }
		
        if(split.length > 1){
            for(int i = 0; i < split.length; i++)
                saveAprGroupAndDelTmp(split[i], i + 1 + "", split[0], split[0], companyID, userInfo.getTenantId());
        }
            
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID.trim().split(","));
		map.put("v_TENANTID", userInfo.getTenantId());
		map.put("v_USERID", userID.trim());
		map.put("v_ISUSED", "");
		
		String oldDocID = "";
		if(strXML.getElementsByTagName("saveFlag").getLength() > 0) {
			oldDocID = strXML.getElementsByTagName("oldDocID").item(0).getTextContent();
			map.put("v_DOCID", oldDocID.split(","));
		}
		
		if (isUsed.equals("reuse")) {
			map.put("v_ISUSED", isUsed);
			map.put("v_DOCID", beforeDocID.trim());
		}
		
		logger.debug("doProcess param : v_DOCID =" + docID.trim() + " v_TENANTID =" + userInfo.getTenantId() + " v_USERID =" + userID.trim());
		// 진행 or 보류인 결재라인 정보 호출 TBL_APRDOCINFO
		int aprCount = ezApprovalGDAO.doProcessCount(map);
        
        //결재선 지정 이전에 자동 임시저장시 기안자만 결재선에 추가하여 임시저장
        if(aprCount == 0 && "autosave".equals(FautoSaveFlag)){
            LocalDateTime now = LocalDateTime.now(ZoneId.of("UTC"));
            String nowStr = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss").format(now);
            
            Map<String, Object> param = new HashMap<String, Object>();
            param.put("v_DOCID", oldDocID);
            param.put("v_APRMEMSN", 1);
            param.put("v_APRTYPE", "018");
            param.put("v_APRSTATE", "002");
            param.put("v_APRMEMID", userInfo.getId());
            param.put("v_APRMEMDEPTYN", "N");
            param.put("v_APRMEMNM", userInfo.getDisplayName());
            param.put("v_APRMEMNM2", userInfo.getDisplayName2());
            param.put("v_APRMEMJOBTITLE", userInfo.getTitle());
            param.put("v_APRMEMJOBTITLE2", userInfo.getTitle2());
            param.put("v_APRMEMBERDEPTID", userInfo.getDeptID());
            param.put("v_APRMEMBERDEPTNAME", userInfo.getDeptName());
            param.put("v_APRMEMBERDEPTNAME2", userInfo.getDeptName2());
            param.put("v_APRMEMBERLDAPPATH", userInfo.getCompanyID());
            param.put("v_RECEIVEDDATE", nowStr);
            param.put("v_PROCESSDATE", nowStr);
            param.put("v_REASONDONOTAPPROV", "");
            param.put("v_ISPROPOSERYN", "N");
            param.put("v_ISBRIEFUSERYN", "N");
            param.put("v_TENANTID", userInfo.getTenantId());
            param.put("companyID", companyID);

            ezApprovalGDAO.insertApprLine(param);
            aprCount = 1;
        }
		
		if (aprCount < 1) {
			if (strXML.getElementsByTagName("DOCSTATE").item(0).getTextContent() != null) {
				if (strXML.getElementsByTagName("DOCSTATE").item(0).getTextContent().equals("017")) {
					map.put("v_MODE", "END");
					aprCount =  ezApprovalGDAO.checkAprLine(map);
				}
			}
		}
		//count만 이전 꺼 가져오고 다시 원복
		map.put("v_DOCID", docID.trim());
		logger.debug("doProcess value : aprCount =" + aprCount);
		logger.debug("doProcess aprState =" + aprState);
		
		if (aprCount < 1 && !aprState.equals(staASmikyul)) {
			rtnVal = false;
		} else {
			switch (aprState) {
			case "000": // 미결
				if (rtnVal) {
					subSQL = updateDocInfo(strXML, userID, companyID, lang, userInfo.getTenantId());
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				break;
				
			case "003": // 승인
				if (!strXML.getElementsByTagName("DOCSTATE").item(0).getTextContent().equals("017")) {
					if (rtnVal) {
						subSQL = updateDocInfo(strXML, userID, companyID, lang, userInfo.getTenantId());
						
						if (subSQL.toUpperCase().equals("FALSE")) {
							rtnVal = false;
						} 
					}
				}
				if (rtnVal) {
					subSQL = doApprove(docID, userID, aprState, userName, userName2, dirPath, deptID, proxyUserID, companyID, lang, userInfo, curDocNum, chamState, nonElecRecXML, passAprLine, sendNotiFlag);
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				break;
				
			case "004": // 반송
				if (rtnVal) {
					subSQL = updateDocInfo(strXML, userID, companyID, lang, userInfo.getTenantId());
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				if (rtnVal) {
					subSQL = doBansong(docID, "", userID, aprState, dirPath, deptID, companyID, lang, userInfo, curDocNum, sendNotiFlag);
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				break;
				
			case "005": // 보류
				if (rtnVal) {
					subSQL = updateDocInfo(strXML, userID, companyID, lang, userInfo.getTenantId());
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				if (rtnVal) {
					subSQL = doBoryu(docID, userID, aprState, companyID, lang, userInfo.getTenantId(), userInfo.getDisplayName(), sendNotiFlag);
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				break;
				
			case "001": // 대기
				if (rtnVal) {
					subSQL = updateDocInfo(strXML, userID, companyID, lang, userInfo.getTenantId());
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				if (rtnVal) {
					logger.debug("doapprov makeTmpDocInfo started. userID = " + userID + " || docID = " + docID + " || proxyUserID = " + proxyUserID + " || companyID = " + companyID + " || tenantID = " + userInfo.getTenantId());

					String listType = "";
					if (strXML.getElementsByTagName("LISTTYPE").getLength() > 0) {
						listType = strXML.getElementsByTagName("LISTTYPE").item(0).getTextContent();
					}

					String draftFlag = "";
					if (strXML.getElementsByTagName("DRAFTFLAG").getLength() > 0) {
						draftFlag = strXML.getElementsByTagName("DRAFTFLAG").item(0).getTextContent();
					}
					
					String FormHref = "";
					if (strXML.getElementsByTagName("FORMHREF").getLength() > 0) {
						FormHref = strXML.getElementsByTagName("FORMHREF").item(0).getTextContent();
					}
					
					String docSN = "";
					if (strXML.getElementsByTagName("DOCSN").getLength() > 0) {
						docSN = strXML.getElementsByTagName("DOCSN").item(0).getTextContent();
					}

                    String tmp = docID;
                    String[] split2 = FormHref.split(",");
                    String[] split3 = docSN.split(",");
                    String[] split4 = oldDocID.split(",");
                    for(int d = 0; d < split.length; d++){
                        docID = split[d];
                        FormHref = split2[d];
                        docSN = split3.length == 0 ? "" : split3[d];
                        oldDocID = "".equals(split4[0]) ? "" : split4[d];
                    if (!FormHref.equals("") && listType.equals("21") && draftFlag.equals("REDRAFT") && !oldDocID.equals("") && !beforeDocID.equals("")) {
						if (!compareTmpDocID(FormHref, docSN, companyID, userInfo.getTenantId())) {
							return "<RESULT>FALSE</RESULT>";
						} else {
							String path = userInfo.getRealPath() + commonUtil.getUploadPath("upload_approvalG.ROOT", userInfo.getTenantId()) + commonUtil.separator;
							
							String delRtn = deleteTmpDocInfo(userID, docSN.split("@")[1], path, userInfo.getCompanyID(), userInfo.getLang(), userInfo.getTenantId());
							if (!delRtn.equals("<RESULT>TRUE</RESULT>")) {
								return "<RESULT>FALSE</RESULT>";
							}
						}
					}

                    String autopDocSN = "";
                    if (strXML.getElementsByTagName("autopDocSN").getLength() > 0) {
                        autopDocSN = strXML.getElementsByTagName("autopDocSN").item(0).getTextContent();
                    }

                    if (autoSaveFlag.equals("Y")) {
                        subSQL = autopDocSN.split("@")[1];
                    }else{
                        subSQL = "";
                    }
					
 					if (oldDocID.equals("")) {
						subSQL = makeTmpDocInfo(userID, docID, autoSaveFlag, companyID, lang, userInfo.getTenantId(), docID, subSQL);
					} else { // 임시저장 여러번 반복 시
						subSQL = makeTmpDocInfo(userID, docID, autoSaveFlag, companyID, lang, userInfo.getTenantId(), oldDocID, subSQL);
						subSQL = makeTmp2IngDocInfo(userID, subSQL, companyID, lang, userInfo.getTenantId(), docID, oldDocID, autoSaveFlag);
					}
					}
                    docID = tmp;
					logger.debug("doapprov makeTmpDocInfo ended.");
					
					if (subSQL.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					} 
				}
				
				break;
			}
		}
		
        for(int d = 0; d < split.length; d++){
            docID = split[d];
            chkDocDelete(docID, docID, rtnVal, userID, deptID, dirPath, companyID, userInfo.getTenantId());
        }
		if (rtnVal) {
			result = "<RESULT>TRUE</RESULT>";
		} else {
			result = "<RESULT>FALSE</RESULT>";
		}

		logger.debug("doProcess ended");
		
		return result;
	}

	@Override
	public String getTotalAttachSize(String docID, String companyID, int tenantID) throws Exception {
		logger.debug("getTotalAttachSize started");

		Map<String, Object> map = new HashMap<String, Object>();
		
        String[] sp = docID.split(",");
        String attachSizes = "";
        
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		int temp = 0;
        List<ApprGAttachInfoVO> apprGAttachInfoVOList = null;
        String biggestSize = "0";

        for(int i = 0; i < sp.length; i++){
            map.put("v_DOCID", sp[i]);
            // 외부 수신처가 존재하는지 체크 (외부시행문이어도 수신자가 회사 내부 조직도라면 추가적으로 용량을 체크하지 않음)
            temp = ezApprovalGDAO.getTotalAttachSizeTemp(map);
            if ( temp > 0 ) {
                map.put("v_temp" , "1");
            } else {
                map.put("v_temp" , "0");
            }

            if(temp > 0 || i == 0)
                apprGAttachInfoVOList = ezApprovalGDAO.getTotalAttachSize(map);
            attachSizes += "," + apprGAttachInfoVOList.get(0).getTotalSize();
            
            if(Integer.parseInt(apprGAttachInfoVOList.get(0).getTotalSize()) > Integer.parseInt(biggestSize))
                biggestSize = apprGAttachInfoVOList.get(0).getTotalSize();
            if("Y".equals(apprGAttachInfoVOList.get(0).getFlag())){
                if(sp.length > 1)
                    apprGAttachInfoVOList.get(0).setPageNum(i + 1 + "");
                break;
            }
        }
        apprGAttachInfoVOList.get(0).setTotalSize(biggestSize);
        
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGAttachInfoVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGAttachInfoVOList.get(i)));
		}
		
		// 외부발송일 경우 외부발송 플래그 추가 2018-07-13 강민수92
		if (temp > 0) {
			sb.append("<ROW><EXTFLAG>Y</EXTFLAG></ROW>");
		}
        
        sb.append("<TOTALSIZE>" + attachSizes + "</TOTALSIZE>");
		sb.append("</DATA>");

		logger.debug("getTotalAttachSize ended");
		
		return sb.toString();
	}

