	@Override
	public String getSignInfo(String docID, String offset, Locale locale, String primary, String companyID, int tenantID) throws Exception {
		logger.debug("getSignInfo started");

		StringBuilder resultXML = new StringBuilder();
		
		resultXML.append("<SIGNINFOS>");
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_DOCID", docID.trim());
		map.put("primary", primary);
		
		List<ApprGSignInfoVO> apprGSignInfoVOList = ezApprovalGDAO.getSignInfo(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGSignInfoVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGSignInfoVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		
		for (int k = 0; k < docXML.getElementsByTagName("ROW").getLength(); k++) {
			resultXML.append("<SIGNINFO>");
			resultXML.append("<DOCID>" + docID + "</DOCID>");
			resultXML.append("<APRSN>" + makeListField(docXML.getElementsByTagName("APRSN").item(k).getTextContent()) + "</APRSN>");
			resultXML.append("<SIGNTYPE>" + makeListField(docXML.getElementsByTagName("SIGNTYPE").item(k).getTextContent()) + "</SIGNTYPE>");
			
			// 2023-05-12 이사라 : NullPointerException 시큐어코딩
			String tempSignName = Optional.ofNullable(makeListField(docXML.getElementsByTagName("SIGNNAME").item(k).getTextContent())).orElse("");
			String tempContent = Optional.ofNullable(makeListField(docXML.getElementsByTagName("CONTENT").item(k).getTextContent())).orElse("");
			
			resultXML.append("<SIGNNAME>" + tempSignName + "</SIGNNAME>");
			
			if (tempContent != null && tempSignName.indexOf("date") > -1 && tempContent.length() > 18) {
				resultXML.append("<CONTENT>" + makeXMLString(commonUtil.getDateStringInUTC(tempContent, offset, false).substring(5, 10).replace("-", ".")) + "</CONTENT>");
			} else {
				/* 2023-11-30 홍승비 - 부재자설정 중 자동결재(결재통과) 시, TBL_SIGNINFO 테이블에 부재사유를 코드(b1~b12)가 아닌 메세지로 저장하도록 수정하였으므로 참고삼아 주석을 기재함. */
				if (tempContent.equals("b1") || tempContent.equals("b2") || tempContent.equals("b3") || tempContent.equals("b4") || tempContent.equals("b5") || tempContent.equals("b6") || tempContent.equals("b7") || tempContent.equals("b8") || tempContent.equals("b9") || tempContent.equals("b10") || tempContent.equals("b11") || tempContent.equals("b12")) {
					resultXML.append("<CONTENT>" + messageSource.getMessage("ezApprovalG." + tempContent, locale) + "</CONTENT>");
				} else {
					resultXML.append("<CONTENT>" + makeXMLString(tempContent) + "</CONTENT>");
				}
			}
			
			resultXML.append("<APRMEMBERNAME>" + makeListField(docXML.getElementsByTagName("APRMEMBERNAME").item(k).getTextContent()) + "</APRMEMBERNAME>");
			
			resultXML.append("</SIGNINFO>");
		}
		
		// 개인병렬합의/협조 관련 추가 작업		
		String agreeReturnType = ezCommonService.getTenantConfig("PersonalAgreeReturnType", tenantID);
		
		if (agreeReturnType != null && agreeReturnType.equalsIgnoreCase("2")) {
			boolean chkBansong = false;
			map.put("v_FLAG", "1");
			List<ApprGAprLineVO> vo = ezApprovalGDAO.getAprLineInfo(map);
			
			for (int i = 0; i < vo.size(); i++) {
				if(vo.get(i).getAprType().equalsIgnoreCase(staATByungRyulHyubJo) && vo.get(i).getAprState().equalsIgnoreCase(staASBanSong)) {
					chkBansong = true;
				}
			}
			
			resultXML.append("<CHKBANSONG>");
			
			if (chkBansong) {
				resultXML.append("TRUE");
			} else {
				resultXML.append("FALSE");
			}
			
			resultXML.append("</CHKBANSONG>");
		}		
		
		resultXML.append("</SIGNINFOS>");

		logger.debug("getSignInfo ended");
		
		return resultXML.toString();
	}

