	/**
	 * 각 문서별 서명 정보 업데이트
	 * DOCID 기준으로 저장
	 * */
	@Override
	public String updateSignInfo(Document xmlDom, String companyID, String mode, int tenantID) throws Exception {
		logger.debug("updateSignInfo started");

		String docID = xmlDom.getElementsByTagName("DOCID").item(0).getTextContent().trim();
		String orgCompanyID = xmlDom.getElementsByTagName("ORGCOMPANYID").item(0).getTextContent().trim();
		
		if (!orgCompanyID.equals("") && !orgCompanyID.equals(companyID)) {
			companyID = orgCompanyID;
		}
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);

        String[] split = docID.split(",");
        for(int i = 0; i < split.length; i++){
            docID = split[i];
            map.put("v_DOCID", docID);
            int aprSN = ezApprovalGDAO.updateSignInfoAprSN(map); // 서명 순번 추출
            int signLength = xmlDom.getElementsByTagName("SIGNINFO").getLength();
            int maxAprSN = 0;

            for (int k = 0; k < signLength; k++) {
                maxAprSN = aprSN + k + 1;

                map.put("v_MAXAPRSN", maxAprSN);
                map.put("v_SIGNTYPE", xmlDom.getElementsByTagName("SIGNTYPE").item(k).getTextContent());
                map.put("v_SIGNNAME", xmlDom.getElementsByTagName("SIGNNAME").item(k).getTextContent());
                map.put("v_CONTENT", xmlDom.getElementsByTagName("CONTENT").item(k).getTextContent());

                ezApprovalGDAO.insertSignInfo(map);
            }
        }

		logger.debug("updateSignInfo ended");
		
		return "TRUE";
	}

	@Override
	public String getCallBackYN(String docID, String tempUserID, String companyID, int tenantID) throws Exception {
		logger.debug("getCallBackYN started");

		boolean rtnVal = true;
		String rtnXML = "";
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID.trim());
		map.put("v_USERID", tempUserID);
		map.put("v_TENANTID", tenantID);
		
		List<ApprGLineTempletVO> apprGLineTempletVOList = ezApprovalGDAO.getCallBackYNLineList(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGLineTempletVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGLineTempletVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		
		int dlength = docXML.getElementsByTagName("ROW").getLength();
		
		if (dlength >= 2) {
			String currAprType = makeListField(docXML.getElementsByTagName("APRTYPE").item(0).getTextContent());
			String nextAprType = makeListField(docXML.getElementsByTagName("APRTYPE").item(1).getTextContent());
			
			if (!(currAprType.equals(staATGyulJe) || currAprType.equals(staatwhoakin) || currAprType.equals(staATgian) || currAprType.equals(staATgumto))) {
				rtnVal = false;
			}
			
			if (!(nextAprType.equals(staATGamSaBu) || nextAprType.equals(staATDekyul) || nextAprType.equals(staATgumto) || nextAprType.equals(staATGyulJe) || nextAprType.equals(staatwhoakin) || nextAprType.equals(staATJunGyul) || nextAprType.equals(staATSoonChaHyubJo) || nextAprType.equals(staATByungRyulHyubJo))) {
				rtnVal = false;
			}
			
			if (!staATByungRyulHyubJo.equals(currAprType) && staATByungRyulHyubJo.equals(nextAprType)) { 
			    // 개인순차/병렬협조일때 협조자가 한명이라두 결재했으면 회수못하게 하는데 개인협조는 아래에서 걸러지므로 병렬협조만 처리
			    map.put("v_APRMEMBERSN", apprGLineTempletVOList.get(0).getAprMemberSN());
			    List<ApprGLineTempletVO> nextAprLineList = ezApprovalGDAO.getNextAprLineInfo(map);
			    
			    for (int i = 0, len = nextAprLineList.size(); i < len; i++) {
			        if (!staATByungRyulHyubJo.equals(nextAprLineList.get(i).getAprType())) {
			            break;
			        }
			        
			        if (!staASJinHang.equals(nextAprLineList.get(i).getAprState())) {
			            rtnVal = false;
			            break;
			        }
			    }
			}
			
			String aprState = makeListField(docXML.getElementsByTagName("APRSTATE").item(1).getTextContent());
			
			if (!aprState.equals(staASJinHang)) {
				rtnVal = false;
			}
			
			if (rtnVal) {
				if (makeListField(docXML.getElementsByTagName("APRMEMBERSN").item(0).getTextContent()).equals("1")) {
					rtnXML = "<RESULT>CALLBACK</RESULT>";
				} else {
					rtnXML = "<RESULT>CANCEL</RESULT>";
				}
			}
		} else {
			rtnVal = false;
		}
		
		if (rtnXML.equals("")) {
			logger.debug("getCallBackYN ended");
			return "<RESULT>FALSE</RESULT>";
		} else {
			logger.debug("getCallBackYN ended");
			return rtnXML;
		}
	}

	@Override
	public String getCallBackYNForceLine(String docID, String tempUserID, String companyID, int tenantID) throws Exception {
		logger.debug("getCallBackYNForceLine started");

		String docList = getCallBackYNForceLineList(docID, companyID, tempUserID, tenantID);
		Document docXML = commonUtil.convertStringToDocument(docList);
		
		String result = "<RESULT>TRUE</RESULT>";
		
		if (docXML.getElementsByTagName("ROW").getLength() > 1) {
			boolean NextLineCheck = false;
			for (int i = 0; i < docXML.getElementsByTagName("ROW").getLength(); i++) {
				String aprtype = docXML.getElementsByTagName("APRTYPE").item(i).getTextContent();
				String aprstate = docXML.getElementsByTagName("APRSTATE").item(i).getTextContent();
				String aprmenberid = docXML.getElementsByTagName("APRMEMBERID").item(i).getTextContent();
				
				if (!NextLineCheck && tempUserID.trim().equals(aprmenberid.trim())) {
					NextLineCheck = true;
					if (!(aprtype.equals("001") || aprtype.equals("002") || aprtype.equals("008") || aprtype.equals("009") || aprtype.equals("018") || aprtype.equals("019"))) {
						result = "<RESULT>FALSE</RESULT>";
						break;
					}
					if (i == 0 && docXML.getElementsByTagName("APRSTATE").item(0).getTextContent().equals("002")) {
						result = "<RESULT>FALSE</RESULT>";
						break;
					}
					
					continue;
				}
				if (NextLineCheck) {
					if (!(aprtype.equals("001") || aprtype.equals("002") || aprtype.equals("004") || aprtype.equals("007") || aprtype.equals("008") || aprtype.equals("009") || aprtype.equals("013") || aprtype.equals("016") || aprtype.equals("019"))) {
						result = "<RESULT>FALSE</RESULT>";
						break;
					}
					
					if (aprstate.equals("002")) {
						break;
					}
				}
			} 
		} else {
			result = "<RESULT>FALSE</RESULT>";
		}

		logger.debug("getCallBackYNForceLine ended");
		    
		return result;
	}

