	@Override
	public String registerCabinet(Document xmlDom, String strLang, int tenantID) throws Exception {
		logger.debug("registerCabinet started");

		String subSQL = "";
		
		String companyID = xmlDom.getElementsByTagName("COMPANYID").item(0).getTextContent();
		String deptCode = xmlDom.getElementsByTagName("DEPTCODE").item(0).getTextContent().trim();
		String taskCode = xmlDom.getElementsByTagName("TASKCODE").item(0).getTextContent();
		
		/* 2025-04-01 홍승비 - 전자결재G > 기산일(회계년도) 시간대 기준 값을 테넌트 컨피그로 옵션화, 디폴트로 UTC 정시가 아닌 한국시(UTC + 9)를 기준으로 사용하도록 수정 */
		String createDate = commonUtil.getTodayUTCTime("");
		String accountYearTimeZone = ezCommonService.getTenantConfig("accountYearTimeZone", tenantID);
		
		if ("KST".equals(accountYearTimeZone)) {
			createDate = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), "235|+09:00", false);
		}
		
		//'기록물철 분류번호: 처리과기관코드+단위업무코드+생산년도+등록일련번호
		//수정(2007.07.26 김상건) : 회계년도가 3월 ~ 익년 2월까지이므로 RegYear 년도는 회계년도 값을 가져야 한다.
		String regSN = formatSerialNum(getSerialNum("001", deptCode, taskCode, companyID, strLang, tenantID));
		String produceY = getAccountingYear(createDate, companyID, strLang,tenantID);
		String cabinetClassNO = deptCode + taskCode + produceY + regSN;
		String specialFlag = xmlDom.getElementsByTagName("SPECIALFLAG").item(0).getTextContent();
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_CabinetClassNo", cabinetClassNO);
		map.put("v_ProductionYear", produceY);
		map.put("v_RegSerialNo", regSN);
		map.put("v_TerminateFlag", "0");
		map.put("v_Title", xmlDom.getElementsByTagName("TITLE").item(0).getTextContent());
		map.put("v_Title2", xmlDom.getElementsByTagName("TITLE2").item(0).getTextContent());
		map.put("v_RecTypeCode", xmlDom.getElementsByTagName("RECTYPE").item(0).getTextContent());
		map.put("v_ExpirationYear", produceY);
		map.put("v_KeepingMethod", xmlDom.getElementsByTagName("KEEPMETHOD").item(0).getTextContent());
		map.put("v_KeepingPlace", xmlDom.getElementsByTagName("KEEPPLACE").item(0).getTextContent());
		map.put("v_DisplayEndDate", xmlDom.getElementsByTagName("DISPLAYENDDATE").item(0).getTextContent());
		map.put("v_DisplayReason", xmlDom.getElementsByTagName("DISPLAYREASON").item(0).getTextContent());
		map.put("v_OwnerName", xmlDom.getElementsByTagName("OWNERNAME").item(0).getTextContent());
		map.put("v_OwnerName2", xmlDom.getElementsByTagName("OWNERNAME2").item(0).getTextContent());
		map.put("v_OwnerID", xmlDom.getElementsByTagName("OWNERID").item(0).getTextContent());
		map.put("v_OldCabinetFlag", "1");
		map.put("v_SpecialCatalogFlag", specialFlag);
		map.put("v_ConfirmFlag", "0");
		map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
		map.put("v_KeepingPeriod", xmlDom.getElementsByTagName("KEEPPERIOD").item(0).getTextContent());
		map.put("v_DisplayRecFlag", xmlDom.getElementsByTagName("DISPLAYFLAG").item(0).getTextContent());
		map.put("v_ProcessDeptCode", deptCode);
		map.put("v_ProcessDeptName", xmlDom.getElementsByTagName("DEPTNAME").item(0).getTextContent());
		map.put("v_ProcessDeptName2", xmlDom.getElementsByTagName("DEPTNAME2").item(0).getTextContent());
		map.put("v_TaskCode", taskCode);
		map.put("v_TaskName", xmlDom.getElementsByTagName("TASKNAME").item(0).getTextContent());
		map.put("v_TaskName2", xmlDom.getElementsByTagName("TASKNAME2").item(0).getTextContent());
		map.put("v_TransDelayFlag", "0");
		map.put("v_OwnerDeptID", deptCode);
		map.put("v_OwnerTask", taskCode);
		map.put("v_DelayEndYFlag", "N");
		map.put("v_DelFlag", "0");
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		ezApprovalGDAO.insertRegCabinetCalss(map);
		
		Map<String, Object> map1 = new HashMap<String, Object>();
		map1.put("v_CABINETCLASSNO",  cabinetClassNO);
		map1.put("v_DeptMID",  xmlDom.getElementsByTagName("OWNERID").item(0).getTextContent());
		map1.put("v_DeptMName",  xmlDom.getElementsByTagName("OWNERNAME").item(0).getTextContent());
		map1.put("v_DeptMName2",  xmlDom.getElementsByTagName("OWNERNAME2").item(0).getTextContent());
		map1.put("v_TENANTID",  tenantID);
		map1.put("v_SYSDATE",commonUtil.getTodayUTCTime(""));
		map1.put("companyID", companyID);
		
		ezApprovalGDAO.trigerTbCabinet(map1);
		ezApprovalGDAO.trigerTbCabRoleInfo(map1);
		
		if (!specialFlag.equals("0")) {
			subSQL = saveSpecialInfoCab(specialFlag, cabinetClassNO, xmlDom, tenantID, companyID);
			
			if (subSQL.equals("FALSE")) {
				rollbackSN("001", deptCode, taskCode, regSN, companyID, strLang, tenantID);
				logger.debug("registerCabinet ended");
				return "<RESULT>FALSE</RESULT>";
			} 
		}

		logger.debug("registerCabinet ended");
		return "<RESULT><![CDATA[" + cabinetClassNO + "001" + "]]></RESULT>";
	}

	@Override
	public String getNewVolumeNo(String cabClassNO, String companyID, int tenantID) throws Exception {
		logger.debug("getNewVolumeNo Started");
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_CABCLASSNO", cabClassNO.trim());
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		logger.debug("getNewVolumeNo Param : v_CABCLASSNO = " + cabClassNO.trim() + " companyID =" + companyID + " v_TENANTID =" + tenantID );
		String result = ezApprovalGDAO.getNewVolumeNo(map);
		
		logger.debug("getNewVolumeNo Ended");
		if (result.length() > 0) {
			return "<RESULT>" + result + "</RESULT>";
		} else {
			return "<RESULT>FALSE</RESULT>";
		}
	}

	@Override
	public String addNewVolume(String cabClassNO, String newVolNO, String companyID, int tenantID) throws Exception {
		logger.debug("addNewVolume Started");
		String createDate = commonUtil.getTodayUTCTime("");
		String cabID = cabClassNO + formatVolNum(newVolNO);
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_CABINETID", cabID);
		map.put("v_VOLUMENO", formatVolNum(newVolNO));
		map.put("v_CABCLASSNO", cabClassNO);
		map.put("v_CREATEDATE", createDate);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_SYSDATE",commonUtil.getTodayUTCTime(""));

		logger.debug("addNewVolume Param : v_CABINETID = " + cabID + " v_VOLUMENO = " + formatVolNum(newVolNO) + " v_CABCLASSNO = " + cabClassNO + " v_CREATEDATE =" + createDate + " companyID = " + companyID + " v_TENANTID = " + tenantID);
		ezApprovalGDAO.addNewVolume(map);
		logger.debug("addNewVolume Ended");

		return "TRUE";
	}

	@Override
	public String getFindSimpleCabinetList(String processDeptCode, String productionYear, String searchKeyword, String flag, String companyID, String langType, int tenantID) throws Exception {
		logger.debug("getFindSimpleCabinetList started");

		String strMultiData = commonUtil.getMultiData(langType, tenantID);
		
		/* 2025-04-01 홍승비 - 전자결재G > 기산일(회계년도) 시간대 기준 값을 테넌트 컨피그로 옵션화, 디폴트로 UTC 정시가 아닌 한국시(UTC + 9)를 기준으로 사용하도록 수정 */
		String todayUTCTime = commonUtil.getTodayUTCTime("");
		String accountYearTimeZone = ezCommonService.getTenantConfig("accountYearTimeZone", tenantID);
		
		if ("KST".equals(accountYearTimeZone)) {
			todayUTCTime = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), "235|+09:00", false);
		}
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_PDEPTCODE", processDeptCode);
		map.put("v_PYEAR", getAccountingYear(todayUTCTime, companyID, langType, tenantID));
		map.put("v_SEARCHNAME", searchKeyword);
		map.put("v_FLAG", flag);
		map.put("v_LANGTYPE", strMultiData);
		map.put("v_TENANTID", tenantID);
		
		List<ApprGCabinetVO> apprGCabinetVOList = ezApprovalGDAO.getFindSimpleCabinetList(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGCabinetVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGCabinetVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		
		StringBuffer resultXML = new StringBuffer();
		String listString = "";
		
		listString = getListHeader("096", companyID, langType, tenantID);
		
		Document listXML = commonUtil.convertStringToDocument(listString);
		
		int hlength = listXML.getElementsByTagName("NAME").getLength();
		
		resultXML.append("<LISTVIEWDATA>");
		resultXML.append("<HEADERS>");
		
		for (int k = 0; k < hlength; k++) {
			resultXML.append("<HEADER>");
			resultXML.append("<NAME>" + listXML.getElementsByTagName("NAME").item(k).getTextContent() + "</NAME>");
			resultXML.append("<WIDTH>" + listXML.getElementsByTagName("WIDTH").item(k).getTextContent() + "</WIDTH>");
			resultXML.append("</HEADER>");
		}
		resultXML.append("</HEADERS>");
		
		int dlength = docXML.getElementsByTagName("ROW").getLength();
		
		resultXML.append("<ROWS>");
		
		for (int k = 0; k < dlength; k++) {
			resultXML.append("<ROW>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE><![CDATA[" + makeListField(docXML.getElementsByTagName("CNAME").item(k).getTextContent()) + "]]></VALUE>");
			resultXML.append("<DATA1><![CDATA[" + makeListField(docXML.getElementsByTagName("CABINETID").item(k).getTextContent()) + "]]></DATA1>");
			resultXML.append("<DATA2><![CDATA[" + makeListField(docXML.getElementsByTagName("TASKCODE").item(k).getTextContent()) + "]]></DATA2>");
			resultXML.append("<DATA3><![CDATA[" + makeListField(docXML.getElementsByTagName("CABINETCLASSNO").item(k).getTextContent()) + "]]></DATA3>");
			resultXML.append("<DATA4><![CDATA[" + makeListField(docXML.getElementsByTagName("OWNERID").item(k).getTextContent()) + "]]></DATA4>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + makeListField(docXML.getElementsByTagName("MCNAME").item(k).getTextContent()) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + makeListField(docXML.getElementsByTagName("SCNAME").item(k).getTextContent()) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE><![CDATA[" + makeListField(docXML.getElementsByTagName("TASKNAME").item(k).getTextContent()) + "]]></VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + commonUtil.cleanValue(makeListField(docXML.getElementsByTagName("TITLE").item(k).getTextContent())) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + getRecordTypeString(makeListField(docXML.getElementsByTagName("RECTYPECODE").item(k).getTextContent()), companyID, langType, tenantID) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + makeListField(docXML.getElementsByTagName("REGSERIALNO").item(k).getTextContent()) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("<CELL>");
			resultXML.append("<VALUE>" + makeListField(docXML.getElementsByTagName("VOLUMENO").item(k).getTextContent()) + "</VALUE>");
			resultXML.append("</CELL>");
			resultXML.append("</ROW>");
		}
		
		resultXML.append("</ROWS>");
		resultXML.append("</LISTVIEWDATA>");
		
		logger.debug("getFindSimpleCabinetList ended");
		
		return resultXML.toString();
	}

