	private String getAVTypeString(String pCode, String companyID, String LangType, int tenantID) throws Exception {
		logger.debug("getAVTypeString started");

		String [] pCodes = pCode.split(",");
		String rtnVal="";
		for(int i = 0; i < pCodes.length; i++){
			if(pCodes[i].trim().length() >= 1){
				if(!rtnVal.trim().equals("")){
					rtnVal += ",";
				}
				if(pCodes[i].substring(0,1).toUpperCase().equals("C")){
					rtnVal += getCabinetCode2Name("009", pCodes[i].toString(), companyID, LangType, tenantID);
				}
				else{
					rtnVal += getCabinetCode2Name("008", pCodes[i].toString(), companyID, LangType, tenantID);
				}
			}
		}

		logger.debug("getAVTypeString ended");
		return rtnVal;
	}
	
	private String rollbackSN(String snType1, String snType2, String snType3, String toSN, String companyID, String strLang, int tenantID) throws Exception {
		logger.debug("rollbackSN started");
		
		/* 2025-04-01 홍승비 - 전자결재G > 기산일(회계년도) 시간대 기준 값을 테넌트 컨피그로 옵션화, 디폴트로 UTC 정시가 아닌 한국시(UTC + 9)를 기준으로 사용하도록 수정 */
		String todayUTCTime = commonUtil.getTodayUTCTime("");
		String accountYearTimeZone = ezCommonService.getTenantConfig("accountYearTimeZone", tenantID);
		
		if ("KST".equals(accountYearTimeZone)) {
			todayUTCTime = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), "235|+09:00", false);
		}

		String accountYear = getAccountingYear(todayUTCTime, companyID, strLang, tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("iv_Type1", snType1);
		map.put("iv_Type2", snType2);
		map.put("iv_Type3", snType3);
		map.put("v_CurSN", toSN);
		map.put("v_AccountYear", accountYear);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_SYSDATE",commonUtil.getTodayUTCTime(""));
		
		/* 2022-09-21 홍승비 - 정상적인 문서번호 채번 뒤의 중복삽입 오류가 발생한 경우, 기존 문서번호를 롤백하지 않도록 카운트 체크 */
		int noRollbackCnt = ezApprovalGDAO.getNoRollbackRecordCnt(map);
		if (noRollbackCnt <= 0) { // 롤백하지 않아야 하는 레코드가 없을때만 롤백
			ezApprovalGDAO.spRollbackSN(map);
		}
		
		logger.debug("rollbackSN ended, noRollbackCnt = " + noRollbackCnt);

		return "TRUE";
	}

	private String saveSpecialInfoCab(String specialFlag, String cabinetClassNO, Document xmlDom, int tenantID, String companyID) throws Exception{
		logger.debug("saveSpecialInfoCab started.");

		String rtn = null;
		
		String sc1 = xmlDom.getElementsByTagName("LIST1").item(0).getTextContent().trim();
		String sc2 = xmlDom.getElementsByTagName("LIST2").item(0).getTextContent().trim();
		String sc3 = xmlDom.getElementsByTagName("LIST3").item(0).getTextContent().trim();
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_CABINETCLASSNO", cabinetClassNO);
		map.put("v_SC1", sc1);
		map.put("v_SC2", sc2);
		map.put("v_SC3", sc3);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
	 	logger.debug("insertTbSpecialCatalogInfo_Cab param = v_CABINETCLASSNO =" + cabinetClassNO + "v_SC1=" +sc1+ "v_SC2=" +sc2+ "v_SC3=" +sc3+"v_TENANTID ="+tenantID);

		ezApprovalGDAO.insertTbSpecialCatalogInfo_Cab(map);
		
		NodeList nodeList=xmlDom.getElementsByTagName("SCDATA");
 		if (specialFlag.equals("1")) {
			for (int k = 0; k < xmlDom.getElementsByTagName("SCDATA").getLength(); k++) {
				
				map.put("v_CABINETCLASSNO", cabinetClassNO);
				map.put("v_SERIALNO", nodeList.item(k).getChildNodes().item(0).getTextContent().trim());
				map.put("v_SC1", nodeList.item(k).getChildNodes().item(1).getTextContent().trim());
				map.put("v_SC2", nodeList.item(k).getChildNodes().item(2).getTextContent().trim());
				map.put("v_SC3", nodeList.item(k).getChildNodes().item(3).getTextContent().trim());
				map.put("v_TENANTID", tenantID);
			 	logger.debug("insertTbSpecialCatalogInfo_Cab2 param = v_CABINETCLASSNO =" + cabinetClassNO + "v_SERIALNO=" + nodeList.item(k).getChildNodes().item(0).getTextContent().trim()+ "v_SC1=" + nodeList.item(k).getChildNodes().item(1).getTextContent().trim() + "v_SC2=" + nodeList.item(k).getChildNodes().item(2).getTextContent().trim() + "v_SC3=" + nodeList.item(k).getChildNodes().item(3).getTextContent().trim() +"v_TENANTID ="+tenantID);

				ezApprovalGDAO.insertTbSpecialCatalogInfo_Cab2(map);
			}
		}
 		rtn = "TURE";
 		logger.debug("saveSpecialInfoCab ended.");
		return rtn;
	}

