	public String updateGamsaResult(String docID, String companyID, String orgDocID, String orgCompanyID, String aprLinersDeptID, String aprLinersDeptName, String aprLinersDeptName2, String mode, String lang, LoginVO userInfo, String curDocNum) throws Exception {
		logger.debug("updateGamsaResult started");

		String subSQL = "";
		boolean isHesong = false;
		
		subSQL = setLastOpinionToOrgDoc(docID, orgDocID, companyID, orgCompanyID, "QUERY", lang, userInfo.getTenantId());
		
		if (subSQL.toUpperCase().equals("FALSE")) {
			return "FALSE";
		} 
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_LANGTYPE", lang);
		map.put("lang", commonUtil.getMultiData(lang, userInfo.getTenantId()));
		map.put("v_TENANTID", userInfo.getTenantId());
		
		String signType = "TEXT";
		String signTitle = "";
		String signCont = "";
		
		if (mode.toUpperCase().equals("H")) {
			signCont = messageSource.getMessage("ezApprovalG.t1434", userInfo.getLocale());
		} else {
			// 해당 문서의 마지막 서명 정보 가져오기
			List<ApprGSignInfoVO> apprGSignInfoVOList = ezApprovalGDAO.updateHabyuiResultSignInfo(map);
			
			if (apprGSignInfoVOList.size() > 0) {
				signType = makeListField(apprGSignInfoVOList.get(0).getSignType());
				signCont = makeListField(apprGSignInfoVOList.get(0).getContent());
			} else {
				signCont = makeListField(ezApprovalGDAO.updateHabyuiResultAprMemberNM(map));
			}
		}
		
		signTitle = makeListField(ezApprovalGDAO.updateHabyuiResultAprMemberJobTitle(map));
		
		if (signTitle.trim().equals("")) {
			signTitle = "-";
		}
		
		map.put("v_DOCID", orgDocID);
		// APRTYPE이 '합의(개인순차, 개인병렬, 부서순차, 부서병렬)' 리스트 출력
		List<ApprGAprLineVO> apprGAprLineVOList = ezApprovalGDAO.updateHabyuiResultAprMember(map);
		
		
		for (int k = 0; k < apprGAprLineVOList.size(); k++) {
			// 수신처ID == detpID(결재부서ID) && 결재 대상이 부서(Y) && AprState == 진행
			if (apprGAprLineVOList.get(k).getAprMemberDeptID().toLowerCase().equals(aprLinersDeptID.toLowerCase()) && apprGAprLineVOList.get(k).getAprMemberIsDeptYN().toUpperCase().equals("Y") && apprGAprLineVOList.get(k).getAprState().equals("002")) {
				break;
			}
			
			if (apprGAprLineVOList.get(k).getAprMemberDeptID().toLowerCase().equals(aprLinersDeptID.toLowerCase()) && apprGAprLineVOList.get(k).getAprMemberIsDeptYN().toUpperCase().equals("Y") && apprGAprLineVOList.get(k).getAprState().equals("015")) {
				isHesong = true;
				break;
			}
		}
		
		Boolean isGamsaDoc = false;
		
		//원본문서 합의란에 서명기입
		Map<String, Object> map3 = new HashMap<String, Object>();
		map3.put("companyID", orgCompanyID);
		map3.put("v_DOCID", orgDocID);
		map3.put("v_TENANTID", userInfo.getTenantId());
		map3.put("v_FLAG", "APR");
		
		String docHref = ezApprovalGDAO.getDocInfoHref(map3);
		String formURL = userInfo.getRealPath() + docHref;
		String ext = getExtendedFileName(formURL);
		
		if ("mht".equals(ext)) {
			String loadMht = ezCommonService.loadMHTFile(formURL); // 결재문서 가져오기
			// HTML -> MHT
			String content = ezCommonService.startMHT2HTML(userInfo.getRealPath() + commonUtil.getUploadPath("config.LocalPath", userInfo.getTenantId()), loadMht, userInfo.getRealPath() + commonUtil.getUploadPath("config.LocalPath", userInfo.getTenantId()), userInfo.getRealPath(), userInfo.getLocale(), "", "");
			//HTML 파싱 document 클래스 겹쳐서 임포트 못함
			org.jsoup.nodes.Document doc = Jsoup.parse(content);
			
			if (doc.getElementById("deptgamsaname") != null) {
				isGamsaDoc = true;
			}
			
			if (signType.equals("IMAGE")) {
				String signImageType = ezCommonService.getTenantConfig("signImageType", userInfo.getTenantId());
				
				String[] tempSignCont = signCont.split("::");
				
				/* 2023-11-01 홍승비 - 이미지 서명 확인 시, ::문자 split한 이후의 데이터가 존재하는지 체크하도록 수정 */
				if (tempSignCont.length > 1 && tempSignCont[1] != null && tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t26", userInfo.getLocale())) > -1) {
					if (signImageType.equals("NAME")) {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
					} else {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'>";
					}
				} else {
					if (signImageType.equals("NAME")) {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
					} else {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'>";
					}
				}
			}
			
			if (isGamsaDoc) {
				if (doc.getElementById("deptgamsasign") != null) {
					doc.getElementById("deptgamsasign").html(signCont);
				}
			}
			
			String tempHtml = doc.outerHtml();
			String convertedMHT = ezCommonService.startHtml2Mht(tempHtml, userInfo.getRealPath(), userInfo.getLocale());
			String tempMht = new EzFile(formURL).getFile().getParentFile() + commonUtil.separator + orgDocID + "_backup.mht"; // getParentFile() 부분 정상 동작 여부 확인, getfile 한번 써주기
			
			EzFAL.copyFile(new EzFile(formURL), new EzFile(tempMht));
			
			// EzFAL EzFileOutputStream 사용 (자동 close 호출)
			try (EzFileOutputStream fos = new EzFileOutputStream(formURL)) {
				fos.write(convertedMHT.getBytes()); // MHT 문자열을 바이트 배열로 가져와 파일 저장
				fos.flush();
			} catch (FileNotFoundException fnfe) {
				logger.debug("fnfe: {}", fnfe);
			} catch (IOException ioe) {
				logger.debug("ioe: {}", ioe);
			} catch (Exception e) {
				logger.debug("e: {}", e);
			}
		} else if ("hwp".equals(ext)) { //부서합의 한글 기안기 처리하기 위해 수정. 접수 후 결재완료 됐을 경우 파싱 에러 때문에 수정. 2019-09-24 홍대표
			
            if (EzFAL.isObjectStorageMode()) { // 원격저장소 사용여부를 확인
				byte[] orgBytes = null;
				
				// 원본 파일을 스트림에서 바이트로 read
				// EzFAL EzFileInputStream 사용 (자동 close 호출)
				try (EzFileInputStream fis = new EzFileInputStream(formURL)) {
					orgBytes = IOUtils.toByteArray(fis);
				} catch (Exception e) {
					logger.error(e.getMessage(), e);
				}
				// 읽어온 원본 파일(EzFile)을 로컬 파일(File)로 임시 저장
				// EzFAL EzFileOutputStream 사용 (자동 close 호출)
				try (FileOutputStream fos = new FileOutputStream(formURL)) {
					fos.write(orgBytes);
					fos.flush();
				} catch (Exception e) {
					logger.error(e.getMessage(), e);
				}
			}
            
            List<ApprGGroupDocInfoVO> group = getGroupDocList(docID, "APR", userInfo.getTenantId(), companyID);
            boolean draftAllTypeB = "Y".equals(ezCommonService.getTenantConfig("draftAllTypeB", userInfo.getTenantId())) && group.size() > 1;
            boolean hwpFilter = "Y".equals(ezCommonService.getTenantConfig("hwpFilter", userInfo.getTenantId()));
            String hwpPath = ezCommonService.getTenantConfig("hwpPath", userInfo.getTenantId());
            List<Object> loadHwp = new ArrayList<>();
            loadHwp.add(HWPReader.fromFile(new File(formURL)));
            if(hwpFilter)
                loadHwp.add(new RestWHWP(ezCommonService.getTenantConfig("hwpFilterServer", userInfo.getTenantId())).open(hwpPath + docHref));
			
			if (findHwpField("deptgamsaname", loadHwp)) {
				isGamsaDoc = true;
			}
			
			// 사인이 이미지인 경우 작업 필요
//			if (signType.equals("IMAGE")) {
//				String signImageType = ezCommonService.getTenantConfig("signImageType", userInfo.getTenantId());
//				
//				String[] tempSignCont = signCont.split("::");
//				
//				if (tempSignCont[1] != null && tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t26", userInfo.getLocale())) > -1) {
//					if (signImageType.equals("NAME")) {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
//					} else {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'>";
//					}
//				} else {
//					if (signImageType.equals("NAME")) {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
//					} else {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'>";
//					}
//				}
//			}
			
			if (isGamsaDoc) {
				if (findHwpField("deptgamsasign", loadHwp)) {
					setHwpText(draftAllTypeB, loadHwp, "deptgamsasign", signCont);
				}
			}
            
            if (!hwpFilter) {
			    HWPWriter.toFile((HWPFile) loadHwp.get(0), formURL); // 변경한 loadHwp 파일을 formURL 파일에 덮어쓰기 (로컬 파일 시스템 상에서의 동작)
            } else {
                whwpSave(((RestWHWP) loadHwp.get(1)), hwpPath + docHref, formURL.substring(0, formURL.lastIndexOf("/")));
            }
            
			// 위의 변경된 loadHwp파일 (로컬 파일 시스템 상에서의 formURL 경로 파일)을 아래 코드로 오브젝트 스토리지에 쓰기 처리
			// EzFileOutputStream을 선언하는 순간 로컬 파일 경로에 새로운 File 객체가 생성되므로, 미리 저장해둔 byte 배열을 전달
	        byte[] hwpFileBytes = FileUtils.readFileToByteArray(new File(formURL));
	        
			// EzFAL EzFileOutputStream 사용 (자동 close 호출)
			try (EzFileOutputStream fosHwp = new EzFileOutputStream(formURL)) { // 오브젝트 스토리지로 연결되는 파일아웃스트림
				fosHwp.write(hwpFileBytes); // 로컬 파일 시스템에서 가져온 파일
				fosHwp.flush(); // 로컬 파일 시스템 -> 오브젝트 스토리지로 업로드
			} catch (Exception e) {
				logger.error(e.getMessage(), e);
			}
		}
		
		StringBuilder resultXML = new StringBuilder();
		
		resultXML.append("<SIGNINFOS>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + "TEXT" + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + "examposition" + "</SIGNNAME>");
		resultXML.append("<CONTENT><![CDATA[" + signTitle + "]]></CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + signType + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + "examnaja" + "</SIGNNAME>");
		resultXML.append("<CONTENT><![CDATA[" + signCont + "]]></CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + "TEXT" + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + "examdate" + "</SIGNNAME>");
		resultXML.append("<CONTENT><![CDATA[" + signCont + "]]></CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("</SIGNINFOS>");
		
		subSQL = updateSignInfo(resultXML, orgCompanyID, "QUERY", userInfo.getTenantId());
		
		if (subSQL.toUpperCase().equals("FALSE")) {
			return "FALSE";
		} 

		logger.debug("updateGamsaResult ended");
		
		return subSQL;
	}

	/**
	 * 합의를 위한 서명정보 생성 및 DB에 입력을 하였으나 이제는 바로 원본문서에 서명정보를 기입하기로 함
	 * */
	public String updateHabyuiResult(String docID, String companyID, String orgDocID, String orgCompanyID, String deptID, String deptName, String deptName2, String mode, String lang, LoginVO userInfo, String curDocNum) throws Exception {
		logger.debug("updateHabyuiResult started");

		StringBuilder strSQL = new StringBuilder();
		boolean isHesong = false;
		String subSQL = "";
		//String docNumZeroCnt = ezCommonService.getTenantConfig("docNumZeroCnt", userInfo.getTenantId());
		String docNumZeroCnt = getDocNumZeroCnt(companyID, userInfo.getTenantId());
		
		subSQL = setLastOpinionToOrgDoc(docID, orgDocID, companyID, orgCompanyID, "QUERY", lang, userInfo.getTenantId());
		
		if (subSQL.indexOf("FALSE") > -1) {
			return "FALSE";
		}
		
		String signType = "TEXT";
		String signTitle = "";
		String signCont = "";
		String signName = "";
		String cabinetSN = "";
		
		/* 2023-10-04 홍승비 - 양식상에 저장되는 서명일자는 UTC 시간이 아닌 결재자의 타임존 시간으로 저장 (웹과 동일 스펙, MM.dd 형식) */
		// 2025-02-19 조수빈 - ParseException으로 utc 기준 일자가 저장되는 결함 수정
		String utcTime = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), userInfo.getOffset(), false);
		String signDateMD = utcTime.substring(5, 7) + "." + utcTime.substring(8, 10);
        
        /* 2023-11-07 홍승비 - 합의결재 완료 시 이미지 서명을 원문서에 맵핑하는 경우, DB의 tbl_signinfo 테이블에는 이미지 서명 파일의 경로(+ 대결,전결 + 컨피그에 따라 결재자명까지)를 저장 */
        String imgSignCont = ""; // MHT에서 사용, 이미지 서명과 기타 데이터를 HTML로 맵핑하기 위해 사용
        
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("lang", commonUtil.getMultiData(lang, userInfo.getTenantId()));
		map.put("v_TENANTID", userInfo.getTenantId());
		
		if (mode.toUpperCase().equals("H")) {
			signCont = messageSource.getMessage("ezApprovalG.t1434", userInfo.getLocale());
		} else {
			// 해당 합의문서의 마지막 서명 정보 가져오기
			List<ApprGSignInfoVO> apprGSignInfoVOList = ezApprovalGDAO.updateHabyuiResultSignInfo(map);
			
			if (apprGSignInfoVOList.size() > 0) {
				signType = makeListField(apprGSignInfoVOList.get(0).getSignType());
				signCont = makeListField(apprGSignInfoVOList.get(0).getContent());
			} else {
				signCont = makeListField(ezApprovalGDAO.updateHabyuiResultAprMemberNM(map));
			}
		}
		
		//서명한 사람의 직위뿐만 아니라 다른 정보들도 필요해서 조회방식 변경
		//signTitle = makeListField(ezApprovalGDAO.updateHabyuiResultAprMemberJobTitle(map));
		
		ApprGAprLineVO aprLineVO = ezApprovalGDAO.selectHabyuiResultAprMemberInfoVO(map);
		if (aprLineVO != null) {
			if (lang.equals("2")) {
				signTitle = aprLineVO.getAprMemberJobTitle2();
				signName = aprLineVO.getAprMemberName2();
			} else {
				signTitle = aprLineVO.getAprMemberJobTitle();
				signName = aprLineVO.getAprMemberName();
			}
		}
		
		/* 2023-05-12 홍승비 - 합의 서명을 위한 직위나 이름이 없는 경우, null 처리 추가 */
		if (signTitle == null || signTitle.trim().equals("")) {
			signTitle = "-";
		}
		if (signName == null || signName.trim().equals("")) {
			signName = "-";
		}
		
		String susinSN = getSusinSNInside(orgDocID, orgCompanyID, userInfo.getTenantId());
		
		map.put("v_DOCID", orgDocID);
		// APRTYPE이 '합의(개인순차, 개인병렬, 부서순차, 부서병렬)' 리스트 출력
		List<ApprGAprLineVO> apprGAprLineVOList = ezApprovalGDAO.updateHabyuiResultAprMember(map);
		
		int aprSN = 0;
		
		for (int k = 0; k < apprGAprLineVOList.size(); k++) {
			// 수신처ID == detpID(결재부서ID) && 결재 대상이 부서(Y) && AprState == 진행
			if (apprGAprLineVOList.get(k).getAprMemberDeptID().toLowerCase().equals(deptID.toLowerCase()) && apprGAprLineVOList.get(k).getAprMemberIsDeptYN().toUpperCase().equals("Y") && apprGAprLineVOList.get(k).getAprState().equals("002")) {
				aprSN = k + 1;
				break;
			} else if (apprGAprLineVOList.get(k).getAprMemberIsDeptYN().toUpperCase().equals("Y") && apprGAprLineVOList.get(k).getAprState().equals("002")) {
                /* 2024-06-20 김유진 - 문서과로 저장한 부서의 문서를 처리하는지 체크 */
                String aprMemberDeptID = apprGAprLineVOList.get(k).getAprMemberDeptID();
                String[] manageDeptArray = getDocManageDeptInfo(deptID, userInfo.getTenantId()).replace("'", "").split(",\\s*");
                if (Arrays.asList(manageDeptArray).stream()
                        .anyMatch(deptId -> deptId.equalsIgnoreCase(aprMemberDeptID))) {
                    aprSN = k + 1;
                    break;
                }
            }
			
			if (apprGAprLineVOList.get(k).getAprMemberDeptID().toLowerCase().equals(deptID.toLowerCase()) && apprGAprLineVOList.get(k).getAprMemberIsDeptYN().toUpperCase().equals("Y") && apprGAprLineVOList.get(k).getAprState().equals("015")) {
				aprSN = k + 1;
				isHesong = true;
				break;
			}
		}
		
		//원본문서 합의란에 서명기입
		Map<String, Object> map3 = new HashMap<String, Object>();
		map3.put("companyID", orgCompanyID);
		map3.put("v_DOCID", orgDocID);
		map3.put("v_TENANTID", userInfo.getTenantId());
		map3.put("v_FLAG", "APR");
		
		String docHref = ezApprovalGDAO.getDocInfoHref(map3);
		String formURL = userInfo.getRealPath() + docHref;
		String ext = getExtendedFileName(formURL);
		
		if ("mht".equals(ext)) {
			String loadMht = ezCommonService.loadMHTFile(formURL); // 결재문서 가져오기
			// HTML -> MHT
			String content = ezCommonService.startMHT2HTML(userInfo.getRealPath() + commonUtil.getUploadPath("config.LocalPath", userInfo.getTenantId()), loadMht, userInfo.getRealPath() + commonUtil.getUploadPath("config.LocalPath", userInfo.getTenantId()), userInfo.getRealPath(), userInfo.getLocale(), "", "");
			//HTML 파싱 document 클래스 겹쳐서 임포트 못함
			org.jsoup.nodes.Document doc = Jsoup.parse(content);
			
			if (isHesong) {
				if (doc.getElementById(susinSN + "habyuipositon" + aprSN) != null) {
					doc.getElementById(susinSN + "habyuipositon" + aprSN).html(userInfo.getTitle());
				}
			} else {
				if (doc.getElementById(susinSN + "habyuipositon" + aprSN) != null) {
					doc.getElementById(susinSN + "habyuipositon" + aprSN).html(signTitle);
				}
			}
			
			if (signType.equals("IMAGE")) {
				String signImageType = ezCommonService.getTenantConfig("signImageType", userInfo.getTenantId());
				String[] tempSignCont = signCont.split("::");
				imgSignCont = tempSignCont[0];
				
				/* 2023-11-01 홍승비 - 합의문의 이미지 서명 확인 시, ::문자 split한 이후의 데이터가 존재하는지 체크하도록 수정 (대리결재(代), 대결, 전결 문자) */
				if (tempSignCont.length > 1 && tempSignCont[1] != null && 
						(tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t26", userInfo.getLocale())) > -1 || tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t25", userInfo.getLocale())) > -1
						|| tempSignCont[1].indexOf(messageSource.getMessage("ezApproval.t498", userInfo.getLocale())) > -1)) {
					
					/* 2023-11-15 홍승비 - 합의자의 대리결재(代) 문자, '대결/전결' 문자를 이미지 서명 위에 함께 표출하도록 수정 (문자서명과 동일 스펙) */
					signCont = tempSignCont[1];
					imgSignCont += "::" + tempSignCont[1];
					
					if (signImageType.equals("NAME")) {
						signCont += "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
						imgSignCont += "::" + userInfo.getDisplayName();
					} else {
						signCont += "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'>";
					}
				} else {
					if (signImageType.equals("NAME")) {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
						imgSignCont += "::::" + userInfo.getDisplayName();
					} else {
						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'>";
					}
				}
			}
			
			//부서 합의 일 경우 원문서 문서번호 채번
			if (!isHesong) {
				int lastHabyuiCnt = lastKyulJeHabYuiYN(orgDocID, "approvUi", userInfo.getCompanyID(), userInfo.getTenantId());
				String orgDeptID = getOrgDraftDeptID(orgDocID, userInfo.getTenantId(), userInfo.getCompanyID());
				
				if (lastHabyuiCnt > 0) {
					map.put("v_habDocID", docID);
					List<ApprGDocListVO> docState = ezApprovalGDAO.getLastHabYuiDocState(map);
					
					if (docState.size() > 0) {
						if (docState.get(0).getDocState().equals("012")) {
							Document xmlDom = commonUtil.convertStringToDocument(getCabinetNum(orgDeptID, "", companyID, userInfo.getTenantId(), userInfo.getOffset()));
							cabinetSN = xmlDom.getElementsByTagName("RESULT").item(0).getTextContent();
							
							map.put("v_DOCNO", doc.getElementById("docnumber").html() + createDocNO(cabinetSN, docNumZeroCnt));
							map.put("v_MODE", "APR");
							ezApprovalGDAO.updateDocNumber(map);
							map.put("v_MODE", "END");
							map.put("v_DOCID", orgDocID);
							ezApprovalGDAO.updateDocNumber(map);
						}
						doc.getElementById("docnumber").html(doc.getElementById("docnumber").html() + createDocNO(cabinetSN, docNumZeroCnt));					
					}
				}   
			}
			
			if (doc.getElementById(susinSN + "habyuisign" + aprSN) != null) {
				doc.getElementById(susinSN + "habyuisign" + aprSN).html(signCont);
			}
			
			if (doc.getElementById(susinSN + "habyuidate" + aprSN) != null) {
				doc.getElementById(susinSN + "habyuidate" + aprSN).html(commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), userInfo.getOffset(), false).substring(5, 10).replace("-", "."));
			}
		
			if (doc.getElementById(susinSN + "habyuija" + aprSN) != null) {
				doc.getElementById(susinSN + "habyuija" + aprSN).html(signName);
			}
		
			String tempHtml = doc.outerHtml();
			String convertedMHT = ezCommonService.startHtml2Mht(tempHtml, userInfo.getRealPath(), userInfo.getLocale());
			String tempMht = new EzFile(commonUtil.detectPathTraversal(formURL)).getFile().getParentFile() + commonUtil.separator + orgDocID + "_backup.mht";
			EzFAL.copyFile(new EzFile(commonUtil.detectPathTraversal(formURL)), new EzFile(commonUtil.detectPathTraversal(tempMht)));
			
			// EzFAL EzFileOutputStream 사용 (자동 close 호출)
			try (EzFileOutputStream fos = new EzFileOutputStream(formURL)) {
				fos.write(convertedMHT.getBytes()); // MHT 문자열을 바이트 배열로 가져와 파일 저장
				fos.flush();
			}  catch (FileNotFoundException fnfe) {
				logger.debug("fnfe: {}", fnfe);
			} catch (IOException ioe) {
				logger.debug("ioe: {}", ioe);
			} catch (Exception e) {
				logger.debug("e: {}", e);
			}
		} else if("hwp".equals(ext)) { //부서합의 한글 기안기 처리하기 위해 수정. 접수 후 결재완료 됐을 경우 파싱 에러 때문에 수정. 2019-09-24 홍대표
            if (EzFAL.isObjectStorageMode()) { // 원격저장소 사용여부를 확인
                byte[] orgBytes = null;

                // 원본 파일을 스트림에서 바이트로 read
                // EzFAL EzFileInputStream 사용 (자동 close 호출)
                try (EzFileInputStream fis = new EzFileInputStream(formURL)) {
                    orgBytes = IOUtils.toByteArray(fis);
                } catch (Exception e) {
                    logger.error(e.getMessage(), e);
                }
                // 읽어온 원본 파일(EzFile)을 로컬 파일(File)로 임시 저장
                // EzFAL EzFileOutputStream 사용 (자동 close 호출)
                try (FileOutputStream fos = new FileOutputStream(formURL)) {
                    fos.write(orgBytes);
                    fos.flush();
                } catch (Exception e) {
                    logger.error(e.getMessage(), e);
                }
            }

            boolean hwpFilter = "Y".equals(ezCommonService.getTenantConfig("hwpFilter", userInfo.getTenantId()));
            String hwpPath = ezCommonService.getTenantConfig("hwpPath", userInfo.getTenantId());
            List<Object> loadHwp = new ArrayList<>();
            loadHwp.add(HWPReader.fromFile(new File(formURL)));
            if (hwpFilter)
                loadHwp.add(new RestWHWP(ezCommonService.getTenantConfig("hwpFilterServer", userInfo.getTenantId())).open(hwpPath + docHref));
            List<ApprGGroupDocInfoVO> group = getGroupDocList(docID, "APR", userInfo.getTenantId(), companyID);
            boolean draftAllTypeB = "Y".equals(ezCommonService.getTenantConfig("draftAllTypeB", userInfo.getTenantId())) && "".equals(susinSN) && group.size() > 1;

            if (findHwpField(susinSN + "habyuipositon" + aprSN, loadHwp)) {
                if (isHesong) {
                    setHwpText(draftAllTypeB, susinSN + "habyuipositon" + aprSN, userInfo.getTitle(), loadHwp);
                } else {
                    setHwpText(draftAllTypeB, susinSN + "habyuipositon" + aprSN, signTitle, loadHwp);
                }
            }

            // 사인이 이미지인 경우 작업 필요 (서버단에서 HWP 문서에 이미지 삽입하는 로직 미구현)
//			if (signType.equals("IMAGE")) {
//				String signImageType = ezCommonService.getTenantConfig("signImageType", userInfo.getTenantId());
//				
//				String[] tempSignCont = signCont.split("::");
//				
//				if (tempSignCont[1] != null && tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t26", userInfo.getLocale())) > -1) {
//					if (signImageType.equals("NAME")) {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
//					} else {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=28 spath='" + tempSignCont[0] + "'>";
//					}
//				} else {
//					if (signImageType.equals("NAME")) {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'><br>" + userInfo.getDisplayName();
//					} else {
//						signCont = "<img src='" + tempSignCont[0] + "' border=0 embedding=1 width=50 height=50 spath='" + tempSignCont[0] + "'>";
//					}
//				}
//			}

            /* 2023-11-15 홍승비 - HWP 파일이면서 이미지 서명인 경우, 원문서에 맵핑되는 정보는 TEXT 유형의 서명으로 고정한다. (현재 결재자명을 문자서명으로 사용) */
            if (signType.equals("IMAGE")) {
                String[] tempSignCont = signCont.split("::");
                signCont = userInfo.getDisplayName();

                /* 2023-11-01 홍승비 - 합의문의 이미지 서명 확인 시, ::문자 split한 이후의 데이터가 존재하는지 체크하도록 수정 (대리결재(代), 대결, 전결 문자) */
                if (tempSignCont.length > 1 && tempSignCont[1] != null &&
                        (tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t26", userInfo.getLocale())) > -1 || tempSignCont[1].indexOf(messageSource.getMessage("ezApprovalG.t25", userInfo.getLocale())) > -1
                                || tempSignCont[1].indexOf(messageSource.getMessage("ezApproval.t498", userInfo.getLocale())) > -1)) {
                    /* 2023-11-15 홍승비 - 합의자의 대리결재(代) 문자, '대결/전결' 문자를 문자 서명 위에 함께 표출하도록 수정  (문자서명과 동일 스펙) */
                    signCont = tempSignCont[1] + signCont;
                }
            }

            // 부서 합의인 경우 원문서 문서번호 채번
            if (!isHesong) {
                int lastHabyuiCnt = lastKyulJeHabYuiYN(orgDocID, "approvUi", userInfo.getCompanyID(), userInfo.getTenantId());
                String orgDeptID = getOrgDraftDeptID(orgDocID, userInfo.getTenantId(), userInfo.getCompanyID());
                if (lastHabyuiCnt > 0) {
                    String docNo = getHwpText("docnumber", loadHwp);

                    map.put("v_habDocID", docID);
                    List<ApprGDocListVO> docState = ezApprovalGDAO.getLastHabYuiDocState(map);

                    if (docState.size() > 0) {
                        if (docState.get(0).getDocState().equals("012")) {
                            Document xmlDom = commonUtil.convertStringToDocument(getCabinetNum(orgDeptID, "", companyID, userInfo.getTenantId(), userInfo.getOffset()));
                            cabinetSN = xmlDom.getElementsByTagName("RESULT").item(0).getTextContent();

                            map.put("v_DOCNO", docNo + createDocNO(cabinetSN, docNumZeroCnt));
                            map.put("v_MODE", "APR");
                            ezApprovalGDAO.updateDocNumber(map);
                            map.put("v_MODE", "END");
                            map.put("v_DOCID", orgDocID);
                            ezApprovalGDAO.updateDocNumber(map);
                        }
                        setHwpText(false, loadHwp, "docnumber", docNo + createDocNO(cabinetSN, docNumZeroCnt));
                    }
                }
            }

            if (findHwpField(susinSN + "habyuisign" + aprSN, loadHwp)) {
                setHwpText(draftAllTypeB, loadHwp, susinSN + "habyuisign" + aprSN, signCont);
            }

            String strDate = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), userInfo.getOffset(), false).substring(5, 10).replace("-", ".");
            if (findHwpField(susinSN + "habyuidate" + aprSN, loadHwp)) {
                setHwpText(draftAllTypeB, loadHwp, susinSN + "habyuidate" + aprSN, strDate);
            }

            if (!hwpFilter) {
                HWPWriter.toFile((HWPFile) loadHwp.get(0), formURL); // 오브젝트 스토리지가 아닌 로컬 파일 시스템의 formURL 경로에 현재 변경한 loadHwp을 저장
            } else {
                whwpSave(((RestWHWP) loadHwp.get(1)), hwpPath + docHref, formURL.substring(0, formURL.lastIndexOf("/")));
            }
			
			// EzFileOutputStream을 선언하는 순간 로컬 파일 경로에 새로운 File 객체가 생성되므로, 미리 저장해둔 byte 배열을 전달
	        byte[] hwpFileBytes = FileUtils.readFileToByteArray(new File(formURL));
	        
			// EzFAL EzFileOutputStream 사용 (자동 close 호출)
			try (EzFileOutputStream fosHwp = new EzFileOutputStream(formURL)) { // 오브젝트 스토리지로 연결되는 파일아웃스트림
				fosHwp.write(hwpFileBytes); // 로컬 파일 시스템에서 가져온 파일
				fosHwp.flush();
			} catch (Exception e) {
				logger.error(e.getMessage(), e);
			}
		}
		
		// '합의' 서명 XML 생성
		StringBuilder resultXML = new StringBuilder();
		
		resultXML.append("<SIGNINFOS>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + "TEXT" + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + susinSN + "habyui" + aprSN + "</SIGNNAME>");
		resultXML.append("<CONTENT>" + commonUtil.cleanValue(deptName) + "</CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + "TEXT" + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + susinSN + "habyuipositon" + aprSN + "</SIGNNAME>");
		resultXML.append("<CONTENT>" + commonUtil.cleanValue(signTitle) + "</CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNNAME>" + susinSN + "habyuisign" + aprSN + "</SIGNNAME>");
		
		/* 2023-11-07 홍승비 - 합의결재 완료 시 이미지 서명을 원문서에 맵핑하는 경우, DB의 tbl_signinfo 테이블에는 이미지 서명 파일의 경로(+ 대결/전결 문자 + 컨피그에 따라 결재자명까지)를 저장 */
		if ("mht".equals(ext)) {
			resultXML.append("<SIGNTYPE>" + signType + "</SIGNTYPE>");
			
			if (signType.equals("IMAGE")) { // MHT 이미지서명
				resultXML.append("<CONTENT>" + commonUtil.cleanValue(imgSignCont) + "</CONTENT>");
			} else { // MHT 문자서명 (HTML)
				resultXML.append("<CONTENT>" + commonUtil.cleanValue(signCont) + "</CONTENT>");
			}
		}
		// 2023-11-07 기준, 한글문서의 경우 합의결재 완료시 원문서 서명이 텍스트(TEXT) 타입으로 고정함
		else {
			resultXML.append("<SIGNTYPE>TEXT</SIGNTYPE>");
			resultXML.append("<CONTENT>" + commonUtil.cleanValue(signCont) + "</CONTENT>");
		}
		
		resultXML.append("</SIGNINFO>");
		resultXML.append("<SIGNINFO>");
		resultXML.append("<DOCID>" + orgDocID + "</DOCID>");
		resultXML.append("<SIGNTYPE>" + "TEXT" + "</SIGNTYPE>");
		resultXML.append("<SIGNNAME>" + susinSN + "habyuidate" + aprSN + "</SIGNNAME>");
		resultXML.append("<CONTENT>" + signDateMD + "</CONTENT>");
		resultXML.append("</SIGNINFO>");
		resultXML.append("</SIGNINFOS>");
		
		subSQL = updateSignInfo(resultXML, orgCompanyID, "QUERY", userInfo.getTenantId());
		
		if (subSQL.indexOf("FALSE") > -1) {
			return "FALSE";
		}

		logger.debug("updateHabyuiResult ended");
		
		return strSQL.toString();
	}
	
