	public String getSerialNum(String snType1, String snType2, String snType3, String companyID, String langType, int tenantID) throws Exception {
		logger.debug("getSerialNum started.");
		
		/* 2025-04-01 홍승비 - 전자결재G > 기산일(회계년도) 시간대 기준 값을 테넌트 컨피그로 옵션화, 디폴트로 UTC 정시가 아닌 한국시(UTC + 9)를 기준으로 사용하도록 수정 */
		String todayUTCTime = commonUtil.getTodayUTCTime("");
		String accountYearTimeZone = ezCommonService.getTenantConfig("accountYearTimeZone", tenantID);
		
		if ("KST".equals(accountYearTimeZone)) {
			todayUTCTime = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime(""), "235|+09:00", false);
		}
		
		String accountYear = getAccountingYear(todayUTCTime, companyID, langType ,tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("iv_Type1", snType1);
		map.put("iv_Type2", snType2);
		map.put("iv_Type3", snType3);
		map.put("v_AccountYear", accountYear);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_SYSDATE",commonUtil.getTodayUTCTime(""));
		
		String result = ezApprovalGDAO.spGetSerialNo(map);
		map.put("v_CurSN", result);
		if (result == null) {
			logger.debug("insert");
			
			map.put("v_CurSN", "1");
			ezApprovalGDAO.insertSerialNo(map);
			result = "1";
		}
		
		int rollBackFlag =  ezApprovalGDAO.rollBackFlag(map);
		
		if (rollBackFlag == 1) {
			logger.debug("delete");
			 ezApprovalGDAO.deleteSerialNo(map);
		} else {
			logger.debug("update");
			ezApprovalGDAO.updateSerialNo(map);
			result = Integer.toString((Integer.parseInt(result)));
		}
		
		logger.debug("deptID,SerialNum = " + snType2 + result);
		logger.debug("getSerialNum ended.");
		
		return String.valueOf(result);
	}
	/**
	 * 완료된 문서에 대한 파일 복사 및 DB 데이터 입력.
	 * */
	public String doApproveEnd(String docID, String dirPath, String deptID, boolean sendFlag, String companyID, int tenantID) throws Exception {
		logger.debug("doApproveEnd started");

		boolean rtnVal = true;
		String docState = "";
		String href = "";
		String orgDeptID = "";
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_TENANTID", tenantID);
		// 진행중인 문서 정보 리스트 추출
		List<ApprGDocListVO> apprGDocListVOList = ezApprovalGDAO.doApproveEndDocInfo(map);
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (int i = 0; i < apprGDocListVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGDocListVOList.get(i)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		
		if (docXML.getElementsByTagName("DOCSTATE").item(0) != null) {
			docState = makeListField(docXML.getElementsByTagName("DOCSTATE").item(0).getTextContent());
		}
		if (docXML.getElementsByTagName("HREF").item(0) != null) {
			href = makeListField(docXML.getElementsByTagName("HREF").item(0).getTextContent());
		}
		if (docXML.getElementsByTagName("APRMEMBERDEPTID").item(0) != null) {
			orgDeptID = makeListField(docXML.getElementsByTagName("APRMEMBERDEPTID").item(0).getTextContent());
		}
		if (orgDeptID.trim().equals("")) {
			orgDeptID = deptID;
		}
		
		if (docState.trim().equals("") && !sendFlag) {
			rtnVal = false;
		} else {
			switch (docState) {
			case "017": // 017 참조
				break;
				
			default:
				if (sendFlag) {
					docState = staDSBalsin;
				}
				
				if (docState.equals(staDSGongRam)) {
					orgDeptID = deptID;
				}

                /* 전자결재G > 상위부서문서함 사용 > 상위부서 conainerID 사용 */
                String upperDeptCode = "";
                Map<String, String> upDeptInfo = getUpperDeptInfo(orgDeptID, tenantID);
                if (upDeptInfo.get("USEUPPERDEPTBOX") != null && upDeptInfo.get("USEUPPERDEPTBOX").equals("Y")) {
                    upperDeptCode = upDeptInfo.get("upperDeptCode");
                }

				String containerID = returnContainerID((upperDeptCode.equals("") ? orgDeptID : upperDeptCode), docState, companyID, tenantID);
				String extFileName = getExtendedFileName(href);
				String oldYear = getDocHrefYear(docID, companyID, tenantID);
				String endURL = commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator + companyID + commonUtil.separator + "doc" + commonUtil.separator + oldYear + commonUtil.separator + getDocDir(docID) + commonUtil.separator + docID + "." + extFileName;
				String source = dirPath + commonUtil.separator + href.replace(commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator, "");
				String targetPath = dirPath + commonUtil.separator + companyID + commonUtil.separator + "doc" + commonUtil.separator + oldYear + commonUtil.separator + getDocDir(docID) + commonUtil.separator + docID + "." + extFileName;
				
				rtnVal = copyFile(source, targetPath, dirPath + commonUtil.separator + companyID + commonUtil.separator + "doc" + commonUtil.separator + oldYear + commonUtil.separator + getDocDir(docID));
                
                // 파일 복사에 성공하면 완료문서 관련 테이블에 데이터 입력.
				if (rtnVal) {
                    EzFile file = new EzFile(commonUtil.detectPathTraversal(targetPath));
                    String fileSize = "";
                    if (file.exists()) {
                        long lFileSize = file.length();
                        fileSize = Long.toString(lFileSize);
                    } else {
                        fileSize = "90112";
                    }
                    map.put("docSize", fileSize);

					map.put("v_DOCID", docID);
					map.put("v_DOCSTATE", docState);
					map.put("v_endURL", endURL);
					map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
					map.put("v_ContainerID", containerID);
					map.put("companyID", companyID);
					map.put("v_TENANTID", tenantID);

					if(config.getProperty("config.useOpenGov").equalsIgnoreCase("YES")) {
                        ezApprovalGDAO.updateOpenGovDocFileSize(map);
                    }

					ezApprovalGDAO.insertApprovEndAprDocInfo(map);
					ezApprovalGDAO.insertApprovEndAprLineInfo(map);
					ezApprovalGDAO.insertApprovEndAttachInfo(map);
					ezApprovalGDAO.insertApprovEndAprDocAttachInfo(map);
					ezApprovalGDAO.insertApprovEndAprOpinionInfo(map);
					ezApprovalGDAO.insertApprovEndReceiptPointInfo(map);
					ezApprovalGDAO.insertApprovEndReceiptProcessInfo(map);
					ezApprovalGDAO.insertApprovExpEndAprDocInfo(map);
					ezApprovalGDAO.insertApprovExpEndAprLine(map);
					
					// 2018.06.20 - mht 문서는 KLIB 암호화 제공 안 함 (추후에 개발)
					if ("yes".equalsIgnoreCase(ezCommonService.getTenantConfig("useApprovalKlib", tenantID)) && "G".equals(ezCommonService.getTenantConfig("ApprovalFlag", tenantID))) {
						ezApprovalGKlibService.encryptCompleteApproveFiles(docID, companyID, tenantID);
					}
				}
				
				break;
			}
		}
		
		logger.debug("doApproveEnd ended");
		
		if (rtnVal) {
			return "TRUE";
		} else {
			return "FALSE";
		}
	}
	/**
	 * 문서함 아이디 추출.
	 * 기존에 존재하는 문서함 아이디가 없으면 생성.
	 * */
	public String returnContainerID(String deptID, String docState, String companyID, int tenantID) throws Exception {
		logger.debug("returnContainerID started");

		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DEPTID", deptID);
		map.put("v_DOCSTATE", docState);
		map.put("v_TENANTID", tenantID);
		
		String containerID = ezApprovalGDAO.returnContainerID(map);
		
		if(containerID == null) {
			containerID = "";
		}
		
		String containerID2 = "";
		
		if(containerID.equals("")) {
			containerID2 = ezApprovalGDAO.returnContainerID2(map);
		}
		
		if(containerID2 == null) {
			containerID2 = "";
		}
		map.put("v_CONTAINERID", containerID);
		map.put("v_CONTAINERTYPEID", containerID2);
		
		String containerID3 = ezApprovalGDAO.returnContainerID3(map);
		String containerType ="";
		
		if(!containerID2.equals("")) {
			containerType = containerID3.split(":")[1];
		}
		// 즉, containerID1, containterID2에 둘다 값이 없는 경우
		if(containerID3.equals(":")) {
			containerID3 = "";
		} else {
			containerID3 = containerID3.split(":")[0];
		}
		
		if (containerID3.trim().equals("")) {
			containerID3 = makeContainer(deptID, makeListField(containerType), companyID, tenantID);
		}

		logger.debug("returnContainerID ended");
 		
		return containerID3;
	}
	
	public void setRealReceiptInfo(String docID, String companyID, String lang, int tenantID) throws Exception {
        logger.debug("setRealReceiptInfo started");
        
        Map<String, Object> map = new HashMap<String, Object>();
        map.put("companyID", companyID);
        map.put("v_DOCID", docID);
        map.put("v_TENANTID", tenantID);
        
        List<ApprGReceiptVO> receipts = ezApprovalGDAO.doSendDocReceiptInfo(map);
        
        if (receipts.size() > 0) {
            List<ApprGReceiptVO> newReceipts = getRealReceiptInfo(receipts, docID, companyID, lang, tenantID);
            
            map.put("v_NEWRECEIPTS", newReceipts);
            
            ezApprovalGDAO.deleteReceiptInfo(map);
            ezApprovalGDAO.insertDisbandGroupReceipt(map);
        }
        
        logger.debug("setRealReceiptInfo ended");
	}
	
	public List<ApprGReceiptVO> getRealReceiptInfo(List<ApprGReceiptVO> receipts, String docID, String companyID, String lang, int tenantID) throws Exception {
        logger.debug("getRealReceiptInfo started");
        
        String susinGroupIcon = getCode2Name("A53", "001", companyID, lang, tenantID);
        
        Map<String, Object> map = new HashMap<String, Object>();
        map.put("companyID", companyID);
        map.put("v_DOCID", docID);
        map.put("v_TENANTID", tenantID);
        
        boolean isGroup = false;
        
        List<ApprGReceiptVO> newReceipts = new LinkedList<ApprGReceiptVO>();
        
        //수신처중 수신처그룹이 있는지 확인, 수신처그룹이 있으면 해제하여 수신처리스트에 추가함
        for (ApprGReceiptVO receipt : receipts) {
            if (receipt.getReceiptPointID().startsWith(susinGroupIcon)) {
                isGroup = true;
                
                map.put("v_MAINID", Integer.parseInt(receipt.getReceiptPointID().replaceFirst(susinGroupIcon, "")));
                map.put("v_CURRRECEIPT", receipt);
                List<ApprGReceiptVO> susinGroupMembers = ezApprovalGDAO.selectDisbandGroupReceipt(map);
                Iterator<ApprGReceiptVO> iterator = susinGroupMembers.iterator();
                while (iterator.hasNext()) {
                    ApprGReceiptVO member = iterator.next();
                    if ("N".equals(member.getExtReceptYN())) {
                        // 2024-05-23 김유진 - 폐지부서일 경우 list에서 삭제
                        String TrashDeptYN = (member.getDept_Cd_Path() == null || member.getDept_Cd_Path() == "" || member.getDept_Cd_Path().contains("trash_dept")) ? "Y" : "N";
                        if ("Y".equals(TrashDeptYN)) {
                            iterator.remove();
                        }
                    }
                }

                newReceipts.addAll(susinGroupMembers);
            } else {
                newReceipts.add(receipt);
            }
        }
        
        //수신처중 수신처그룹이 있으면 전체 중복체크, 수신처 DB 정보 삭제후 다시 인서트
        if (isGroup) {
            Map<String, Boolean> distinctMap = new HashMap<String, Boolean>();
            int sn = 1;
            
            for (Iterator<ApprGReceiptVO> iter = newReceipts.iterator(); iter.hasNext();) {
                ApprGReceiptVO newReceipt = iter.next();
                
                if (distinctMap.putIfAbsent(newReceipt.getReceiptPointID(), true) == null) {
                    newReceipt.setDeptMemberSN(String.valueOf(sn++));
                } else {
                    iter.remove();
                }
            }
        }
        
        logger.debug("getRealReceiptInfo ended");
        
        return newReceipts;
	}

