	public String getBujaeInfo(String userID, String deptID, int tenantID, String offset, String companyID) throws Exception {
		logger.debug("getBujaeInfo started");

		String absentReason = ezOrganService.getPropertyValue(userID, "extensionAttribute5", tenantID);
		String rtnVal = "";
		String userRealDeptId = "";
		userRealDeptId = ezOrganService.getUserOrgDeptId(userID, tenantID, companyID);
		if (deptID.equals(userRealDeptId)) {
			absentReason = ezOrganService.getPropertyValue(userID, "extensionAttribute5", tenantID);
		} else {
			absentReason = ezOrganService.getAddJobProxy(userID, deptID, tenantID);
		}
		
		if (absentReason != null && !absentReason.trim().equals("")) {
			String[] reasons = absentReason.split(":");
			if (reasons[0].trim().equals("") && reasons.length >= 7) {
				//String now = commonUtil.getTodayUTCTime("");
				//if (now.compareTo(reasons[3].replace("/", ":")) >= 0 && now.compareTo(reasons[4].replace("/", ":")) <= 0) {
				//	rtnVal = reasons[5];
				//}
				String now = commonUtil.getDateStringInUTC(commonUtil.getTodayUTCTime("yyyy-MM-dd HH:mm"), offset, false);
				
				if (now.compareTo(reasons[3].concat(":"+reasons[4])) >= 0 && now.compareTo(reasons[5].concat(":"+reasons[6])) <= 0) {
					rtnVal = reasons[7];
				}
			}
		}

		logger.debug("getBujaeInfo ended");
		
		return rtnVal;
	}

	public String doChamjo(String docID, String userID, String userName, String userName2, String userJobTitle, String userJobTitle2, String deptID, String deptName,
			String deptName2, String deptYN, String pCompanyID, String dirPath, String docState, String companyID, int tenantID) throws Exception {
		logger.debug("doChamjo started");

		String aprState = "";
		String aprType = "";
		String approvalFlag = ezCommonService.getTenantConfig("ApprovalFlag", tenantID);
		
		if (deptYN.toUpperCase().equals("Y")) {
			aprState = staASDoJak;
		} else {
			aprState = staASJinHang;
		}
		
		if (docState.equals(staDSChamJo)) {
			aprType = staATChamJo;
		} else {
			aprType = staATGongram;
		}

		String newID = getNewID(companyID, tenantID);
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("companyID", companyID);
		map.put("v_DOCID", docID);
		map.put("v_TENANTID", tenantID);
		map.put("v_FLAG", "APR");
		
		String fileName = ezApprovalGDAO.getDocInfoHref(map);
		String extFileName = getExtendedFileName(fileName);
		String fileURL = dirPath + commonUtil.separator + fileName.replace(commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator, "");
		String url = commonUtil.getUploadPath("upload_approvalG.ROOT", tenantID) + commonUtil.separator + pCompanyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getTodayUTCTime("yyyy") + commonUtil.separator + "1000" + commonUtil.separator +
				getDocDir(newID) + commonUtil.separator + newID + "." + extFileName;
		boolean rtnVal = copyFile(fileURL, dirPath + commonUtil.separator + pCompanyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getTodayUTCTime("yyyy") + commonUtil.separator + "1000" + commonUtil.separator +
				getDocDir(newID) + commonUtil.separator + newID + "." + extFileName, dirPath + commonUtil.separator + pCompanyID + commonUtil.separator + "doc" + commonUtil.separator + commonUtil.getTodayUTCTime("yyyy") + commonUtil.separator +
				"1000" + commonUtil.separator + getDocDir(newID));
		
		if (rtnVal) {
			map.put("v_NEWID", newID);
			map.put("v_DOCSTATE", docState);
			map.put("v_APRSTATE", aprState);
			map.put("v_URL", url);
			map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
			
			ezApprovalGDAO.insertCamjoAPrDocInfo(map);
			ezApprovalGDAO.insertCamjoExAPrDocInfo(map);
			ezApprovalGDAO.insertCamjoAprAttachInfo(map);
			ezApprovalGDAO.insertCamjoAprDocAttachInfo(map);
			ezApprovalGDAO.insertCamjoAprOpinionInfo(map);
			
			if (deptYN.toUpperCase().equals("Y")) {
				map.put("v_DEPTID", deptID);
				map.put("v_DEPTNAME", deptName);
				map.put("v_DEPTNAME2", deptName2);
				map.put("v_STAASDOJAK", staASDoJak);
				
				ezApprovalGDAO.insertCamjoAprReceiptProcessInfo(map);
				
			} else {
				map.put("v_APRTYPE", aprType);
				map.put("v_USERID", userID);
				map.put("v_USERNAME", userName);
				map.put("v_USERNAME2", userName2);
				map.put("v_USERJOBTITLE", userJobTitle);
				map.put("v_USERJOBTITLE2", userJobTitle2);
				map.put("v_DEPTID", deptID);
				map.put("v_DEPTNAME", deptName);
				map.put("v_DEPTNAME2", deptName2);
				map.put("v_PCOMPANYID", pCompanyID);
				
				if (approvalFlag.equals("G")) {
					map.put("v_SN", "1");
				} else {
					map.put("v_SN", "2");
				}
				ezApprovalGDAO.insertCamjoAprLineInfo(map);
				ezApprovalGDAO.insertCamjoExAprLine(map);
			}
		} else {
			logger.debug("doChamjo ended");
			return "FALSE";
		}

		logger.debug("doChamjo ended");
		
		return "TURE";
	}

	/* 2025-06-22 홍승비 - 공통적인 파일 복사 메서드에 EzFAL 적용 (서버 상에 저장된 파일 간 복사에 사용) */
	public boolean copyFile(String source, String target, String dirPath) throws Exception {
		logger.debug("copyFile started");

		if (!dirPath.trim().equals("")) {
			EzFile file = new EzFile(commonUtil.detectPathTraversal(dirPath));
			
			if (!file.exists()) {
				file.mkdirs();
			}
		}
		try {
			EzFile src = new EzFile(commonUtil.detectPathTraversal(source));
			EzFile des = new EzFile(commonUtil.detectPathTraversal(target));
			
			EzFAL.copyFile(src, des);
			
			logger.debug("copyFile ended");
			return true;
		} catch (Exception e) {
			logger.error(e.getMessage(), e);
			return false;
		}
	}
	
	/* 2025-06-22 홍승비 - 공통적인 파일 복사 메서드에 EzFAL 적용 (서버 상에 저장된 파일 간 복사에 사용) */
	/**
	 * source 파일의 바이트를 KLIB 으로 복호화 후 target 파일로 복사한다.
	 * */
	// copyFile() 메소드와 같은 중복코드 리팩토링 안 함
	public boolean copyDecryptFileForKlib(String source, String target, String dirPath) throws Exception {
		logger.debug("copyDecryptFileForKlib started");

		if (!dirPath.trim().equals("")) {
			EzFile file = new EzFile(commonUtil.detectPathTraversal(dirPath));
			
			if (!file.exists()) {
				file.mkdirs();
			}
		}
		try {
			File src = new EzFile(commonUtil.detectPathTraversal(source)).getFile();
			File des = new EzFile(commonUtil.detectPathTraversal(target)).getFile();
			
			byte[] descryptedBytes = klibUtil.decrypt(commonUtil.readBytesFromFile(src.toPath()));
			
			// 로컬 파일 시스템에서의 decrypt된 파일을 로컬 파일 시스템의 des 경로에 저장
			ByteArrayInputStream inputStream = new ByteArrayInputStream(descryptedBytes);
			Files.copy(inputStream, des.toPath(), StandardCopyOption.REPLACE_EXISTING);
			
			// 위에서 decrypt한 파일을 다시 오브젝트 스토리지로 업로드
			try (EzFileOutputStream fos = new EzFileOutputStream(commonUtil.detectPathTraversal(target))) { // 오브젝트 스토리지로 연결되는 파일아웃스트림
				fos.write(FileUtils.readFileToByteArray(new File(commonUtil.detectPathTraversal(target)))); // 로컬 파일 시스템에서 가져온 파일
				fos.flush();
			}
			
			logger.debug("copyDecryptFileForKlib ended");
			return true;
		} catch (Exception e) {
			logger.error(e.getMessage(), e);
			return false;
		}
	}

	public String getExtendedFileName(String href) {
		String[] tempHref = href.split("\\.");
		
		return tempHref[tempHref.length - 1];
	}
	/**
	 * LeftMenu->결재환경설정->알림메일설정 관련
	 * TBL_NOTIFICATION 테이블에 히스토리 남김
	 * */
	public String sendMsg(String docID, String nextUserID, String mode, String companyID, String lang, int tenantID) throws Exception{
		boolean notiFlag = false;
		logger.debug("sendMsg started");

		if (getCode2Name("A43", "001", companyID, lang, tenantID).equals("Y")) {
			
			notiFlag = true;
		}
		
		if (notiFlag) {

			String docTitle = "";
			
			Map<String, Object> map = new HashMap<String, Object>();
			map.put("companyID", companyID);
            map.put("v_COMPANYID", companyID);
			map.put("v_TENANTID", tenantID);
			map.put("v_DOCID", docID);
			map.put("v_FLAG", "ING");

            switch (mode.toUpperCase()){
                case "ING": case "HESU": case "BAN": case "BOR":
                    String groupDocSN = ezApprovalGDAO.getGroupDocSN(map);
                    if(!"".equals(groupDocSN) && !docID.equals(groupDocSN))
                        return "TRUE";
            }
            
            docTitle = makeListField(ezApprovalGDAO.getDocTitle(map));
			
			if (docTitle.trim().equals("")) {
				Map<String, Object> map1 = new HashMap<String, Object>();
				map1.put("companyID", companyID);
				map1.put("v_DOCID", docID);
				map1.put("v_TENANTID", tenantID);
				map1.put("v_FLAG", "END");
				
				docTitle = makeListField(ezApprovalGDAO.getDocTitle(map1));
				
				if (docTitle.trim().equals("")) {
					docTitle = getCode2Name("L06", "001", companyID, lang, tenantID);
					

				} else {
					if (nextUserID.trim().equals("")) {
						Map<String, Object> map2 = new HashMap<String, Object>();
						map2.put("companyID", companyID);
						map2.put("v_DOCID", docID);
						map2.put("v_TENANTID", tenantID);
						map2.put("v_FLAG", "END");
						
						nextUserID = makeListField(ezApprovalGDAO.getDraftUserID(map2));
					}
				}
			} else {
				if (nextUserID.trim().equals("")) {
					Map<String, Object> map3 = new HashMap<String, Object>();
					map3.put("companyID", companyID);
					map3.put("v_DOCID", docID);
					map3.put("v_TENANTID", tenantID);
					map3.put("v_FLAG", "ING");
					
					nextUserID = makeListField(ezApprovalGDAO.getDraftUserID(map3));
				}
			}
			
			// 2025-03-17 조수빈 - voc #156654 모바일 PUSH> 결재 관련 알림 미번역
			// 발신인 기준의 언어 설정으로 발송되거나 수신인의 언어 설정이 모바일의 언어와 웹의 언어가 다른 경우가 있으므로 lang 값을 별도 가져옴.
			
			String recvWebLang = ezCommonService.selectUserGetLang(nextUserID, tenantID);
			String recvMobileLang = ezCommonService.getMobileLang(nextUserID, tenantID);
			
			// 한 번도 로그인 하지 않은 경우 언어가 없을 수 있으므로 처리
			String useSecondaryLang = ezCommonService.getTenantConfig("useSecondaryLang", tenantID);
			String primaryLang = ezCommonService.getTenantConfig("PrimaryLang", tenantID);
			
			if ("YES".equals(useSecondaryLang)){
				primaryLang = "2";
			}
			
			recvWebLang = (null == recvWebLang || "".equals(recvWebLang)) ? primaryLang : recvWebLang;
			recvMobileLang = (null == recvMobileLang || "".equals(recvMobileLang)) ? primaryLang : recvMobileLang;
			
			String webNotyStr = "";
			String mobileNotyStr = "";
			NotiType notiType;
			switch (mode.toUpperCase()) {
			case "ING" :
                webNotyStr = getCode2Name("L06", "002", companyID, recvWebLang, tenantID); //"문서도착";
                mobileNotyStr = getCode2Name("L06", "002", companyID, recvMobileLang, tenantID); //"문서도착";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "END" :
                webNotyStr = getCode2Name("L06", "003", companyID, recvWebLang, tenantID); //"문서완료";
                mobileNotyStr = getCode2Name("L06", "003", companyID, recvMobileLang, tenantID); //"문서완료";
                notiType = NotiType.APPROVAL_COMPLETE;
				break;
			case "BAN" :
                webNotyStr = getCode2Name("L06", "004", companyID, recvWebLang, tenantID); //"문서반송";
                mobileNotyStr = getCode2Name("L06", "004", companyID, recvMobileLang, tenantID); //"문서반송";
                notiType = NotiType.APPROVAL_REJECT;
				break;
			case "BOR" :
                webNotyStr = getCode2Name("L06", "005", companyID, recvWebLang, tenantID); //"문서보류";
                mobileNotyStr = getCode2Name("L06", "005", companyID, recvMobileLang, tenantID); //"문서보류";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "BAL" :
                webNotyStr = getCode2Name("L06", "006", companyID, recvWebLang, tenantID); //"문서발송";
                mobileNotyStr = getCode2Name("L06", "006", companyID, recvMobileLang, tenantID); //"문서발송";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "SUSIN" :
                webNotyStr = getCode2Name("L06", "007", companyID, recvWebLang, tenantID); //"수신문서";
                mobileNotyStr = getCode2Name("L06", "007", companyID, recvMobileLang, tenantID); //"수신문서";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "JIJUNG" :
                webNotyStr = getCode2Name("L06", "008", companyID, recvWebLang, tenantID); //"지정문서";
                mobileNotyStr = getCode2Name("L06", "008", companyID, recvMobileLang, tenantID); //"지정문서";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "BEBU" :
                webNotyStr = getCode2Name("L06", "012", companyID, recvWebLang, tenantID); //"배부문서"; //012
                mobileNotyStr = getCode2Name("L06", "012", companyID, recvMobileLang, tenantID); //"배부문서"; //012
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "HESONG" :
                webNotyStr = getCode2Name("L06", "009", companyID, recvWebLang, tenantID); //"회송문서";
                mobileNotyStr = getCode2Name("L06", "009", companyID, recvMobileLang, tenantID); //"회송문서";
                notiType = NotiType.APPROVAL_RECEIPT_REJECT;
				break;
			case "HESU" :
                webNotyStr = getCode2Name("L06", "010", companyID, recvWebLang, tenantID); //"문서회수";
                mobileNotyStr = getCode2Name("L06", "010", companyID, recvMobileLang, tenantID); //"문서회수";
                notiType = NotiType.APPROVAL_RETURN;
				break;
			case "REJIJUNG" :
                webNotyStr = getCode2Name("L06", "013", companyID, recvWebLang, tenantID); //"재지정요청"; //013
                mobileNotyStr = getCode2Name("L06", "013", companyID, recvMobileLang, tenantID); //"재지정요청"; //013
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			case "REBEBU" :
                webNotyStr = getCode2Name("L06", "014", companyID, recvWebLang, tenantID); //"재배부요청"; //014
                mobileNotyStr = getCode2Name("L06", "014", companyID, recvMobileLang, tenantID); //"재배부요청"; //014
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			default :
                webNotyStr = getCode2Name("L06", "011", companyID, recvWebLang, tenantID); //"결재노티";
                mobileNotyStr = getCode2Name("L06", "011", companyID, recvMobileLang, tenantID); //"결재노티";
                notiType = NotiType.APPROVAL_ARRIVE;
				break;
			}
			
			insertNotifyItem(nextUserID, webNotyStr, docTitle, "2", docID, tenantID, companyID);

			String useEzTalkNotification = ezCommonService.getTenantConfig("useEzTalkNotification", tenantID);

			// useEzTalkNotification이 YES일 때는 ezTalk으로 결재 알림을 보낸다.
			if (useEzTalkNotification.equals("YES")) {

                String useSaas = ezCommonService.getTenantConfig("useSaas", tenantID);
                if ("Y".equalsIgnoreCase(useSaas)){
                    String linkUrl = "/mobile/ezApprovalG/mApproveDoc.do?"
                            + "pDocID=" + docID + "&pType=" + mode.toUpperCase() + "&pAprMemberSN=2&pMode=APR&companyID=" + companyID; // pAprMemberSN, pMode 파라메터가 확실치 않음.
                    String domainName = ezCommonService.getTenantConfig("DomainName", tenantID);
                    String userEmail = new StringBuilder(nextUserID).append("@").append(domainName).toString();
                    ezEmailService.addEzTalkNotification(userEmail, mobileNotyStr, docTitle, String.valueOf(notiType.mainType()), String.valueOf(notiType.subType()), linkUrl);
                } else {
                    String linkUrl = "/mobile/ezApprovalG/mApproveDoc.do?"
                            + "pDocID=" + docID + "&pType=" + mode.toUpperCase() + "&pAprMemberSN=2&pMode=APR&companyID=" + companyID; // pAprMemberSN, pMode 파라메터가 확실치 않음.
                    ezEmailService.addEzTalkNotification(nextUserID, mobileNotyStr, docTitle, String.valueOf(notiType.mainType()), String.valueOf(notiType.subType()), linkUrl);
                }
            }
		}
		logger.debug("sendMsg ended");

		return "TRUE";
	}

	public String insertNotifyItem(String userID, String notyStr, String subject, String type, String etcData, int tenantID, String companyID) throws Exception {
		logger.debug("insertNotifyItem started");

		String result = "OK";
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_PUSERID", userID);
		map.put("v_PSENDER", notyStr);
		map.put("v_PSUBJECT", subject);
		map.put("v_PTYPE", type);
		map.put("v_PETCDATA", etcData);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
		
		logger.debug("notifyItem param : userID = " + userID + " subject = " + subject);
		
		String itemSeq = ezApprovalGDAO.notifiCationSeq(map);
		
		if(itemSeq == null){
			itemSeq = "0";
			map.put("v_itemSeq", itemSeq);
			
			ezApprovalGDAO.insertNotifyItem(map);
		} else {
			map.put("v_itemSeq", Integer.parseInt(itemSeq) +1);
			ezApprovalGDAO.insertNotifyItem(map);
		}

		logger.debug("insertNotifyItem ended");
		
		return result;
	}

