						String formId = makeListField(docXML.getElementsByTagName("FORMID").item(k).getTextContent());
						
						resultXML.append("<DATA10>" + docXML.getElementsByTagName("FUNCTIONTYPE").item(k).getTextContent() + "</DATA10>");
