	@Override
	public String getAprLineInfoDB(String docID, String flag, String userID, String formID, String companyID, int tenantID, String isUsed, String beforeDocID, String mode, String docState) throws Exception {
		logger.debug("getAprLineInfoDB started.");
		logger.debug("docID = " + docID + " || flag = " + flag + " || userID = " + userID + " || formID = " + formID + " || companyID = " + companyID + " || tenantID = " + tenantID + " || mode =" + mode + " || docState = " + docState);
		
		if (mode.equals("CHAMJOAPR")) {
			mode = "APR";
		} else if (mode.equals("CHAMJOEND")){
			mode = "END";
		}
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID);
		map.put("v_FLAG", flag);
		map.put("v_USERID", userID);
		map.put("v_FORMID", formID);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		map.put("isUsed", isUsed);
		map.put("beforeDocID", beforeDocID);
		map.put("v_MODE", mode);
		map.put("docState", docState);
		// 진행중인 결재 리스트 추출
		List<ApprGAprLineVO> apprGAprLineVOList = ezApprovalGDAO.getAprLineInfo(map);
		
		if (isUsed.equals("reuse")) {
			for (int i = 0; i < apprGAprLineVOList.size(); i++) {
				apprGAprLineVOList.get(i).setAprState("001");
			}
			apprGAprLineVOList.get(apprGAprLineVOList.size()-1).setAprState("002");
		}
		StringBuffer sb = new StringBuffer();
        sb.append("<DATA>");
        
        for (int i = 0; i < apprGAprLineVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGAprLineVOList.get(i)));
		}
        
		sb.append("</DATA>");
		
		logger.debug("getAprLineInfoDB ended.");
		
		return sb.toString();
	}

	@Override
	public Document checkPermission(String docID, String userID, String deptID, String checkMode, String companyID, int tenantID, String docState) throws Exception {
		logger.debug("checkPermission started.");
		
		int v_temp = 0;
		int v_temp2 = 0;
		int v_temp3 = 0;
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_PDOCID", docID);
		map.put("v_PAPRUSERID", userID);
		map.put("v_PDEPTID", deptID);
		map.put("v_PMODE", checkMode);
		map.put("v_TENANTID", tenantID);
		map.put("companyID", companyID);
		map.put("v_temp3", 0);
		map.put("v_temp4", 0);
		map.put("approvalFlag", ezCommonService.getTenantConfig("ApprovalFlag", tenantID));
		map.put("shareApprovalFlag", ezCommonService.getTenantConfig("useShareApproval", tenantID));
		
		if (checkMode.equals("VIE")) {
			v_temp  = ezApprovalGDAO.countVieTempDocID(map);
			map.put("v_temp", v_temp);
			
			if (v_temp < 1) {
				v_temp2  = ezApprovalGDAO.countVieTempDocID2(map);
				map.put("v_temp2", v_temp2);
			}
		} else if (checkMode.equals("REC")) {
			v_temp  = ezApprovalGDAO.countRecTempDocID(map);
			map.put("v_temp", v_temp);
			
			if (v_temp > 0 ) {
				v_temp2  = ezApprovalGDAO.countRecTempDocID2(map);
				map.put("v_temp2", v_temp2);
			} else {
				v_temp3 = ezApprovalGDAO.countVieTempDocID(map);
				if (v_temp3 < 0) {
					map.put("v_temp3", v_temp3);
				}				
				if (v_temp3 > 0 ) {
					map.put("v_temp3", v_temp3);
					
					List<ApprGAprLineVO> tempList = ezApprovalGDAO.countRecTempDocID3(map);
					map.put("v_temp4", tempList.size());
				}
			}
		}
		List<ApprGAprLineVO> apprGAprLineVOList = ezApprovalGDAO.checkPermission(map);
		
		if (apprGAprLineVOList.size() == 0) {
			if (docState != null && docState.equals("017")) {
				apprGAprLineVOList = ezApprovalGDAO.chamJoEndPerMission(map);
			}
		}

		StringBuffer sb = new StringBuffer();
        sb.append("<DATA>");
        
        for (int i = 0; i < apprGAprLineVOList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGAprLineVOList.get(i)));
		}
        
		sb.append("</DATA>");
		
		Document doc = commonUtil.convertStringToDocument(sb.toString());
		
		logger.debug("checkPermission ended.");
		
		return doc;
	}
	
