         sb.append("<DATA>");
        
         for (int i = 0; i < docList.size(); i++) {
        	 sb.append(commonUtil.getQueryResult(docList.get(i)));
         }
         sb.append("</DATA>");
         
		 Document docXML = commonUtil.convertStringToDocument(sb.toString());
		 String listHeader = getListHeader("104", companyID, lang, tenantID);
