	@Override
	public String doCancelForce(String docID, String userID, String companyID,	int tenantId) throws Exception {
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID);
		map.put("v_USERID", userID);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantId);
		
		logger.debug("doCancelForce = v_DOCID =" + docID + " v_USERID =" + userID + " campanyID =" + companyID  + " v_TENANTID =" + tenantId );
		
		//2018-07-10 배현상, 강제회수가 되지 않아야 하는 경우 로직이 그대로 진행되는 오류 수정(팝업이나 row에 강제회수버튼이 살아있는 경우)
		String rtnVal = "OK";
		String cancelForceYN = getCallBackYNForceLine(docID, userID, companyID, tenantId);
		
		if (!cancelForceYN.equals("<RESULT>TRUE</RESULT>")) {
			rtnVal = "FALSE";
		}
		
		if (rtnVal.equals("OK")) {
			// 톡 서버로 알림 전송
			for (ApprGAprLineVO line : getLineList(docID, "APR", companyID, Offset.KST, "1", tenantId)) {
				if (("002".equals(line.getAprState()) || "003".equals(line.getAprState())) && !"1".equals(line.getAprMemberSN())) {
					String lang = ezCommonService.selectUserGetLang(line.getOrgUserID(), tenantId);
					sendMsg(docID, line.getOrgUserID(), "HESU", companyID, lang, tenantId);
					sendNoti(docID, userID, "", line.getOrgUserID(), "", "", "HESU", companyID, lang, tenantId);
				}
			}

			int aprMemberSn = ezApprovalGDAO.selectDoCallBack(map);
			map.put("v_curAprSN", aprMemberSn);
			logger.debug("doCancelForce = aprMemberSn =" + aprMemberSn);

			if(aprMemberSn > 0) {
				if(aprMemberSn == 1) {
					String passAprFlag = ezApprovalGDAO.getPassAprLineFlagByDocID(map);
					if (passAprFlag.equals("Y")) {
						map.put("v_PASSAPRFLAG", passAprFlag);
					}
					
					ezApprovalGDAO.updateDoCallBack(map);
				}
				map.put("v_APRMEMBERSN", aprMemberSn);
				ezApprovalGDAO.updateDoCallBack2(map);
				
				map.put("v_APRMEMBERSN", aprMemberSn + 1);
				ezApprovalGDAO.updateDoCallBack3(map);
			} else {
				rtnVal = "FALSE";
			}
		}
		return rtnVal;
	}

