	@Override
	public String doHabyuiHesong(Document doc, String dirPath, String companyID, String lang, int tenantID, LoginVO userInfo, String curDocNum) throws Exception {
		String result = "";
		boolean rtnVal = true;
		
		String docID = doc.getElementsByTagName("ASSIGN").item(0).getChildNodes().item(0).getTextContent().trim();
		String pDeptID = doc.getElementsByTagName("ASSIGN").item(0).getChildNodes().item(1).getTextContent().trim();
		// String pUserID = doc.getElementsByTagName("ASSIGN").item(0).getChildNodes().item(2).getTextContent().trim();
		String pReceiveSN = doc.getElementsByTagName("ASSIGN").item(0).getChildNodes().item(3).getTextContent().trim();
		
		String pOrgDocID = "";
		String pOrgCompanyID = "";
        String approvalFlag = ezCommonService.getTenantConfig("ApprovalFlag", tenantID);
		 
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID);
		map.put("companyID", companyID);
		map.put("v_TENANTID", tenantID);
		
		Map<String, Object> map2 = new HashMap<String, Object>();
		map2.put("v_DOCID", docID);
		map2.put("companyID", companyID);
		map2.put("v_TENANTID", tenantID);
		map2.put("v_FLAG", 1);
		
		List<ApprGAprLineVO> aprLineInfo = ezApprovalGDAO.getAprLineInfo(map2);
		
		int aprLineCnt = aprLineInfo.size();
		long waitCnt = aprLineInfo.stream().filter(elem -> "001".equals(elem.getAprState())).count();
		
		// 결재선 지정없이 접수자가 바로 회송을 눌렀거나, 결재선을 지정하고 접수자가 회송을 누를 경우, 결재선에 접수자만 반송 상태로 추가해서 회송한다. 2020-04-16 임민석
		if(aprLineCnt == 0 || aprLineCnt - 1 <= waitCnt) {
			ezApprovalGDAO.deleteApprLineInfo(map);
			
			LocalDateTime now = LocalDateTime.now(ZoneId.of("UTC"));
			String nowStr = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss").format(now);
			
			Map<String, Object> param = new HashMap<String, Object>();
			param.put("v_DOCID", docID);
			param.put("v_APRMEMSN", 1);
			param.put("v_APRTYPE", "001");
			param.put("v_APRSTATE", "004");
			param.put("v_APRMEMID", userInfo.getId());
			param.put("v_APRMEMDEPTYN", "N");
			param.put("v_APRMEMNM", userInfo.getDisplayName());
			param.put("v_APRMEMNM2", userInfo.getDisplayName2());
			param.put("v_APRMEMJOBTITLE", userInfo.getTitle());
			param.put("v_APRMEMJOBTITLE2", userInfo.getTitle2());
			param.put("v_APRMEMBERDEPTID", userInfo.getDeptID());
			param.put("v_APRMEMBERDEPTNAME", userInfo.getDeptName());
			param.put("v_APRMEMBERDEPTNAME2", userInfo.getDeptName2());
			param.put("v_APRMEMBERLDAPPATH", userInfo.getCompanyID());
			param.put("v_RECEIVEDDATE", nowStr);
			param.put("v_PROCESSDATE", nowStr);
			param.put("v_REASONDONOTAPPROV", "");
			param.put("v_ISPROPOSERYN", "N");
			param.put("v_ISBRIEFUSERYN", "N");
			param.put("v_TENANTID", tenantID);
			param.put("companyID", companyID);
			
			ezApprovalGDAO.insertApprLine(param);
			
			param.put("v_ORGUSERID", userInfo.getId());
			
			ezApprovalGDAO.deleteExApprLine(param);
			ezApprovalGDAO.insertExApprLine(param);
		}
		
		List <ApprGAprDocInfoVO> hesongList = ezApprovalGDAO.doSusinHesongAprDocInfo(map);
		
		StringBuffer sb = new StringBuffer();
        sb.append("<DATA>");
        	
        for (int j = 0; j < hesongList.size(); j++) {
			sb.append(commonUtil.getQueryResult(hesongList.get(j)));
		}
		sb.append("</DATA>");
		
		Document docXML = commonUtil.convertStringToDocument(sb.toString());
		
		if (docXML.getElementsByTagName("ROW").getLength() > 0) {
			pOrgDocID = docXML.getElementsByTagName("ORGDOCID").item(0).getTextContent();
			pOrgCompanyID = docXML.getElementsByTagName("COMPANYID").item(0).getTextContent();
			//같은 회사 일 때
			if (companyID.equals(pOrgCompanyID)) {
				map.put("v_APRSTATE", staASBanSong);
				map.put("v_SYSDATE", commonUtil.getTodayUTCTime(""));
				map.put("pReceiveSN", pReceiveSN);
				
				ezApprovalGDAO.updateHesongReceiptInfo(map);
				
				int tempReceiveSN = Integer.parseInt(pReceiveSN) + 1;
				
				map.put("v_MAXSN", pReceiveSN);
				map.put("v_DEPTID", docXML.getElementsByTagName("WRITERDEPTID").item(0).getTextContent());
				map.put("v_DEPTNAME", docXML.getElementsByTagName("WRITERDEPTNAME").item(0).getTextContent());
				map.put("v_DEPTNAME2", docXML.getElementsByTagName("WRITERDEPTNAME2").item(0).getTextContent());
				map.put("v_APRSTATE", staASWheSong);
				map.put("v_TEMPSN", tempReceiveSN);
				
				ezApprovalGDAO.insertHesongReceiptInfo(map);
			} else {
				map.put("companyID", pOrgCompanyID);
				//다른 회사임
				result = doSendHesongDoc(docID, dirPath, companyID, pOrgCompanyID, tenantID, ezCommonService.getTenantConfig("ApprovalFlag", userInfo.getTenantId()));

				if (result.toUpperCase().equals("FALSE")){
					rtnVal = false;
				}
			}
			
			if (rtnVal) {
				map.put("v_PDOCID", pOrgDocID);
				map.put("v_PDEPTID", pDeptID);

                /* 2024-06-20 김유진 - 문서과로 저장한 부서의 문서를 처리할 경우, 해당 부서ID로 설정  */
                if ("G".equals(approvalFlag) && companyID.equals(pOrgCompanyID)){
                    Map<String, Object> map3 = new HashMap<String, Object>();
                    map3.put("v_DOCID", docID);
                    map3.put("companyID", companyID);
                    map3.put("v_TENANTID", tenantID);
                    map3.put("v_RECEIVESN", pReceiveSN);
                    ApprGReceiveDocVO  receivedDeptinfo = ezApprovalGDAO.getReceiptProInfo(map3);
                    String receivedDeptId = receivedDeptinfo.getReceivedDeptID();
                    if (!pDeptID.equals(receivedDeptId)) {
                        String[] manageDeptArray = getDocManageDeptInfo(pDeptID, tenantID).replace("'", "").split(",\\s*");
                        if (Arrays.asList(manageDeptArray).stream()
                                .anyMatch(deptId -> deptId.equalsIgnoreCase(receivedDeptId))) {
                            pDeptID = receivedDeptId;
                            map.put("v_PDEPTID", pDeptID);
                        }
                    }
                }

				List<ApprGDocListVO> aprTypeList = ezApprovalGDAO.doHabyuiHesongTypeS(map);
				String aprType = aprTypeList.get(0).getAprType();
				
				if (aprType.equals(staATBuSeuSoonChaHyubJo) || aprType.equals(staATGamSaBu)) {
                    result = doBansong(pOrgDocID, docID, pDeptID,  staASWheSong, dirPath, pDeptID, pOrgCompanyID, lang, userInfo, curDocNum, "");//2011.03.28 개인병렬합의시 대리결재자가 반송시 대리결재자 정보 추가
					if (result.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					}
				} else if(aprType.equals(staATBuSeuByungRyulHyubJo)) {
					// 부서병렬합의에서 회송일 경우, 결재선에서 합의부서 상태값을 015로 넣어주기 위해 추가. 추후 else를 이걸로 수정해도 될듯. 2019-03-05 홍대표
					result = doApprove(pOrgDocID, pDeptID, staASWheSong, ezOrganService.getPropertyValue(pDeptID, "DisplayName", tenantID), ezOrganService.getPropertyValue(pDeptID, "DisplayName2", tenantID), dirPath, pDeptID, "", pOrgCompanyID, lang, userInfo, curDocNum, "", "", "", "");
					sendNoti(pOrgDocID, userInfo.getId(), userInfo.getDisplayName(), "", "", "", "HESONG", pOrgCompanyID, userInfo.getLang(), userInfo.getTenantId());

					if (result.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					}
				} else {
					// 표준모듈 (2007.05.07) : 다국어
					result = doApprove(pOrgDocID, "", staASWheSong, ezOrganService.getPropertyValue(pDeptID, "DisplayName", tenantID), ezOrganService.getPropertyValue(pDeptID, "DisplayName2", tenantID), dirPath, pDeptID, "", pOrgCompanyID, lang, userInfo, curDocNum, "", "", "", "");
					sendNoti(pOrgDocID, userInfo.getId(), userInfo.getDisplayName(), "", "", "", "HESONG", pOrgCompanyID, userInfo.getLang(), userInfo.getTenantId());
					
					if (result.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					}
				}
				
				if (rtnVal) {
					// 감사 유형일 때에는 updateGamsaResult를 타도록 수정. 2020-02-27 홍대표.
					if (aprType.equals(staATGamSaBu)) {
						result = updateGamsaResult(docID, companyID, pOrgDocID, pOrgCompanyID, pDeptID, ezOrganService.getPropertyValue(pDeptID, "DisplayName", tenantID) , ezOrganService.getPropertyValue(pDeptID, "DisplayName2", tenantID), "H", lang, userInfo, curDocNum);
					} else {
						result = updateHabyuiResult(docID, companyID, pOrgDocID, pOrgCompanyID, pDeptID, ezOrganService.getPropertyValue(pDeptID, "DisplayName", tenantID) , ezOrganService.getPropertyValue(pDeptID, "DisplayName2", tenantID), "H", lang, userInfo, curDocNum);
					}
					

					if (result.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					}
				}
				
				//같은 회사 일 때
				//부서합의 회송일 경우 파생된 문서정보를 삭제하도록 재수정. 2019-03-15 홍대표
				if (companyID.equals(pOrgCompanyID) && !aprType.equals(staATBuSeuSoonChaHyubJo) && !aprType.equals(staATBuSeuByungRyulHyubJo) && !aprType.equals(staATGamSaBu)) {

					map.put("v_APRSTATE1", staASWheSong);
					map.put("v_APRSTATE2", staASJinHang);
					
					ezApprovalGDAO.updateHesongLineInfo(map);
					ezApprovalGDAO.updateHesongDocInfo(map);
					
				} else {

					result = deleteDocInfo(docID, "MUST", companyID , tenantID);
					
					if (result.toUpperCase().equals("FALSE")) {
						rtnVal = false;
					}
				}
			}
		} else {
			return "<RESULT>FALSE</RESULT>";
		}
		return "<RESULT>TRUE</RESULT>";
	}
	
