	@Override
	public int lastKyulJeHabYuiYN(String docID, String flag, String companyID, int tenantId) throws Exception {
		int result = 0;
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID);
		map.put("v_TENANTID", tenantId);
		map.put("companyID" , companyID);
		map.put("v_FLAG", flag);
		
		// 마지막 결재 순번 구하기
		int lastKyulJeCnt = ezApprovalGDAO.lastKyulJeCnt(map);
		if (lastKyulJeCnt <= 0) {
			return result;
		}
		
		map.put("v_memSN", lastKyulJeCnt - 1);
		
		String lastHabYuiSN = ezApprovalGDAO.lastHabYuiSN(map);

		map.put("v_memSN", lastHabYuiSN);
		// 마지막 결재가 개인, 부서 순차 합의일 경우 aprmembersn 출력
		String lastKyulJeHabYuiYN = ezApprovalGDAO.lastKyulJeHabYuiYN(map);
		
		if (lastKyulJeHabYuiYN != null) {
			result = ezApprovalGDAO.lastKyulJeHabYuiSN(map);
		}
		
		return result;
}

	@Override
	public String startXmlConvert(String content, String defaultFontFamily, String defaultFontSize, LoginVO userInfo) throws Exception {
		logger.debug("startXmlConvert started");
		
		String strErrorMsg = "";
		try {
			//2020.09.01. 한사대 외부공문 한글 표 붙이기할때 발생하는 주석 제거
			//2020.09.10. 한사대 주석 제거 방식 때문에 전처리 내용이 사라지는 경우가 발생 하여 주석 제거 방식 수정
			content = content.replaceAll("(?m)(?s)<!--(.*)-->", "");
			content = content.replaceAll("﻿", "");
            content = content.replaceAll("\u200B", "").replaceAll("&ZeroWidthSpace;", "");
            
			// 2020-01-12 정주환 태그내 " -> ' 로 처리
			String[] sp1 = content.split("<");
			content = "";
			for (int i = 0; i < sp1.length; i++){
				if(i == 0) {
					content += sp1[i];
					continue;
				}
				String[] sp2 = sp1[i].split(">");
				content += "<";
				content += sp2[0].replaceAll("\\\\\"", "'") + ">";
				if(sp2.length > 1) content += sp2[1] ;
			}
 			content = beforeXmlConverter(content);

 			sp1 = content.split("<");
 			content = "";
 			for (int i = 0; i < sp1.length; i++){
 				if(i == 0) {
 					content += sp1[i];
 					continue;
 				}
 				String[] sp2 = sp1[i].split(">");
 				content += "<";
 				content += sp2[0].replaceAll("\"", "'") + ">";
 				if(sp2.length > 1) content += sp2[1] ;
 			}

 		    // 전체 태그 처리시 순서에 따라 꼬이는 부분이 존재하기 때문에 선처리가 필요한 태그들에 대해 먼저 처리한다.
 		    // SPAN태그는 제거한다.(font-weight:bold > <B>, font-style:italic > <i>, text-decoration:underline > <u>)
			org.jsoup.nodes.Document doc = Jsoup.parse(content);

			int tagsWithClasses = doc.getElementsByAttribute("class").size();
			for (int i = 0; i < tagsWithClasses; i++) {
				doc.getElementsByAttribute("class").get(0).removeAttr("class");
			}

            // body 바로 아래의 연속된 span태그들을 그룹화 작업. <span>을 <p>로 변경 시 의도하지 않은 줄바꿈 처리 없앰.
            Element body = doc.body();
            int index = 0;
            Elements children = body.children();

            int maxCnt = 0;

            while (index < children.size() && maxCnt < 1000) { //무한 반복 방지.
                Element current = children.get(index);

                if (current.tagName().equals("span")) {
                    int start = index;

                    // 연속된 span 찾기
                    while (index + 1 < children.size() &&
                            children.get(index + 1).tagName().equals("span")) {
                        index++;
                    }

                    int end = index;

                    if (end > start) {
                        Element wrapper = new Element("span");

                        // 감쌀 span들을 미리 복사
                        List<Element> spansToWrap = new ArrayList<>();
                        for (int k = start; k <= end; k++) {
                            spansToWrap.add(children.get(k));
                        }

                        // 감쌀 span들을 제거하고 wrapper에 추가
                        for (Element span : spansToWrap) {
                            span.remove();
                            wrapper.appendChild(span);
                        }

                        // wrapper를 body에 삽입
                        body.insertChildren(start, wrapper);

                        // DOM 구조 갱신
                        children = body.children();
                        index = start;
                    } else {
                        index++;
                    }
                } else {
                    index++;
                }
                maxCnt++;
            }
			
			// String style = "";
			
			logger.debug("span tag parsing started");
			
			StringBuilder htmlStyle = new StringBuilder();
            int spanCnt = doc.getElementsByTag("span").size();
			for (int i=0; i < spanCnt; i++) {
				String strInnerHtml = doc.getElementsByTag("span").get(i).html();
                String fontFamily = "";
                String fontSize = "";
                String strStyle = "";
                boolean unwrapSpanFlag = false; // span안에 span안에 span 구조인 경우에 상위 p태그에 속성 이식 후 span을 제거해버림.
				if (doc.getElementsByTag("span").get(i).hasAttr("style")) {
						
					String spanStyle = doc.getElementsByTag("span").get(i).attr("style").toString();
					if(!spanStyle.endsWith(";")){
						spanStyle += ";";
					}
					
					if (spanStyle.indexOf("font-weight") > -1 && findStyleValue("font-weight", spanStyle).equals("bold")) {
						strInnerHtml = "<b>" + strInnerHtml + "</b>";
					}
					
					if (spanStyle.indexOf("font-style") > -1 && findStyleValue("font-style", spanStyle).equals("italic")) {
						strInnerHtml = "<i>" + strInnerHtml + "</i>";
					}
					
					if (spanStyle.indexOf("text-decoration") > -1 && findStyleValue("text-decoration", spanStyle).equals("underline")) {
						strInnerHtml = "<u>" + strInnerHtml + "</u>";
					}
					
					if (spanStyle.indexOf("font-family") > -1) {
						fontFamily = spanStyle.substring(spanStyle.indexOf("font-family"), spanStyle.indexOf(";",spanStyle.indexOf("font-family"))+1);
					}
					
					if (spanStyle.indexOf("font-size") > -1) {
						fontSize = spanStyle.substring(spanStyle.indexOf("font-size"), spanStyle.indexOf(";",spanStyle.indexOf("font-size"))+1);
					}
				}
			    // body 바로 밑에 span이 존재할 경우 P태그로 감싸준다.
				// 2023-05-23 이사라 : 시큐어코딩 문자열 비교 오류 수정
                if (doc.getElementsByTag("span").get(i).parent().tagName().toLowerCase().equals("body")) {
                    if (StringUtils.isNotBlank(fontFamily)) {
                        strStyle = fontFamily;
                    }

                    if (StringUtils.isNotBlank(fontSize)) {
                        strStyle += fontSize;
                    }

                    if (StringUtils.isNotBlank(strStyle)) {
                        Element pTag = doc.createElement("p");
                        pTag.attr("style", strStyle);
                        pTag.html(strInnerHtml);

                        strInnerHtml = pTag.outerHtml();
                    } else {
                        strInnerHtml = "<p>" + strInnerHtml + "</p>";
                    }
                } else if (doc.getElementsByTag("span").get(i).parent().tagName().toLowerCase().equals("p")) {
                	String spanStyle = doc.getElementsByTag("span").get(i).attr("style").toString();
                	if(!spanStyle.endsWith(";")){
                		spanStyle += ";";
                	}
                	String parentStyle = doc.getElementsByTag("span").get(i).parent().attr("style").toString();
                	
                	

                    // 상위태그가 P태그일 경우 P태그의 innerText와 span의 innerText가 동일할 경우 span의 Style을 P태그의 style로 입력한다.
                	if (doc.getElementsByTag("span").get(i).parent().text() != null && !doc.getElementsByTag("span").get(i).parent().text().equals("") 
                    		&& doc.getElementsByTag("span").get(i).text() != null && !doc.getElementsByTag("span").get(i).text().equals("")) {
                    	// 동작하지 않는 조건문 주석처리 함.
                        // if (doc.getElementsByTag("span").get(i).parent().text().trim().equals(doc.getElementsByTag("span").get(i).text().trim())) {
                        if (doc.getElementsByTag("span").get(i).parent().nodeName().equals("p")) {
                        	if (spanStyle.indexOf("font-family") > -1) {
                        		if (parentStyle.indexOf("font-family") > -1) {
                        			parentStyle = replaceStyleValue(parentStyle, fontFamily, "font-family");
                        		} else {
                        			htmlStyle.append(spanStyle.substring(spanStyle.indexOf("font-family"), spanStyle.indexOf(";", spanStyle.indexOf("font-family")) + 1));
                        		}
        					}

                            if (spanStyle.indexOf("font-size") > -1) {
                        		if (parentStyle.indexOf("font-size") > -1) {
                        			parentStyle = replaceStyleValue(parentStyle, fontSize, "font-size");
                                } else {
                        			htmlStyle.append(spanStyle.substring(spanStyle.indexOf("font-size"), spanStyle.indexOf(";", spanStyle.indexOf("font-size")) + 1));
                        		}
                            }

                            if (spanStyle.indexOf("line-height") > -1) {
                            	if (parentStyle.indexOf("line-height") > -1) {
                            		String lineHeight = spanStyle.substring(spanStyle.indexOf("line-height"), spanStyle.indexOf(";", spanStyle.indexOf("line-height"))+1);
                            		parentStyle = replaceStyleValue(parentStyle, lineHeight, "line-height");
                                } else {
                                	htmlStyle.append(spanStyle.substring(spanStyle.indexOf("font-size"), spanStyle.indexOf(";", spanStyle.indexOf("font-size")) + 1));
                                }
                            }
                            
                            htmlStyle.append(parentStyle);
                            
                            if(!htmlStyle.toString().equals("")) {
                            	doc.getElementsByTag("span").get(i).parentNode().attr("style", htmlStyle.toString());
                            }
    						htmlStyle.setLength(0);
                            unwrapSpanFlag = true;
                        }
                    }
                }
                doc.getElementsByTag("span").get(i).html(strInnerHtml);
                if (unwrapSpanFlag) {
                    doc.getElementsByTag("span").get(i).unwrap();
                    i--;
                    spanCnt--;
                }
			}
			
		    //span 태그 제거
			doc.getElementsByTag("span").unwrap();
		    
			logger.debug("span tag parsing ended");
			
			logger.debug("br tag parsing started");
			boolean hasBRTag = true;
			int rptCnt = 1000;
			
			do {
 				if(doc.getElementsByTag("br").size() > 0) {
					Element brElement = doc.getElementsByTag("br").get(0);
					Element brParentEl = brElement.parent();
					
					if (brParentEl.html() != null) {
						if (brParentEl.tagName().toLowerCase().equals("p")) {
							if (brParentEl.html().toUpperCase().indexOf("<BR>") > -1 ) {
								
								String stringSeparators ="<br>";
								String[] result = brParentEl.html().split(stringSeparators);
								
								   boolean bAllEmpty = true;
		                             // String InnerHTML = "";
		                             for (int i = 0; i < result.length; i++) {
		                                 if (result[i] != null && !result[i].equals("")) {
		                                     bAllEmpty = false;
		                                 }
		                             }

		                             int lastItem = result.length;
		                             int itemCnt = 0;
		                             for (int j = 0; j < result.length; j++) {
		                                 if (!bAllEmpty) {
		                                     if (result[j] == null || result[j].equals("")) {
		                                         if (itemCnt != (lastItem - 1)) {
		                                        	 brParentEl.html("&nbsp;");
		                                        	 brParentEl.before(brParentEl.outerHtml());
		                                         } else {
		                                             // p태그 내부에 BR태그가 존재하고 그 뒤에 아무런 문구가 없다면 줄바꿈 시키지 않는다.
		                                         }
		                                     } else {
		                             			org.jsoup.nodes.Document doc2 = Jsoup.parse(brParentEl.outerHtml());
		                             			doc2.getElementsByTag("body").get(0).children().html(result[j]);
		                                    	 brParentEl.before(doc2.getElementsByTag("body").get(0).children().outerHtml());
		                                     }
		                                 } else {
		                                     bAllEmpty = false;
		                                 }

		                                 itemCnt++;
		                             }
		                             
		                           //쿠쿠닥스 에디터에서 문장안에 br 태그가 들어가는 경우는 없어 <p><br></p>는 비어있는 라인으로 처리함. 2020-05-20 홍대표.
		                             brParentEl.html("&nbsp;");
//		                             if(brParentEl.parent().tagName().toLowerCase().equals("td")) {
//		                            	 brParentEl.html("&nbsp;");
//		                             } else {
//		                            	 brParentEl.remove();
//		                             }
								} else {
									// br 태그에 스타일이 들어가는 오류 수정. 2020-01-31 홍대표.
									String fixedBrEl = brParentEl.html().replaceAll("<br[\\s\\w]+.+?>", "<br>");
									brParentEl.html(fixedBrEl);
								}
							} else {
								// 상위태그가 P태그가 아니라면 P태그를 붙여서 줄바꿈한다.
                                if (brParentEl.html().toUpperCase().indexOf("<BR>") > -1)
                                {
                                	String stringSeparators ="<br>";
    								String[] result = brParentEl.html().split(stringSeparators);

                                    // br이 포함되었으나 아무 문구가 없는 경우 (ex. <p><br><p>) 화면상에는 한줄 줄바꿈이기 때문에 
                                    // br태그 앞뒤로 모두 비어있을 경우 한칸은 줄바꿈에서 제외한다.
    								 @SuppressWarnings("unused")
									boolean bAllEmpty = true;
		                             // String InnerHTML = "";
		                             for (int i = 0; i < result.length; i++) {
		                                 if (result[i] != null && !result[i].equals("")) {
		                                     bAllEmpty = false;
		                                 }
		                             }
                                
		                             //쿠쿠닥스 에디터에서 문장안에 br 태그가 들어가는 경우는 없어 <p><br></p>는 비어있는 라인으로 처리함. 2020-05-20 홍대표.
		                             brParentEl.html("&nbsp;");
                                    for (int m = 0; m < result.length; m++) {
                                        if (!bAllEmpty) {
                                            if (result[m] == null && result[m].equals("")) {
                                            	brParentEl.append("<p>&nbsp;</p>");
                                            } else {
                                            	brParentEl.append("<p>" + result[m] + "</p>");
                                            }
                                        } else {
                                            bAllEmpty = false;
                                        }
                                    }
                                }
							}
						}
				} else {
					hasBRTag = false;
				}
 				rptCnt--;
			} while(hasBRTag && rptCnt > 0);
			
			if (rptCnt == 0) {
				return "<DATA><RESULT>FALSE</RESULT><CONTENT><![CDATA[" + messageSource.getMessage("ezApprovalG.t217", userInfo.getLocale()) + "]]></CONTENT></DATA>";
			}
			
			logger.debug("br tag parsing ended");
			
			logger.debug("style tag parsing started");
			
			Elements strongElem = doc.getElementsByTag("strong");
			for (int k = 0; k < strongElem.size(); k++) {
				Element el = doc.createElement("B");
				el.html(strongElem.get(k).html());
				strongElem.get(k).replaceWith(el);
			}
			
			Elements emElem = doc.getElementsByTag("em");
			for (int k = 0; k < emElem.size(); k++) {
				Element el = doc.createElement("i");
				el.html(emElem.get(k).html());
				emElem.get(k).replaceWith(el);
			}
			
			for (int k = 0; k < doc.getElementsByTag("li").size(); k++) {
				String outerHtmlContent = doc.getElementsByTag("li").get(k).outerHtml();
				
				if (!outerHtmlContent.substring(outerHtmlContent.length() - 2, outerHtmlContent.length()).equals("/>") && !outerHtmlContent.toUpperCase().substring(outerHtmlContent.lastIndexOf("<")).equals("</LI>")) {
					doc.getElementsByTag("li").get(k).html(doc.getElementsByTag("li").get(k).outerHtml() + "</LI>");
				}
			}
			
			for (int k = 0; k < doc.getElementsByTag("menu").size(); k++) {
				Element el = doc.createElement("ul");
				el.text(doc.getElementsByTag("menu").get(k).html());
				doc.getElementsByTag("menu").get(k).replaceWith(el);
			}
			
			for (int k = 0; k < doc.getElementsByTag("h1").size(); k++) {
				doc.getElementsByTag("h1").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h1").get(k), "h1"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h2").size(); k++) {
				doc.getElementsByTag("h2").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h2").get(k), "h2"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h3").size(); k++) {
				doc.getElementsByTag("h3").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h3").get(k), "h3"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h4").size(); k++) {
				doc.getElementsByTag("h4").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h4").get(k), "h4"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h5").size(); k++) {
				doc.getElementsByTag("h5").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h5").get(k), "h5"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h6").size(); k++) {
				doc.getElementsByTag("h6").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h6").get(k), "h6"));
			}
			
			logger.debug("style tag parsing ended");
			
			logger.debug("table tag parsing started");
			
			for (int k = 0; k < doc.getElementsByTag("table").size(); k++) {
				Element tableElement = doc.getElementsByTag("table").get(k);
				String tableStyle = tableElement.attr("style");
				if (!tableElement.hasAttr("border")) {
					tableElement.attr("border","1");
				}

                if (tableElement.hasAttr("border") &&
                        "0".equals(tableElement.attr("border").trim())) {
                    tableElement.attr("border", "1");
                }
                
				if (!tableElement.hasAttr("cellspacing")) {
					tableElement.attr("cellspacing","0");
				}
				
				if (!tableElement.hasAttr("cellpadding")) {
					tableElement.attr("cellpadding","0");
				}
				
//				if (tableStyle.indexOf("border-collapse") > 0) {
//					System.out.println(tableStyle.substring(tableStyle.indexOf("border-collapse"), tableStyle.indexOf(";", tableStyle.indexOf("border-collapse")) + 1));
//					tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("border-collapse"), tableStyle.indexOf(";", tableStyle.indexOf("border-collapse")) + 1), "");
//				}
                
				tableStyle = " " + tableStyle;
                tableStyle = tableStyle.replaceAll("WIDTH", "width");
                tableStyle = tableStyle.replaceAll("HEIGHT", "height");
                
				if (!tableElement.hasAttr("width")) {
					if (tableStyle.contains(" width")) {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf(" width"), tableStyle.indexOf(";", tableStyle.indexOf(" width"))).split(":")[1] );
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf(" width"), tableStyle.indexOf(";", tableStyle.indexOf(" width"))), "");
						tableElement.attr("style", tableStyle);
					} 
				} else {
					if (tableStyle.indexOf(" width") > -1) {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf(" width"), tableStyle.indexOf(";", tableStyle.indexOf(" width"))).split(":")[1] );
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf(" width"), tableStyle.indexOf(";", tableStyle.indexOf(" width"))), "");
						tableElement.attr("style", tableStyle);
					} else {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf(" width"), tableStyle.indexOf(";", tableStyle.indexOf(" width"))).split(":")[1]);
					}
					tableElement.removeAttr("width");
				}
				
				if (!tableElement.hasAttr("height")) {
					if (tableStyle.indexOf("height") > -1) {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height"))).split(":")[1]);
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height"))), "");
						tableElement.attr("style", tableStyle);
					} 
				} else {
					if (tableStyle.indexOf("height") > -1) {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height"))).split(":")[1]);
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height"))), "");
						tableElement.attr("style", tableStyle);
					} else {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height"))).split(":")[1]);
					}
					tableElement.removeAttr("height");
				}
				
				if (tableElement.hasAttr("style")) {
					tableElement.removeAttr("style");
				}
				
				if (tableElement.hasAttr("align")) {
					switch (tableElement.attr("align").toString()) {
					case "left":
                    case "center":
                    case "right":
                    case "adjust":
                        break;
					default:
						tableElement.attr("align", "adjust");
						break;
					}
				}
			}
			
			logger.debug("table tag parsing ended");

			logger.debug("th tag parsing started");
            
			for (int k = 0; k < doc.getElementsByTag("th").size(); k++) {
				Element thElement = doc.getElementsByTag("th").get(k);
				String thStyle = thElement.attr("style");
				if (thElement.hasAttr("align")) {
					switch (thElement.attr("align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "adjust":
                        break;
					default:
						thElement.attr("align", "adjust");
						break;
					}
				}
				
				if (thElement.hasAttr("text-align")) {
					switch (thElement.attr("text-align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "justify":
                    case "char":
                    	thElement.attr("align", thElement.attr("text-align"));
                    	break;
					default:
						thElement.attr("align", "justify");
						break;
					}
				}
				
				if (thElement.hasAttr("valign")) {
					switch (thElement.attr("valign").toLowerCase()) {
					case "top":
                    case "middle":
                    case "bottom":
                    case "baseline":
                        break;
					default:
						thElement.attr("valign", "baseline");
						break;
					}
				}
				
				thStyle = " " + thStyle;
                thStyle = thStyle.replaceAll("WIDTH", "width");
                thStyle = thStyle.replaceAll("HEIGHT", "height");
 
				if (!thElement.hasAttr("width")) {
					if (thStyle.indexOf(" width") > -1) {
						thElement.attr("width_kaoni", SizeConvertToMM(thStyle.substring(thStyle.indexOf(" width"), thStyle.indexOf(";", thStyle.indexOf(" width")))));
						thStyle.replace(thStyle.substring(thStyle.indexOf(" width"), thStyle.indexOf(";", thStyle.indexOf(" width"))), "");
						thElement.attr("style", thStyle);
					} 
				} else {
					if (thStyle.indexOf(" width") > -1) {
						thElement.attr("width_kaoni", SizeConvertToMM(thStyle.substring(thStyle.indexOf(" width"), thStyle.indexOf(";", thStyle.indexOf(" width")))));
						thStyle.replace(thStyle.substring(thStyle.indexOf(" width"), thStyle.indexOf(";", thStyle.indexOf(" width"))), "");
						thElement.attr("style", thStyle);
					} else {
						thElement.attr("width_kaoni", SizeConvertToMM(thElement.attr("width").trim()));
					}
					thElement.removeAttr("width");
				}
				
				if (!thElement.hasAttr("height")) {
					if (thStyle.indexOf("height") > 0) {
						thElement.attr("height_kaoni", SizeConvertToMM(thStyle.substring(thStyle.indexOf("height"), thStyle.indexOf(";", thStyle.indexOf("height")))));
						thStyle.replace(thStyle.substring(thStyle.indexOf("height"), thStyle.indexOf(";", thStyle.indexOf("height"))), "");
						thElement.attr("style", thStyle);
					} 
				} else {
					if (thStyle.indexOf("height") > 0) {
						thElement.attr("height_kaoni", SizeConvertToMM(thStyle.substring(thStyle.indexOf("height"), thStyle.indexOf(";", thStyle.indexOf("height")))));
						thStyle.replace(thStyle.substring(thStyle.indexOf("height"), thStyle.indexOf(";", thStyle.indexOf("height"))), "");
						thElement.attr("style", thStyle);
					} else {
						thElement.attr("height_kaoni", SizeConvertToMM(thElement.attr("height").trim()));
					}
					thElement.removeAttr("height");
				}
				
				if (thElement.hasAttr("style")) {
					thElement.removeAttr("style");
				}
				
			}

			logger.debug("th tag parsing ended");
            
			logger.debug("td tag parsing started");
			
			for (int k = 0; k < doc.getElementsByTag("td").size(); k++) {
				Element tdElement = doc.getElementsByTag("td").get(k);
				String tdStyle = tdElement.attr("style");
				if (tdElement.hasAttr("align")) {
					switch (tdElement.attr("align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "adjust":
                        break;
					default:
						tdElement.attr("align", "adjust");
						break;
					}
				}
				
				if (tdElement.hasAttr("text-align")) {
					switch (tdElement.attr("text-align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "justify":
                    case "char":
                    	tdElement.attr("align", tdElement.attr("text-align"));
                    	break;
					default:
						tdElement.attr("align", "justify");
						break;
					}
				}
				
				if (tdElement.hasAttr("valign")) {
					switch (tdElement.attr("valign").toLowerCase()) {
					case "top":
                    case "middle":
                    case "bottom":
                    case "baseline":
                        break;
					default:
						tdElement.attr("valign", "baseline");
						break;
					}
				}
				
				tdStyle = " " + tdStyle;
				tdStyle = tdStyle.replaceAll("WIDTH", "width");
                tdStyle = tdStyle.replaceAll("HEIGHT", "height");

				if (!tdElement.hasAttr("width")) {
					if (tdStyle.indexOf(" width") > -1) {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf(" width"), tdStyle.indexOf(";", tdStyle.indexOf(" width")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf(" width"), tdStyle.indexOf(";", tdStyle.indexOf(" width"))), "");
						tdElement.attr("style", tdStyle);
					} 
				} else {
					if (tdStyle.indexOf(" width") > -1) {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf(" width"), tdStyle.indexOf(";", tdStyle.indexOf(" width")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf(" width"), tdStyle.indexOf(";", tdStyle.indexOf(" width"))), "");
						tdElement.attr("style", tdStyle);
					} else {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdElement.attr("width").trim()));
					}
					tdElement.removeAttr("width");
				}
				
				if (!tdElement.hasAttr("height")) {
					if (tdStyle.indexOf("height") > 0) {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height"))), "");
						tdElement.attr("style", tdStyle);
					} 
				} else {
					if (tdStyle.indexOf("height") > 0) {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height"))), "");
						tdElement.attr("style", tdStyle);
					} else {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdElement.attr("height").trim()));
					}
					tdElement.removeAttr("height");
				}
				
				if (tdElement.hasAttr("style")) {
					tdElement.removeAttr("style");
				}
				
			}

			logger.debug("td tag parsing ended");
			
			String strRtnHtml = doc.getElementsByTag("body").get(0).outerHtml();
			strRtnHtml = strRtnHtml.substring(0, strRtnHtml.lastIndexOf(">") + 1);

			//정주환
			sp1 = strRtnHtml.split("<");
			strRtnHtml = "";
			for (int i = 0; i < sp1.length; i++){
				if(i == 0) {
					strRtnHtml += sp1[i];
					continue;
				}
				String[] sp2 = sp1[i].split(">");
				strRtnHtml += "<";
				strRtnHtml += sp2[0].replaceAll("\"", "'") + ">";
				if(sp2.length > 1) strRtnHtml += sp2[1] ;
			}
			
			String strRtnContent = "<DATA>" +
		                "<RESULT>OK</RESULT>" +
		                "<CONTENT><![CDATA[" + strRtnHtml + "]]></CONTENT>" +
		                "</DATA>";
			//strong 태그를 b태그로 변경
			
			logger.debug("startXmlConvert ended");
			return strRtnContent;
		} catch (Exception e) {
/*			System.out.println(e.getMessage());
			System.out.println(e.getStackTrace());*/
			logger.error(e.getMessage(), e);
			strErrorMsg = "Content 전처리 진행중 오류가 발생했습니다.";
			return ReturnErrorContent(strErrorMsg);
		}
	}
	
	@Override
	public String startXmlConvertHwp(String content, String defaultFontFamily, String defaultFontSize, LoginVO userInfo) throws Exception {
		logger.debug("startXmlConvertHWP started");
		
		String strErrorMsg = "";
		try {
// 			content = beforeXmlConverter("<CONTENT>" + "<body style='font-family:굴림; font-Size:10px; font-style:oblique; font-weight:bolder; text-align:left; text-indent:50px; text-decoration: line-through;'><br/>ffff<br/>aaaa<div style='font-family:굴림; font-Size:10px; font-style:oblique; font-weight:bolder; text-align:left; text-indent:50px; text-decoration: line-through;'>dd</div><p><span style='font-weight:bold; font-style:italic; font-Size:10000px;'>dddd</span></p></body>" + "</CONTENT>");
// 			content = beforeXmlConverter("<body style='font-family:굴림; font-size:10px; font-style:oblique; font-weight:bolder; text-align:left; text-indent:50px; text-decoration: line-through;'>aaaa<div style='font-family:굴림; font-size:10px; font-style:oblique; font-weight:bolder;'><div>ccc</div></div> <div><div style='font-family:굴림; font-weight:bolder;'>eeeeeee</div>fffff</div>bbb</body>");
// 			content = beforeXmlConverter("<div  style='font-family:굴림; font-size:10px; font-style:oblique; font-weight:bolder; text-align:left; text-indent:50px; text-decoration: line-through;'><div>aaa</div>bbb</div>");
			content = content.replace("\"", "");
 			content = beforeXmlConverter(content);

 		    // 전체 태그 처리시 순서에 따라 꼬이는 부분이 존재하기 때문에 선처리가 필요한 태그들에 대해 먼저 처리한다.
 		    // SPAN태그는 제거한다.(font-weight:bold > <B>, font-style:italic > <i>, text-decoration:underline > <u>)
			org.jsoup.nodes.Document doc = Jsoup.parse(content);

			int tagsWithClasses = doc.getElementsByAttribute("class").size();
			for (int i = 0; i < tagsWithClasses; i++) {
				doc.getElementsByAttribute("class").get(0).removeAttr("class");
			}
			
			String fontFamily = "";
			String fontSize = "";
			String strStyle = "";
			// String style = "";
			
			logger.debug("span tag parsing started");
			
			StringBuilder htmlStyle = new StringBuilder();
			for (int i=0; i < doc.getElementsByTag("span").size(); i++) {
				String strInnerHtml = doc.getElementsByTag("span").get(i).html();
				
				if (doc.getElementsByTag("span").get(i).hasAttr("style")) {
						
					String spanStyle = doc.getElementsByTag("span").get(i).attr("style").toString();
					if(!spanStyle.endsWith(";")){
						spanStyle += ";";
					}
					
					if (spanStyle.indexOf("font-weight") > -1) {
						if (spanStyle.substring(spanStyle.indexOf("font-weight"), spanStyle.indexOf(";",spanStyle.indexOf("font-weight"))+1).substring(spanStyle.substring(spanStyle.indexOf("font-weight"), spanStyle.indexOf(";",spanStyle.indexOf("font-weight"))+1).indexOf(":")+1, spanStyle.substring(spanStyle.indexOf("font-weight"), spanStyle.indexOf(";",spanStyle.indexOf("font-weight"))+1).indexOf(";")).equals("bold")) {
							strInnerHtml = "<b>" + strInnerHtml + "</b>";
						}
					}
					
					if (spanStyle.indexOf("font-style") > -1) {
						if (spanStyle.substring(spanStyle.indexOf("font-style"), spanStyle.indexOf(";",spanStyle.indexOf("font-style"))+1).substring(spanStyle.substring(spanStyle.indexOf("font-style"), spanStyle.indexOf(";",spanStyle.indexOf("font-style"))+1).indexOf(":")+1, spanStyle.substring(spanStyle.indexOf("font-style"), spanStyle.indexOf(";",spanStyle.indexOf("font-style"))+1).indexOf(";")).equals("italic")) {
							strInnerHtml = "<i>" + strInnerHtml + "</i>";
						}
					}
					
					if (spanStyle.indexOf("text-decoration") > -1) {
						if (spanStyle.substring(spanStyle.indexOf("text-decoration"), spanStyle.indexOf(";",spanStyle.indexOf("text-decoration"))+1).substring(spanStyle.substring(spanStyle.indexOf("text-decoration"), spanStyle.indexOf(";",spanStyle.indexOf("text-decoration"))+1).indexOf(":")+1, spanStyle.substring(spanStyle.indexOf("text-decoration"), spanStyle.indexOf(";",spanStyle.indexOf("text-decoration"))+1).indexOf(";")).equals("underline")) {
							strInnerHtml = "<u>" + strInnerHtml + "</u>";
						}
					}
					
					if (spanStyle.indexOf("font-family") > -1) {
						fontFamily = spanStyle.substring(spanStyle.indexOf("font-family"), spanStyle.indexOf(";",spanStyle.indexOf("font-family"))+1);
					}
					
					if (spanStyle.indexOf("font-size") > -1) {
						fontSize = spanStyle.substring(spanStyle.indexOf("font-size"), spanStyle.indexOf(";",spanStyle.indexOf("font-size"))+1);
					}
				}
			    // body 바로 밑에 span이 존재할 경우 P태그로 감싸준다.
				// 2023-05-23 이사라 : 시큐어코딩 문자열 비교 오류 수정
                if (doc.getElementsByTag("span").get(i).parent().tagName().toLowerCase().equals("body")) {
                    if (StringUtils.isNotBlank(fontFamily)) {
                        strStyle = "font-family:" + fontFamily;
                    }

                    if (StringUtils.isNotBlank(fontSize)) {
                        if (StringUtils.isNotBlank(strStyle)) {
                            strStyle += ";";
                        }

                        strStyle = "font-size:" + fontSize;
                    }

                    if (StringUtils.isNotBlank(strStyle)) {
                        strInnerHtml = "<p style=\"" + strStyle + "\">" + strInnerHtml + "</p>";
                    } else {
                        strInnerHtml = "<p>" + strInnerHtml + "</p>";
                    }
                } else if (doc.getElementsByTag("span").get(i).parent().tagName().toLowerCase().equals("p")) {
                	String spanStyle = doc.getElementsByTag("span").get(i).attr("style").toString();
                	if(!spanStyle.endsWith(";")){
                		spanStyle += ";";
                	}
                	String parentSpanStyle = doc.getElementsByTag("span").get(i).parent().attr("style").toString();
                	
                	//htmlStyle.append(parentSpanStyle);

                    // 상위태그가 P태그일 경우 P태그의 innerText와 span의 innerText가 동일할 경우 span의 Style을 P태그의 style로 입력한다.
                	if (doc.getElementsByTag("span").get(i).parent().text() != null && !doc.getElementsByTag("span").get(i).parent().text().equals("") 
                    		&& doc.getElementsByTag("span").get(i).text() != null && !doc.getElementsByTag("span").get(i).text().equals("")) {
                		// 동작하지 않는 조건문 주석처리 함.
                		// if (doc.getElementsByTag("span").get(i).parent().text().trim().equals(doc.getElementsByTag("span").get(i).text().trim())) {
                        if (doc.getElementsByTag("span").get(i).parent().nodeName().equals("p")) {
                        	if (spanStyle.indexOf("font-family") > -1) {
                        		if (!(parentSpanStyle.indexOf("font-family") > -1)) {
                        			htmlStyle.append(spanStyle.substring(spanStyle.indexOf("font-family"), spanStyle.indexOf(";", spanStyle.indexOf("font-family"))+1));
                        		}
        					}

                            if (spanStyle.indexOf("font-size") > -1) {
                        		if (!(parentSpanStyle.indexOf("font-size") > -1)) {
                        			htmlStyle.append(spanStyle.substring(spanStyle.indexOf("font-size"), spanStyle.indexOf(";", spanStyle.indexOf("font-size"))+1));
                                }
                            }

                            if (spanStyle.indexOf("line-height") > -1) {
                            	if (!(parentSpanStyle.indexOf("line-height") >   -1)) {
                        			htmlStyle.append(spanStyle.substring(spanStyle.indexOf("line-height"), spanStyle.indexOf(";", spanStyle.indexOf("line-height"))+1));
                                }
                            }
                            
                            htmlStyle.append(parentSpanStyle);
                            
                            if(!htmlStyle.toString().equals("")) {
                            	doc.getElementsByTag("span").get(i).parentNode().attr("style",htmlStyle.toString());
                            }
    						htmlStyle.setLength(0);
                        }
                    }
                }
                doc.getElementsByTag("span").get(i).html(strInnerHtml);
			}
			
		    //span 태그 제거
			doc.getElementsByTag("span").unwrap();
			
			logger.debug("span tag parsing ended");
		    
			logger.debug("br tag parsing started");
			
			boolean hasBRTag = true;
			 
			do {
 				if(doc.getElementsByTag("br").size() > 0) {
					// Element strInnerHtml2 = doc.getElementsByTag("br").get(0);
					
					if (doc.getElementsByTag("br").get(0).parent().html() != null) {
						if (doc.getElementsByTag("br").get(0).parent().tagName().toLowerCase().equals("p")) {
							if (doc.getElementsByTag("br").get(0).parent().html().toUpperCase().indexOf("<BR>") > -1 ) {
								
								String stringSeparators ="<br>";
								String[] result = doc.getElementsByTag("br").get(0).parent().html().split(stringSeparators);
								
								   boolean bAllEmpty = true;
		                             // String InnerHTML = "";
		                             for (int i = 0; i < result.length; i++) {
		                                 if (result[i] != null && !result[i].equals("")) {
		                                     bAllEmpty = false;
		                                 }
		                             }

		                             int lastItem = result.length;
		                             int itemCnt = 0;
		                             for (int j = 0; j < result.length; j++) {
		                                 if (!bAllEmpty) {
		                                     if (result[j] == null || result[j].equals("")) {
		                                         if (itemCnt != (lastItem - 1)) {
		                                        	 doc.getElementsByTag("br").get(0).parent().html("&nbsp;");
		                                        	 doc.getElementsByTag("br").get(0).parent().before(doc.getElementsByTag("br").get(0).parent().outerHtml());
		                                         } else {
		                                             // p태그 내부에 BR태그가 존재하고 그 뒤에 아무런 문구가 없다면 줄바꿈 시키지 않는다.
		                                         }
		                                     } else {
		                             			org.jsoup.nodes.Document doc2 = Jsoup.parse(doc.getElementsByTag("br").get(0).parent().outerHtml());
		                             			doc2.getElementsByTag("body").get(0).children().html(result[j]);
		                                    	 doc.getElementsByTag("br").get(0).parent().before(doc2.getElementsByTag("body").get(0).children().outerHtml());
		                                     }
		                                 } else {
		                                     bAllEmpty = false;
		                                 }

		                                 itemCnt++;
		                             }
		                             doc.getElementsByTag("br").get(0).parent().remove();
								}
							} else {
								// 상위태그가 P태그가 아니라면 P태그를 붙여서 줄바꿈한다.
                                if (doc.getElementsByTag("br").get(0).parent().html().toUpperCase().indexOf("<BR>") > -1)
                                {
                                	String stringSeparators ="<BR>";
    								String[] result = doc.getElementsByTag("br").get(0).parent().html().split(stringSeparators);

                                    // br이 포함되었으나 아무 문구가 없는 경우 (ex. <p><br><p>) 화면상에는 한줄 줄바꿈이기 때문에 
                                    // br태그 앞뒤로 모두 비어있을 경우 한칸은 줄바꿈에서 제외한다.
    								 boolean bAllEmpty = true;
		                             // String InnerHTML = "";
		                             for (int i = 0; i < result.length; i++) {
		                                 if (result[i] != null && !result[i].equals("")) {
		                                     bAllEmpty = false;
		                                 }
		                             }
                                
		                             doc.getElementsByTag("br").get(0).parent().html("");
                                    for (int m = 0; m > result.length; m++) {
                                        if (!bAllEmpty) {
                                            if (result[m] == null && result[m].equals("")) {
                                            	doc.getElementsByTag("br").get(0).parent().after("<p>&nbsp;</p>");
                                            } else {
                                            	doc.getElementsByTag("br").get(0).parent().after("<p>" + result[m] + "</p>");
                                            }
                                        } else {
                                            bAllEmpty = false;
                                        }
                                    }
                                }
							}
						}
				} else {
					hasBRTag = false;
				}
			} while(hasBRTag);
			
			logger.debug("br tag parsing ended");
			
			logger.debug("style tag parsing started");
			
			for (int k = 0; k < doc.getElementsByTag("strong").size(); k++) {
				Element el = doc.createElement("B");
				el.text(doc.getElementsByTag("strong").get(k).text());
				doc.getElementsByTag("strong").get(k).replaceWith(el);
			}
			
			for (int k = 0; k < doc.getElementsByTag("em").size(); k++) {
				Element el = doc.createElement("i");
				el.text(doc.getElementsByTag("em").get(k).text());
				doc.getElementsByTag("em").get(k).replaceWith(el);
			}
			
			for (int k = 0; k < doc.getElementsByTag("li").size(); k++) {
				String outerHtmlContent = doc.getElementsByTag("li").get(k).outerHtml();
				
				if (!outerHtmlContent.substring(outerHtmlContent.length() - 2, 2).equals("/>") && !outerHtmlContent.toUpperCase().substring(outerHtmlContent.lastIndexOf("<")).equals("</LI>")) {
					doc.getElementsByTag("li").get(k).html(doc.getElementsByTag("li").get(k).outerHtml() + "</LI>");
				}
			}
			
			for (int k = 0; k < doc.getElementsByTag("menu").size(); k++) {
				Element el = doc.createElement("ul");
				el.text(doc.getElementsByTag("menu").get(k).html());
				doc.getElementsByTag("menu").get(k).replaceWith(el);
			}
			
			for (int k = 0; k < doc.getElementsByTag("h1").size(); k++) {
				doc.getElementsByTag("h1").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h1").get(k), "h1"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h2").size(); k++) {
				doc.getElementsByTag("h2").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h2").get(k), "h2"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h3").size(); k++) {
				doc.getElementsByTag("h3").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h3").get(k), "h3"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h4").size(); k++) {
				doc.getElementsByTag("h4").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h4").get(k), "h4"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h5").size(); k++) {
				doc.getElementsByTag("h5").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h5").get(k), "h5"));
			}
			
			for (int k = 0; k < doc.getElementsByTag("h6").size(); k++) {
				doc.getElementsByTag("h6").get(k).replaceWith(MakeHTagHTML(doc.getElementsByTag("h6").get(k), "h6"));
			}
			
			logger.debug("style tag parsing ended");
			
			logger.debug("table tag parsing started");
			
			for (int k = 0; k < doc.getElementsByTag("table").size(); k++) {
				Element tableElement = doc.getElementsByTag("table").get(k);
				String tableStyle = tableElement.attr("style");
				if (!tableElement.hasAttr("border")) {
					tableElement.attr("border","1");
				}
				
				if (!tableElement.hasAttr("cellspacing")) {
					tableElement.attr("cellspacing","0");
				}
				
				if (!tableElement.hasAttr("cellpadding")) {
					tableElement.attr("cellpadding","0");
				}
				
//				if (tableStyle.indexOf("border-collapse") > 0) {
//					System.out.println(tableStyle.substring(tableStyle.indexOf("border-collapse"), tableStyle.indexOf(";", tableStyle.indexOf("border-collapse")) + 1));
//					tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("border-collapse"), tableStyle.indexOf(";", tableStyle.indexOf("border-collapse")) + 1), "");
//				}
				
				if (!tableElement.hasAttr("width")) {
					if (tableStyle.contains("width")) {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf("width"), tableStyle.indexOf(";", tableStyle.indexOf("width")) + 1).split(":")[1] );
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("width"), tableStyle.indexOf(";", tableStyle.indexOf("width")) + 1), "");
						tableElement.attr("style", tableStyle);
					} 
				} else {
					if (tableStyle.indexOf("width") > -1) {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf("width"), tableStyle.indexOf(";", tableStyle.indexOf("width")) + 1).split(":")[1] );
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("width"), tableStyle.indexOf(";", tableStyle.indexOf("width")) + 1), "");
						tableElement.attr("style", tableStyle);
					} else {
						tableElement.attr("width_kaoni", tableStyle.substring(tableStyle.indexOf("width"), tableStyle.indexOf(";", tableStyle.indexOf("width")) + 1).split(":")[1]);
					}
					tableElement.attr("width", "0");
				}
				
				if (!tableElement.hasAttr("height")) {
					if (tableStyle.indexOf("height") > -1) {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height")) + 1).split(":")[1]);
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height")) + 1), "");
						tableElement.attr("style", tableStyle);
					} 
				} else {
					if (tableStyle.indexOf("height") > -1) {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height")) + 1).split(":")[1]);
						tableStyle = tableStyle.replace(tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height")) + 1), "");
						tableElement.attr("style", tableStyle);
					} else {
						tableElement.attr("height_kaoni", tableStyle.substring(tableStyle.indexOf("height"), tableStyle.indexOf(";", tableStyle.indexOf("height")) + 1).split(":")[1]);
					}
					tableElement.attr("height", "0");
				}
				
				if (tableElement.hasAttr("style")) {
					tableElement.removeAttr("style");
				}
				
				if (tableElement.hasAttr("align")) {
					switch (tableElement.attr("align").toString()) {
					case "left":
                    case "center":
                    case "right":
                    case "adjust":
                        break;
					default:
						tableElement.attr("align", "adjust");
						break;
					}
				}
			}
			
			logger.debug("table tag parsing ended");
			
			logger.debug("td tag parsing started");
			
			for (int k = 0; k < doc.getElementsByTag("td").size(); k++) {
				Element tdElement = doc.getElementsByTag("td").get(k);
				String tdStyle = tdElement.attr("style");
            	if(tdStyle != null && !tdStyle.equals("") && !tdStyle.endsWith(";")){
            		tdStyle += ";";
            	}
            	tdElement.attr("style", tdStyle);
            	
				if (tdElement.hasAttr("align")) {
					switch (tdElement.attr("align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "adjust":
                        break;
					default:
						tdElement.attr("align", "adjust");
						break;
					}
				}
				
				if (tdElement.hasAttr("text-align")) {
					switch (tdElement.attr("text-align").toLowerCase()) {
					case "left":
                    case "center":
                    case "right":
                    case "justify":
                    case "char":
                    	tdElement.attr("align", tdElement.attr("text-align"));
                    	break;
					default:
						tdElement.attr("align", "justify");
						break;
					}
				}
				
				if (tdElement.hasAttr("valign")) {
					switch (tdElement.attr("valign").toLowerCase()) {
					case "top":
                    case "middle":
                    case "bottom":
                    case "baseline":
                        break;
					default:
						tdElement.attr("valign", "baseline");
						break;
					}
				}
				
				if (!tdElement.hasAttr("width")) {
					if (tdStyle.indexOf("width") > 0) {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("width"), tdStyle.indexOf(";", tdStyle.indexOf("width")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("width"), tdStyle.indexOf(";", tdStyle.indexOf("width"))), "");
						tdElement.attr("style", tdStyle);
					} 
				} else {
					if (tdStyle.indexOf("width") > 0) {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("width"), tdStyle.indexOf(";", tdStyle.indexOf("width")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("width"), tdStyle.indexOf(";", tdStyle.indexOf("width"))), "");
						tdElement.attr("style", tdStyle);
					} else {
						tdElement.attr("width_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("width"), tdStyle.indexOf(";", tdStyle.indexOf("width")))));
					}
					tdElement.attr("width", "0");
				}
				
				if (!tdElement.hasAttr("height")) {
					if (tdStyle.indexOf("height") > 0) {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height"))), "");
						tdElement.attr("style", tdStyle);
					} 
				} else {
					if (tdStyle.indexOf("height") > 0) {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height")))));
						tdStyle.replace(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height"))), "");
						tdElement.attr("style", tdStyle);
					} else {
						tdElement.attr("height_kaoni", SizeConvertToMM(tdStyle.substring(tdStyle.indexOf("height"), tdStyle.indexOf(";", tdStyle.indexOf("height")))));
					}
					tdElement.attr("height", "0");
				}

				// td에 padding style이 있는 문서에 대해
				// td에 padding으로 들어간 값을 현재 td 아래 p요소의 margin style로 넣어주고 td의 style은 삭제
				if(tdStyle.indexOf("padding:") > -1 && tdElement.child(0).tagName().toLowerCase().equals("p")) {
					tdStyle = tdElement.attr("style");
					String pdElem = tdStyle.substring(tdStyle.indexOf("padding:")+8, tdStyle.indexOf(";", tdStyle.indexOf("padding:")));
					String tdStyleForP = "";
					String[] pdElems = pdElem.split(" ");
					for(int l=0; l<pdElems.length; l++) {
						switch(l) { 
							case 0:
								tdStyleForP += "margin-top:" + SizeConvertToMM(pdElems[l]) + ";";
								break;
							case 1:
								tdStyleForP += "margin-right:" + SizeConvertToMM(pdElems[l]) + ";";
								break;
							case 2:
								tdStyleForP += "margin-bottom:" + SizeConvertToMM(pdElems[l]) + ";";
								break;
							case 3:
								tdStyleForP += "margin-left:" + SizeConvertToMM(pdElems[l]) + ";";
								break;
						}
					}
					
					Element pElement = tdElement.child(0);
					String pStyle = pElement.attr("style");
					pElement.attr("style", pStyle + tdStyleForP);
				}
				
				if (tdElement.hasAttr("style")) {
					tdElement.removeAttr("style");
				}
				
				if (tdElement.hasAttr("bgcolor")) {
					tdElement.removeAttr("bgcolor");
				}
				
			}
			
			logger.debug("td tag parsing ended");

			String strRtnHtml = doc.getElementsByTag("body").get(0).outerHtml();
			strRtnHtml = strRtnHtml.substring(0, strRtnHtml.lastIndexOf(">") + 1);
			
			String strRtnContent = "<DATA>" +
		                "<RESULT>OK</RESULT>" +
		                "<CONTENT><![CDATA[" + strRtnHtml + "]]></CONTENT>" +
		                "</DATA>";
			//strong 태그를 b태그로 변경
			
			logger.debug("startXmlConvert ended");
			return strRtnContent;
		} catch (Exception e) {
/*			System.out.println(e.getMessage());
			System.out.println(e.getStackTrace());*/
			logger.error(e.getMessage(), e);
			strErrorMsg = "Content 전처리 진행중 오류가 발생했습니다.";
			return ReturnErrorContent(strErrorMsg);
		}
	}
	
	private String findStyleValue(String targetStyle, String styleStr) {
		Pattern p = Pattern.compile(targetStyle + ".*?:\\s*?(\\w+);");
		Matcher m = p.matcher(styleStr);
		String value = "";
		
		if(m.find()) {
			value = m.group(1);
		}
		return value;
	}
	
	private String replaceStyleValue(String fromStyleStr, String toStyleStr, String targetStyle) {
        String regex = targetStyle + ":.*?;";
        String replacedStr = fromStyleStr;
        if (fromStyleStr.matches(".*" + regex + ".*")) {
            replacedStr = fromStyleStr.replaceAll(regex, toStyleStr);
        }

        replacedStr = replacedStr.replaceAll("\\s*;\\s*", ";")  // ; 주변 공백 제거
                .replaceAll("\\s*:\\s*", ":")  // : 주변 공백 제거
                .trim();

        return replacedStr;
	}

	private String SizeConvertToMM(String pSize) {
		  String strRtnVal = "";
		  
		  Pattern pattern = Pattern.compile("[^(0-9\\-\\.)]");
			Matcher matcher = pattern.matcher(pSize);
			
        double pSizeNum = Double.parseDouble(matcher.replaceAll(""));
        if (pSize.toUpperCase().indexOf("PX") > -1)
        {
            strRtnVal = Math.round(pSizeNum * 0.264583) + "mm";
        }
        else if (pSize.toUpperCase().indexOf("PT") > -1)
        {
            strRtnVal = Math.round(pSizeNum * 0.352777) + "mm";
        }
        else if (pSize.toUpperCase().indexOf("MM") > -1)
        {
            strRtnVal = pSizeNum + "mm";
        }
        else
        {
            strRtnVal = pSize;
        }

        return strRtnVal;
	}

	private org.jsoup.nodes.Node MakeHTagHTML(Element element, String tagType) {
		org.jsoup.nodes.Document doc = Jsoup.parse("");

		Element NewElP = doc.createElement("P");
		Element NewElB = doc.createElement("B");
		
		String strInnerHtml = element.text();
		StringBuilder htmlStyle = new StringBuilder();
		
		String pStyle = element.attr("style").toString();
		if (pStyle.indexOf("font-family") > -1) {
    		htmlStyle.append(element.attr("style").toString().substring(element.attr("style").toString().indexOf("font-family"), element.attr("style").toString().indexOf(";", element.attr("style").toString().indexOf("font-family"))+1));
		} else {
			htmlStyle.append("font-family : 굴림;");
		}
		
	    switch (tagType.toLowerCase()) {
			case "h1":
				htmlStyle.append(" font-size : 24pt;");
			break;
			
			case "h2":
				htmlStyle.append(" font-size : 18pt;");
			break;
			
			case "h3":
				htmlStyle.append(" font-size : 14pt;");
			break;
			
			case "h4":
				htmlStyle.append(" font-size : 12pt;");
			break;
			
			case "h5":
				htmlStyle.append(" font-size : 10pt;");
			break;
			
			case "h6":
				htmlStyle.append(" font-size : 8pt;");
			break;
		}
	    
	    htmlStyle.append(" marginTop : 0.0000mm;");
	    htmlStyle.append(" marginBottom : 0.0000mm;");
	    
	    if (strInnerHtml == null || strInnerHtml.equals("")) {
	    	NewElB.text("&nbsp;");
	    } else {
	    	NewElB.text(strInnerHtml);
	    }
	    
	    NewElP.text(NewElB.outerHtml());
	    NewElP.attr("style",htmlStyle.toString());

		return NewElP;
	}

	private String ReturnErrorContent(String strErrorMsg) {
		String strRtnContent = "<DATA>" +
	                "<RESULT>ERROR</RESULT>" +
	                "<CONTENT><![CDATA[" + strErrorMsg + "]]></CONTENT>" +
	                "</DATA>";
	    return strRtnContent;
	}

	private String beforeXmlConverter(String content) throws Exception {
		// ==========================================================================================================================
        // DIV태그가 겹쳐있을 경우 처리.
        // ex) <td style="border: 1px solid rgb(0, 0, 0); border-image: none; height: 31px;">
        //        <div style="text-align: center; line-height: 1.2; font-size: 12pt; margin-top: 0px; margin-bottom: 0px;">
        //              <div style="font-size: 10pt;">미학과에술문화</div></div></td>
        // 위와 같은 경우 DIV제거를 위해 속성을 맞춰준다.
        // 상위/하위 Element 의 innerText가 동일하다면 Style을 맞춰준다.
        // 리턴시 div태그를 p태그로 변경하여 리턴한다.
		
		logger.debug("beforeXmlConverter started");
		
		org.jsoup.nodes.Document doc = Jsoup.parse(content);

  		StringBuilder style = new StringBuilder();
		for (int i=0; i < doc.body().getElementsByTag("body").size(); i++) {
			for (int j=0; j< doc.body().getElementsByTag("body").get(i).childNodeSize(); j++) {
				org.jsoup.nodes.Node childNode2 = doc.body().getElementsByTag("body").get(i).childNode(j);
				org.jsoup.nodes.Node parentNode = childNode2.parentNode();
				String parentNodeStyle = parentNode.attr("style");
				
				if (doc.body().getElementsByTag("body").get(i).childNode(j).nodeName().equals("#text")) {
					String parentText = doc.select(childNode2.parent().nodeName()).text();
					String tempContext = childNode2.toString().replace("\n", "").trim();
					
					if (!tempContext.equals("") && !parentText.equals(tempContext)) {
						Element el = doc.createElement("p");
						el.text(tempContext);
						
						if (parentNode.hasAttr("style")) {
							if (parentNodeStyle.indexOf("font-family") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-family"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("font-family")) + 1));
							}
							if (parentNodeStyle.toLowerCase().indexOf("font-size") > -1) {
								style.append(parentNodeStyle.toLowerCase().substring(parentNodeStyle.toLowerCase().indexOf("font-size"), parentNodeStyle.indexOf(";", parentNodeStyle.toLowerCase().indexOf("font-size")) + 1));
							}
							if (parentNodeStyle.indexOf("font-style") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-style"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("font-style")) + 1));
							}
							if (parentNodeStyle.indexOf("font-weight") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-weight"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("font-weight")) + 1));
							}
							if (parentNodeStyle.indexOf("text-align") > -1) {
								style.append(parentNodeStyle.toLowerCase().substring(parentNodeStyle.indexOf("text-align"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("text-align")) + 1));
							}
							if (parentNodeStyle.indexOf("text-indent") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("text-indent"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("text-indent")) + 1));
							}
							if (parentNodeStyle.indexOf("text-decoration") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("text-decoration"), parentNodeStyle.indexOf(";", parentNodeStyle.indexOf("text-decoration")) + 1));
							}
						}
						
						if (!"".equals(style.toString().trim())) {
							el.attr("style",style.toString());
						}
						childNode2.replaceWith(el);
						style.setLength(0);
					}
				}
			}
		}
		
		for (int i=0; i < doc.body().getElementsByTag("div").size(); i++) {
			org.jsoup.nodes.Node parentNode = doc.body().getElementsByTag("div").get(i);
			String parentNodeStyle = parentNode.attr("style");
			String parentText = doc.body().getElementsByTag("div").get(i).text();
			for (int j=0; j< parentNode.childNodeSize(); j++) {
				if (parentNode.childNode(j).nodeName().equals("#text")) {
					@SuppressWarnings("unused")
					int m =0;
					if (i == 0) {
						m = i;
					} else {
						m = i-1;
					}
					String tempContext = parentNode.childNode(j).toString().replace("\n", "");
					
					if (!tempContext.equals("") && !parentText.equals(tempContext)) {
						Element el = doc.createElement("p");
						el.text(tempContext);
						
						if (parentNode.hasAttr("style")) {
							if (parentNodeStyle.indexOf("font-family") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-family"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-family")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("font-size") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-size"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-size")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("font-style") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-style"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-style")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("font-weight") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("font-weight"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-weight")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("text-align") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("text-align"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-align")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("text-indent") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("text-indent"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-indent")) + 1) + " ");
							}
							
							if (parentNodeStyle.indexOf("text-decoration") > -1) {
								style.append(parentNodeStyle.substring(parentNodeStyle.indexOf("text-decoration"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-decoration")) + 1) + " ");
							}
						}
						
						if (style.toString().length() > 0) {
							el.attr("style",style.toString());
						}
						
						parentNode.childNode(j).replaceWith(el);
						style.setLength(0);
					}
				} else {
					org.jsoup.nodes.Node childNode = parentNode.childNode(j);
					String childNodeStyle = childNode.attr("style");
					if (childNode.childNodeSize() != 0 && childNode.childNode(0).toString() != null) {
						if (parentText.replace(" ", "").equals(childNode.childNode(0).toString().replace(" ", "").replace("\n", ""))) {
							if (childNode.hasAttr("style")) {
								if (childNodeStyle.toLowerCase().indexOf("font-family") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("font-family"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("font-family")) + 1 )) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("font-size") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("font-size"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("font-size")) + 1)) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("font-style") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("font-style"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("font-style")) + 1)) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("font-weight") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("font-weight"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("font-weight")) + 1)) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("text-align") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("text-align"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("text-align")) + 1)) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("text-indent") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("text-indent"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("text-indent")) + 1)) + " ");
								} 
								
								if (childNodeStyle.toLowerCase().indexOf("text-decoration") > -1) {
									style.append((childNodeStyle.substring(childNodeStyle.indexOf("text-decoration"), childNodeStyle.indexOf(";",childNodeStyle.indexOf("text-decoration")) + 1)) + " ");
								} 
								
								parentNode.attr("style",style.toString());
								style.setLength(0);
								
							} else {
								if (parentNode.hasAttr("style")) {
									if (parentNodeStyle.indexOf("font-family") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("font-family"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-family")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("font-Size") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("font-Size"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-Size")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("font-style") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("font-style"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-style")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("font-weight") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("font-weight"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("font-weight")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("text-align") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("text-align"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-align")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("text-indent") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("text-indent"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-indent")) + 1)) + " ");
									}
									
									if (parentNodeStyle.indexOf("text-decoration") > -1) {
										style.append((parentNodeStyle.substring(parentNodeStyle.indexOf("text-decoration"), parentNodeStyle.indexOf(";",parentNodeStyle.indexOf("text-decoration")) + 1)) + " ");
									}
									
									childNode.attr("style",style.toString());
									style.setLength(0);
								}
							}
						}
					}
				}
			}
		}

		String strRtnHTML = null;
		
		if (doc.body().childNodeSize() == 0) {
            strRtnHTML = "<p style=\"margin-top:0px;margin-bottom:0px\">" + doc.getElementsByTag("body").get(0).outerHtml() + "</p>";
		} else {
			strRtnHTML = doc.getElementsByTag("body").get(0).children().outerHtml();
		}
		
		 // 리턴시 div태그를 p태그로 변경하여 리턴한다.
        strRtnHTML = strRtnHTML.replace("<div", "<p").replace("<DIV", "<p").replace("</div", "</p").replace("</DIV", "</p");
        
        logger.debug("beforeXmlConverter ended");
        
		return strRtnHTML;
	}

	@Override
	public String getAprLineXmlForExt(String docID, LoginVO userInfo) throws Exception {
		int iAprSN;
		int iAssistSN;
		String strChkPosition;
		String strAprType;
		String strIsProposerYN;
		String strIsBriefUserYN;
		String strProcessDate;
		
		Map<String, Object> map = new HashMap<String, Object>();
		StringBuilder result = new StringBuilder();
		
		map.put("docID", docID);
		map.put("v_TENANTID", userInfo.getTenantId());
		map.put("companyID", userInfo.getCompanyID());
		
		List<ApprGAprLineVO> strLineXML = new ArrayList<ApprGAprLineVO>(); 
		strLineXML = ezApprovalGDAO.relayAprLineXmlForExt(map);
		
	    StringBuffer sb = new StringBuffer();
	        sb.append("<DATA>");
	        
	        for (int i = 0; i < strLineXML.size(); i++) {
				sb.append(commonUtil.getQueryResult(strLineXML.get(i)));
			}
			sb.append("</DATA>");
		
		Document xmlDoc = commonUtil.convertStringToDocument(sb.toString());

		int iFinalSn = xmlDoc.getElementsByTagName("ROW").getLength();
		
		result.append("<APPROVALINFO>");
		
		iAprSN = 1;
		iAssistSN = 1;
		
		for (int i = 0; i < iFinalSn; i++) {
			result.append("<APPROVAL>");
			result.append("<ORDER>");
			
			strAprType = xmlDoc.getElementsByTagName("APRTYPE").item(i).getTextContent();
			
			if (strAprType.equals(staATSoonChaHyubJo)) {
				result.append(iAssistSN);
				result.append("</ORDER>");
				iAssistSN += 1;
			} else {
				if (xmlDoc.getElementsByTagName("APRMEMBERSN").item(i).getTextContent().equals(Integer.toString(iFinalSn))) {
					result.append("final");
					result.append("</ORDER>");
					iAprSN += 1;
				} else {
					result.append(iAprSN);
					result.append("</ORDER>");
					iAprSN += 1;
				}
			}
			
			result.append("<OPINION>");
			
			if (xmlDoc.getElementsByTagName("OPINIONGB").item(i).getTextContent().isEmpty()) {
				result.append("NO");
			} else {
				result.append("YES");
			}
			
			result.append("</OPINION>");
			
			strChkPosition = "";
			strIsProposerYN = xmlDoc.getElementsByTagName("ISPROPOSERYN").item(i).getTextContent();
			strIsBriefUserYN = xmlDoc.getElementsByTagName("ISBRIEFUSERYN").item(i).getTextContent();

			if (!strIsProposerYN.isEmpty()) {
				if (strIsProposerYN.equals("Y")) {
					strChkPosition = strChkPosition + "★";
				}
			}
			
			if (!strIsBriefUserYN.isEmpty()) {
				if (strIsBriefUserYN.equals("Y")) {
					strChkPosition = strChkPosition + "⊙";
				}
			}
			
			result.append("<SIGNPOSITION>" + strChkPosition + xmlDoc.getElementsByTagName("APRMEMBERJOBTITLE").item(i).getTextContent() + "</SIGNPOSITION>");
			
			result.append("<TYPE>");
			
			if (strAprType.equals("018")) {
				result.append("상신");
			} else {
				result.append(getCode2Name("A03", strAprType, userInfo.getCompanyID(), userInfo.getLang(), userInfo.getTenantId()));
			}
			
			result.append("</TYPE>");
			
			result.append("<NAME>" + xmlDoc.getElementsByTagName("APRMEMBERNAME").item(i).getTextContent() + "</NAME>");
			
			strProcessDate = xmlDoc.getElementsByTagName("PROCESSDATE").item(i).getTextContent().substring(0,19);
			result.append("<DATE>" + strProcessDate.substring(0,10) + "</DATE>");
			
			result.append("<SIGNDATE>" + strProcessDate.substring(5,10)  + "</SIGNDATE>");
			
			result.append("<TIME>" + strProcessDate.substring(11,19)  + "</TIME>");
			result.append("</APPROVAL>");
		}
		result.append("</APPROVALINFO>");
		return result.toString();
	}

	@Override
	public String checkPubDocXML(String mapPath) throws Exception {
		String result = null;
		DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
		//문서유통 발송 시 파싱에러를 일으켜서 주석처리함. 2019-04-30 홍대표
//		factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
		factory.setValidating(false);
		factory.setNamespaceAware(true);

		DocumentBuilder builder = factory.newDocumentBuilder();

		builder.setErrorHandler(new SimpleErrorHandler());    
		// the "parse" method also validates XML, will throw an exception if misformatted
		try {
    		builder.parse(new InputSource(mapPath));
			result = "OK";
		} catch (Exception e){
			logger.error(e.getMessage(), e);
			result = "FALSE";
		} 
		return result;
	}
	
	public class SimpleErrorHandler implements ErrorHandler {
	    public void warning(SAXParseException e) throws SAXException {
	        System.out.println(e.getMessage());
	    }

	    public void error(SAXParseException e) throws SAXException {
	        System.out.println(e.getMessage());
	    }

	    public void fatalError(SAXParseException e) throws SAXException {
	        System.out.println(e.getMessage());
	    }
	}

	@Override
	public String createSendMsgXML(Document xmlDom, String mapPath, LoginVO userInfo) throws Exception {
		String strRtnXML = "";
		String strDocType = xmlDom.getElementsByTagName("doc-type").item(0).getAttributes().getNamedItem("type").getTextContent();
		String strDocID = xmlDom.getElementsByTagName("doc-id").item(0).getTextContent();
		
		int idx;
        int pos;

        String strConRole;
        String strAttachPath;
        String strAttachFile;
        String strPath;
        
		if (strDocType.equals("send") || strDocType.equals("resend")) {
			if (xmlDom.getElementsByTagName("content").getLength() > 0) {
				for (int i = 0; i < xmlDom.getElementsByTagName("content").getLength(); i++) {
					strConRole = xmlDom.getElementsByTagName("content").item(i).getAttributes().getNamedItem("content-role").getTextContent();
					
					if (!strConRole.equals("pubdoc") && !strConRole.equals("return") && !strConRole.equals("fail")) {
						idx = xmlDom.getElementsByTagName("content").item(i).getTextContent().indexOf("?filepath=");
						
						if (idx > 0) {
							xmlDom.getElementsByTagName("content").item(i).setTextContent(xmlDom.getElementsByTagName("content").item(i).getTextContent().substring(idx + 10));
						}
						
						pos = xmlDom.getElementsByTagName("content").item(i).getTextContent().lastIndexOf("/");
						strAttachPath = xmlDom.getElementsByTagName("content").item(i).getTextContent().substring(0, pos);
						strAttachFile = xmlDom.getElementsByTagName("content").item(i).getTextContent().substring(pos + 1);
						
                        strPath = strAttachPath.replace("/Upload_ApprovalG", mapPath).replace("/", commonUtil.separator) + commonUtil.separator + strAttachFile;
                        
                        // 메일 발송 여부 확인 필요
                        //CDO.IBodyPart attach = objMsg.AddAttachment(strPath, null, null);
                        //xmlDom.getElementsByTagName("content").item(i).getAttributes().getNamedItem("content-type").setNodeValue(objMsg.AddAttachment(strPath, "", "").Fields["urn:schemas:httpmail:content-media-type"].Value.ToString();

						byte[] bytes;
						File file = new File(commonUtil.detectPathTraversal(mapPath + strPath));

						// 2018.08.26 KLIB 복호화
						if (strPath.endsWith("." + EzApprovalGKlibService.ENCRYPTED_FILE_EXT)) {
							bytes = commonUtil.readBytesFromFile(file.toPath());
							bytes = klibUtil.decrypt(bytes);
						} else {
							// CWE-404 보안 취약점 대응
                    		try (InputStream is = new FileInputStream(file)) {
								long length = file.length();
								if (length > Integer.MAX_VALUE) {
									// File is too large
								}
								bytes = new byte[(int)length];
								
								int offset = 0;
								int numRead = 0;
								while (offset < bytes.length && (numRead=is.read(bytes, offset, bytes.length-offset)) >= 0) {
									offset = Math.addExact(offset, numRead);
								}
								
								if (offset < bytes.length) {
									throw new IOException("Could not completely read file "+file.getName());
								}
							}
						}
                    	    
                    		byte[] encoded = Base64.encodeBase64(bytes);
                    		String encodedString = new String(encoded);
                            
                            xmlDom.getElementsByTagName("content").item(i).setTextContent(encodedString);

    					}
                    		
				}
			}
			 strRtnXML = "<?xml version=\"1.0\" encoding=\"euc-kr\"?><!DOCTYPE pack SYSTEM \"pack.dtd\">";
	         strRtnXML = strRtnXML + commonUtil.convertDocumentToString(xmlDom).replace("&amp;", "&");
		}
		 String strFilePath = mapPath + commonUtil.getUploadPath("upload_approvalG.ROOT", userInfo.getTenantId()) + commonUtil.separator + userInfo.getCompanyID() + commonUtil.separator + "ExDocSendMsg" + commonUtil.separator + strDocID + ".xml";

		 File file = new File (commonUtil.detectPathTraversal(mapPath  + commonUtil.getUploadPath("upload_approvalG.ROOT", userInfo.getTenantId()) + commonUtil.separator + userInfo.getCompanyID() + commonUtil.separator + "ExDocSendMsg"));
		 
		 if (!file.exists()) {
			 file.mkdirs();
		 }
		 
         File FI = new File(commonUtil.detectPathTraversal(strFilePath));

         if (FI.exists()) {
        	 FI.delete();
         }
         
 		try {
			// CWE-404 보안 취약점 대응
 			try (FileOutputStream fop = new FileOutputStream(FI)) {
				// get the content in bytes
				fop.write(strRtnXML.replace("\n", "").replace("\t", "").getBytes("euc-kr"));
				fop.flush();
			}
 		} catch (Exception e) {
 			logger.error(e.getMessage(), e);
 		} 
       
         return strDocID + ".xml::" + strRtnXML.replace("\n", "").replace("\t", "");
	}

	@Override
	public String getFileName(Map<String, Object> sendOutMap, String realPath, String strFileName, String strFolderName, String strXML, int tenantID) throws Exception {
		String strPath = commonUtil.separator + "fileroot" + commonUtil.separator + tenantID + commonUtil.separator +"files" + config.getProperty("upload_relay.ROOT") + commonUtil.separator +"data" + commonUtil.separator + strFolderName + commonUtil.separator;
		String strResult = "";
		boolean exist;
		String result = "";
		
		int checkSendOutTable = 0;
		int insertSendOutTable = 0;
		
		String fileName = "";
		String folderName = "";
		String fileState = "fail";
		String sendState = "error";
		
		for (int i = 1; i <= 99; i++) {
			strResult = strFileName + getNDigitNum(Integer.toString(i), 2) + ".xml";
			
		      File FI = new File(commonUtil.detectPathTraversal(realPath + strPath));
		      
		      if (!FI.exists()) {
		    	  FI.mkdirs();
			  }
		      
		      File file = new File(commonUtil.detectPathTraversal(realPath + strPath + strResult));
		         
		      exist = file.exists();
		      
		      if (!exist) {
		    	  strResult =  strFileName + getNDigitNum(Integer.toString(i), 2) + ".xml";
		      } else {
		    	  strResult = strFileName + "00.xml";
		      }
		}
		
		try {
			File fos = new File(commonUtil.detectPathTraversal(realPath + strPath + strResult));
			
		    if (!fos.exists()) {
		    	fos.delete();
			}
		    
			// CWE-404 보안 취약점 대응
			try (FileOutputStream fop = new FileOutputStream(fos)) {
				// get the content in bytes
				fop.write(strXML.getBytes("euc-kr"));
				fop.flush();
			}
			
			result = "OK";
			fileState = "success";
			sendState = "sendtemp";
			fileName = strResult;
			folderName = ">" + strFolderName;
			
		} catch (Exception e) {
			logger.error(e.getMessage(), e);
			result = "FALSE";
		} 
		
		sendOutMap.put("V_FILENAME", fileName);
		sendOutMap.put("V_FOLDERNAME", folderName);
		sendOutMap.put("V_FILESTATE", fileState);
		sendOutMap.put("V_SENDSTATE", sendState);
		
		sendOutMap.put("V_DATABASE", "jmocha");
		sendOutMap.put("V_TABLE", "tbl_sendoutinfo");
		
		checkSendOutTable = ezApprovalGAdminDao.checkSendOutInfoTable(sendOutMap);
		
		if(checkSendOutTable > 0) {
			insertSendOutTable = ezApprovalGAdminDao.insertSendOutInfo(sendOutMap);
		}
		
		logger.debug("checkSendOutTable" + checkSendOutTable);
		logger.debug("insertSendOutTable" + insertSendOutTable);
		
		return result;
	}

	@Override
	public boolean insertRelayDB(String strDocID, String strXDocID, String strRecDate, String strFrom, String strTo, String strSubject, String strXMailType, String strXFromCode, String strXToCode,
			String strXGW, String strXDocType, String strXDTDVersion, String strXXSLVersion, String strContentType, String strSealURL, String strXmlURL, String strLastDate, String strCompanyID, int tenantID) throws Exception {
		
		Map<String, Object> map = new HashMap<String, Object>();
		SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
		
		String format = null;
		format = sdf.format(sdf.parse(strRecDate));
		boolean result = false;
		
		try {
			map.put("xDocID", strXDocID);
			map.put("xToCode", strXToCode);
			map.put("docID", strDocID);
			map.put("recDate", format.toString());
			map.put("from", strFrom);
			map.put("to", strTo);
			map.put("subject", strSubject);
			map.put("xMailType", strXMailType);
			map.put("xFromCode", strXFromCode);
			map.put("xGw", strXGW);
			map.put("xDocType", strXDocType);
			map.put("xDtdVersion", strXDTDVersion);
			map.put("xxslVersion", strXXSLVersion);
			map.put("contentType", strContentType);
			map.put("sealUrl", strSealURL);
			map.put("xmlUrl", strContentType);
			map.put("lastDate", strLastDate);
			map.put("companyID", strCompanyID);
			map.put("v_TENANTID", tenantID);
			
			//string 인지 리스트로 받아오는지 확실치 않아서 일단 리스트, 확인 후 변경
			List<ApprGRelayVO> apprGAttachInfoVOList = ezApprovalGDAO.recRelayInfo(map);
			
			if (apprGAttachInfoVOList.size() > 0) {
				for (ApprGRelayVO relayVO : apprGAttachInfoVOList) {
					map.put("v_docID", relayVO.getDocID());
					ezApprovalGDAO.deleteRelayAprDocInfo(map);
					ezApprovalGDAO.deleteRecRelayInfo(map);
				}
			}
			ezApprovalGDAO.insertRelayDB(map);
			result = true;
		} catch (Exception e) {
			logger.error(e.getMessage(), e);
			result = false;
		}
		return result;
	}

