	@Override
	public String sendAck(String docID, String type, String userName, String userDeptName, String errMsg, String companyID, int tenantID) throws Exception {
		logger.debug("sendAck Started");
		String result = "";
		Map <String, Object> map = new HashMap<String, Object>();
		map.put("v_DOCID", docID);
		map.put("v_TENANTID", tenantID);
		map.put("companyID", companyID);
		
		List<ApprGRelayVO> relayDocList = ezApprovalGDAO.getSendAckDocInfo(map);
		
		if(relayDocList.size() < 1) {
			result = "<RESULT>NONE</RESULT>";
		} else {
			String strXDocID = relayDocList.get(0).getxDocID();
			String strXToCode = relayDocList.get(0).getxToCode();
			String strXFromCode = relayDocList.get(0).getxFromCode();
			String strSubject = relayDocList.get(0).getSubject();
			
	/*	1. recRelayInfo 테이블에서 해당 문서의 정보를 조회함
            1) 수신부서의 ID            : xFromCode (원문발신부서코드)
            2) 원문상의 문서ID          : xDocID
            3) 원문상의 문서제목        : subject
        2. 원본 통합문서 sample xml를 로딩 (값이 없는 샘플문서를 미리 생성하여 둠)
        3. 입력값 Assign
        4. sendtemp 폴더에 저장 : 발신부서코드(7) + 수신부서코드(7) + 시간스탬프(YYYYMMDDhhmmss) + 일련번호(2)*/
			boolean rtnVal = sendAck(strXDocID, strXToCode, strXFromCode, strSubject, type, userDeptName, userName, errMsg, companyID, tenantID);
			
			if (rtnVal) {
				result = "<RESLUT>TRUE</RESULT>";
				
				// 2019-2-7 재발송요청일경우 완료되면 문서정보 지워줌
				if (type.equals("req-resend")) {
					map.put("v_DocID", docID);
					
					ezApprovalGDAO.aprDeleteDocInfo(map);
					ezApprovalGDAO.aprDeleteDocInfo2(map);
					ezApprovalGDAO.aprDeleteDocInfo3(map);
					ezApprovalGDAO.aprDeleteDocInfo4(map);
					ezApprovalGDAO.aprDeleteDocInfo5(map);
					ezApprovalGDAO.aprDeleteDocInfo6(map);
					ezApprovalGDAO.aprDeleteDocInfo7(map);
					ezApprovalGDAO.aprDeleteDocInfo8(map);
					ezApprovalGDAO.aprDeleteDocInfo9(map);
                    deleteSummaryFile(docID, companyID, tenantID);
				}
				
			} else {
				result = "<RESULT>FALSE</RESULT>";
			}
		}
		logger.debug("sendAck ended");
		return result;
	}

