	@Override
	public String updateSusinState(String docID, String mode, String deptID, String companyID, int tenantID) throws Exception {
		String recStates = "";

		switch(mode.trim()) {
			case "send":
				recStates = "S";
				break;

			case "resend":
				recStates = "S";
				break;

			case "fail":
				recStates = "E";
				break;
		
			case "arrive":
				recStates = "V";
				break;

			case "receive":
				recStates = "R";
				break;

			case "accept":
				recStates = "I";
				break;

			case "return":
				recStates = "T";
				break;

			case "req-resend":
				recStates = "T";
				break;
		}
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("docID", docID);
		map.put("receiptPointID", deptID);
		map.put("processDate", commonUtil.getTodayUTCTime(""));
		map.put("processYN", recStates);
		map.put("companyID", companyID);
		map.put("tenantID", tenantID);
		
		if (deptID.equals("Address")) {
			map.put("address", "Y");
		} else {
			map.put("address", "N");
		}
		
		ezApprovalGDAO.updateSusinState(map);
		
		return "TRUE";
	}
	
