	@Override
	public String getStoragePeriodName(String period, String lang, String approvalFlag, String companyID, int tenantID) throws Exception {
		logger.debug("getStoragePeriodName started | Period:" + period + " | Lang:" + lang);
		
		String rtnVal = "";
		
		Map<String, Object> map = new HashMap<String, Object>();
		map.put("v_LANGTYPE", lang);
		map.put("v_TENANTID", tenantID);
		map.put("companyID", companyID);
		map.put("approvalFlag", approvalFlag);
		
		List<ApprGLeftVO> apprGetKeepTypeList = ezApprovalGDAO.getKeepType(map);
		
		StringBuffer sb = new StringBuffer();
		
        sb.append("<DATA>");
        for (int i = 0; i < apprGetKeepTypeList.size(); i++) {
			sb.append(commonUtil.getQueryResult(apprGetKeepTypeList.get(i)));
		}
		sb.append("</DATA>");
		
		Document dataXML = commonUtil.convertStringToDocument(sb.toString());
		
		int dlength = dataXML.getElementsByTagName("ROW").getLength();
		
		try {
			for (int k = 0; k < dlength; k++) {
				String[] colOption = dataXML.getElementsByTagName("NAME").item(k).getTextContent().split(";");
				if (colOption[2].equals(period)) {
					rtnVal = colOption[1];
					break;
				}
			}
		} catch (Exception e) {
			logger.error(e.getMessage(), e);
			rtnVal = "ERROR";
		}
		
		logger.debug("getStoragePeriodName ended | result:" + rtnVal);
		return rtnVal;
	}
	
	@Override
	public String convertDocumentToImg(MultipartFile file, String tempUploadPath, String docId, int tenantId, String companyId, String userId, String ext) throws Exception {
		logger.debug("convertDocumentToImg started");

		String originalFilename = docId + "_office";
//		EzFileMngUtil.writeFile(file, originalFilename, tempUploadPath);

        // 다른 서버에 설치되어있는 변환솔루션의 경우, 솔루션서버에 마운트된 위치를 filePath로 알려줘야함
//		String filePath = URLEncoder.encode(tempUploadPath + commonUtil.separator + originalFilename, "UTF-8");
        String oldYear = getDocHrefYear(docId, companyId, tenantId);
        String filePath2 = commonUtil.getUploadPath("upload_approvalG.ROOT", tenantId) + commonUtil.separator + companyId + commonUtil.separator + "uploadFile" + commonUtil.separator + oldYear +
                commonUtil.separator +  getDocDir(docId);
        if(file != null){
            originalFilename = file.getOriginalFilename();
            EzFileMngUtil.writeFile(file, docId + "_office", servletContext.getRealPath("") + filePath2);
            ext = originalFilename.substring(originalFilename.lastIndexOf('.') + 1);
        }
        String filePath = filePath2 + commonUtil.separator + docId + "_office";
		String fileName = URLEncoder.encode(originalFilename, "UTF-8");
        
        String serverUrl = ezCommonService.getTenantConfig("SATimageConvertServerURL", tenantId);
        String address = "";
        if (serverUrl.contains("/DG_viewer")) {
            address = serverUrl.split("/DG_viewer")[0];
        } else {
            logger.debug("SAT Server doesn't exists.");
            throw new Exception("incorrect server url");
//				+ "filepath=" + filePath + "&filename=" + fileName + "&fileext=" + fileExt
        };
//        String address = config.getProperty("config.officeConverterServerURL") + "/DG_viewer/viewer/document/docviewer.do?"
            address += "/DG_viewer/viewer/getThumbnail.do?filepath=" + URLEncoder.encode(tempUploadPath + "/ezApprovalG/downloadAttachForHwp.do?filePath=" + URLEncoder.encode(filePath, "UTF-8"), "UTF-8").replace("+", "%20")
                + "&filename=" + URLEncoder.encode(fileName, "UTF-8") + "&fileext=" + ext;

		logger.debug("image converting requestURL : " + address);
		
		URL url = new URL(address);
		HttpURLConnection conn = (HttpURLConnection) url.openConnection();	
		conn.setRequestMethod("GET");
		
		// CWE-404 보안 취약점 대응
		try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
			String line;
			StringBuffer response = new StringBuffer();
			
			while((line = br.readLine()) != null) {			
				response.append(line);						
			}
		
			// 2021-01-14 이혁진 넘어온 response값을 가지고 이미지URL생성
			String convertedImgInfo = serverUrl.split("/DG_viewer")[0] + "/DG_viewer" + response;
			
			// 컨버팅 후, 오피스 문서 파일 삭제
//			File tempFile = new File(tempUploadPath + commonUtil.separator + file.getOriginalFilename());
//			tempFile.delete();
			
			logger.debug("convertDocumentToImg ended");
			return convertedImgInfo;	
		}
	}

	@Override
	public JSONObject getConvertedImgInfo(String hash) throws Exception {
		logger.debug("getConvertedImgInfo started");
		
		String body = "hash=" + hash;
		
		JSONObject result;
		
		int attemptCNT = 0;
		
		// 컨버팅 프로세스가 변환서버에서 다 끝나기 전에 리퀘스트를 보내서 파일명을 가져오지 못할 때가 있음. 가져올때까지 리퀘스트를 보낸다.
		while(true) {
			URL url = new URL(config.getProperty("config.officeConverterServerURL") + "/DG_viewer/viewer/getThumbnail.do");
			HttpURLConnection conn = (HttpURLConnection) url.openConnection();
			conn.setRequestMethod("POST");
			conn.setDoOutput(true);
			
			// CWE-404 보안 취약점 대응
			try (OutputStream os = conn.getOutputStream()) {
				os.write(body.getBytes("UTF-8"));
				os.flush();
			}
			
			// CWE-404 보안 취약점 대응
			try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
				String line;
				StringBuffer response = new StringBuffer();
				
				while((line = br.readLine()) != null) {
					response.append(line);
				}
						
				result = (JSONObject) new JSONParser().parse(response.toString());
			}			

			Long pageTotal = result.get("page_total") != null ? (Long) result.get("page_total") : -1L;
			int fileCNT = ((JSONArray)result.get("dirnmL")).size();
			
			logger.debug("page_total : " + pageTotal + ", fileCNT : " + fileCNT);
			
			if(fileCNT == pageTotal) {
				break;
			// 변환솔루션서버가 제대로 동작하지 않을 경우, 무한루프에 빠질 수 있기 때문에 변환시도 횟수를 120회로 제한(2분)
			} else if(++attemptCNT > 120) {
				throw new Exception("convert fails");
			}
			
			logger.debug("attemptCNT : " + attemptCNT + "(time : " + System.currentTimeMillis() + ")");
			Thread.sleep(1000);
		}
		
		logger.debug("getConvertedImgInfo ended");
		return result;	
		
	}
	
