	public String getLeftDocCountNew(String userID, String deptID, String userIDs, String deptIDs, String userFlag, String offset, String companyID , int tenantID, List<ApprGProxyVO> list, String type) throws Exception {
		logger.debug("getLeftDocCount started");

		Map<String, Object> map = new HashMap<String, Object>();
		
		String[] userIDArr = userIDs.replace(" ", "").replace("\'", "").split(",");
		String[] deptIDArr = deptIDs.replace(" ", "").replace("\'", "").split(",");
		String startDate = Integer.toString(Integer.parseInt(commonUtil.getTodayUTCTime("yyyy-MM-dd").substring(0,4))-1) + commonUtil.getTodayUTCTime("yyyy-MM-dd").substring(4,commonUtil.getTodayUTCTime("yyyy-MM-dd").length())  + " 00:00:01";
        String endDate = EgovDateUtil.getCurrentDate("-") + " 23:59:59";
		
		map.put("v_USERID", userID);
		map.put("v_DEPTID", deptID);
		map.put("v_USERIDS", userIDArr);
		map.put("v_DEPTIDS", deptIDArr);
		map.put("v_USERFLAG", userFlag.trim().toLowerCase());
		map.put("v_TENANTID", tenantID);
		map.put("companyID", companyID);
		// v_STARTDATE, v_ENDDATE UTC 시간 기준으로 수정 (DB에는 UTC 시간으로 저장되므로)
		map.put("v_STARTDATE", commonUtil.getDateStringInUTC(startDate, offset, true)); 
		map.put("v_ENDDATE", commonUtil.getDateStringInUTC(endDate, offset, true)); /* 2023-05-09 양지혜 - UTC 시간 적용이 중복되어 수정 */
        logger.debug("endDate = "+endDate+" , v_ENDDATE = "+ commonUtil.getDateStringInUTC(endDate, offset, true));
		map.put("MineViewYN", ezCommonService.getTenantConfig("MineViewYN", tenantID));
		map.put("proxyList", list);
		
		String ApprovalFlag = ezCommonService.getTenantConfig("ApprovalFlag", tenantID);
		map.put("v_aprFlag", ApprovalFlag);
		
		String shareApprovalFlag = ezCommonService.getTenantConfig("useShareApproval", tenantID);
		map.put("v_shareApprovalFlag", shareApprovalFlag);
		
		String relayFormID = config.getProperty("Relay_FormID", "");
		map.put("v_RELAYFORMID", relayFormID);

        boolean usePublicFlag = true;
        if (getIsUse("A22", "001", companyID, "1", tenantID).equals("1")) {
            usePublicFlag = true; //보안등급 사용여부
        } else {
            usePublicFlag = false;
        }

        map.put("usePublicFlag", usePublicFlag);
        if (usePublicFlag) {
            String userSecurityCode = ezOrganService.getPropertyValue(userID, "extensionAttribute6", tenantID);

            if (userSecurityCode == null || userSecurityCode.equals(" ") || userSecurityCode.equals("")) {
                userSecurityCode = "0";
            }
            map.put("userSecurityCode", userSecurityCode);

            String tempIsUse = getIsUse("A22", "005", companyID, "1", tenantID);
            map.put("isUse", tempIsUse);
        }
        
        /* 전자결재G > 상위부서문서함 사용 > 부서수신함 카운트 상위부서정보로 확인 */
        Map<String, String> upDeptInfo = getUpperDeptInfo(deptID, tenantID);
        if (upDeptInfo.get("USEUPPERDEPTBOX") != null && upDeptInfo.get("USEUPPERDEPTBOX").equals("Y")) {
            map.put("upperDeptCode", upDeptInfo.get("upperDeptCode"));
            String[] upperDeptIDArr = getDocManageDeptInfo(upDeptInfo.get("upperDeptCode"), tenantID).replace(" ", "").replace("\'", "").split(",");
            map.put("upperDeptIDArr", upperDeptIDArr);
        }
		
		Map<String, Object> result = new HashMap<>();
        
        if (type != null && !"".equals(type) && "dash".equals(type)) {
            result = ezApprovalGDAO.getDashBoardProGressDocCount(map);
        } else {
            result = ezApprovalGDAO.getLeftDocCountNew(map); 
        }
		
		StringBuffer sb = new StringBuffer();
		sb.append("<DATA>");
		
		for (String key : result.keySet()) {
		    sb
	        .append("<").append(key.toUpperCase()).append(">")
	        .append(ObjectUtils.defaultIfNull(result.get(key), 0))
	        .append("</").append(key.toUpperCase()).append(">");
		}
		
		sb.append("</DATA>");
		
		logger.debug("getLeftDocCount ended");
        
		return sb.toString();
	}
	
